window.TAM_MASTER_BIBLE = {"meta":{"title":"Tap Against Me Comprehensive Game Bible","version":"2.0","updated":"July 2026","chapterCount":50,"referenceSectionCount":53,"wordCount":28880,"tableCount":93},"parts":[{"id":"part-i","label":"Part I","name":"Canon, identity, audience, and product architecture"},{"id":"part-ii","label":"Part II","name":"Competitive gameplay, ranked systems, and environment"},{"id":"part-iii","label":"Part III","name":"Infinity Taps, living worlds, discovery, and heroes"},{"id":"part-iv","label":"Part IV","name":"Progression, economy, cosmetics, effects, and collection"},{"id":"part-v","label":"Part V","name":"Music, sound, interface, onboarding, and profiles"},{"id":"part-vi","label":"Part VI","name":"Backend, security, analytics, accessibility, and mobile quality"},{"id":"part-vii","label":"Part VII","name":"Roadmap, live operations, risks, and decisions"},{"id":"part-viii","label":"Part VIII","name":"Catalogs, data models, release gates, and source concordance"}],"chapters":[{"id":"document-control","number":null,"title":"Document Control","part":"Front Matter","partName":"Governance, provenance, and navigation","blocks":[{"type":"table","rows":[["Field","Canonical value"],["Document","Tap Against Me Comprehensive Game Bible"],["Version","2.0 - canonical consolidation"],["Compilation date","July 2026"],["Feature owner","Don't Watch Media"],["Primary platform","Android-first, portrait-oriented mobile 2D"],["Products","Competitive Tap Against Me and Infinity Taps"],["Authority rule","Newest explicit decision wins; locked/confirmed rules outrank working, candidate, tuning, open, and legacy material."],["Source count","Nine supplied files; eight unique documents because two Game Design Bible PDFs are byte-identical."]]},{"type":"p","text":"CANONICAL This document is the consolidated product-intent authority. It is not a substitute for code specifications, balance sheets, legal terms, platform submissions, sprint tickets, or live-operations runbooks. Those artifacts should link back to the relevant chapter and decision status here."},{"type":"heading","level":2,"text":"Decision Status Legend","id":"document-control-decision-status-legend"},{"type":"table","rows":[["Status","Meaning","Implementation treatment"],["LOCKED","Core identity, fairness, or non-negotiable boundary.","Do not change without feature-owner approval and a recorded revision."],["CONFIRMED","Approved product or system direction.","Implement as written; exact engineering details may still be specified separately."],["WORKING","Current intended direction with unresolved implementation or policy detail.","Design modularly and keep tunable values configurable."],["CANDIDATE / PROPOSED","Strong option not yet approved as committed scope.","Do not schedule as required launch work without a decision."],["TUNING","The behavior is intended; exact values need playtesting.","Expose values through data or remote configuration."],["OPEN","Unresolved decision with material product impact.","Record the decision before dependent implementation."],["LEGACY / RESERVED","Historical idea retained for context or possible future reuse.","Do not treat as canonical unless revived explicitly."]]},{"type":"heading","level":2,"text":"Implementation Evidence Legend","id":"document-control-implementation-evidence-legend"},{"type":"p","text":"Design status and implementation status answer different questions. A LOCKED design can still be NOT STARTED; an IMPLEMENTED feature can still embody legacy behavior that the canonical design supersedes."},{"type":"table","rows":[["Evidence state","Meaning","Required next action"],["IMPLEMENTED","Repository or build evidence shows the feature exists across its stated scope.","Verify against acceptance gates; implementation alone is not release proof."],["PARTIAL","A usable subset exists, but required phases, paths, devices, or edge cases remain.","Name the missing scope and the next measurable gate."],["DATA-DEFINED","Catalog/configuration records exist, but runtime reachability and grant behavior are not proven here.","Exercise every record through automated and in-build validation."],["PLANNED","The design is documented and sequenced, with no complete implementation evidence in this compilation.","Create the technical specification and milestone evidence."],["NOT STARTED","The feature is intentionally absent from the current baseline.","Do not imply current availability; retain dependencies and phase."],["UNKNOWN / AUDIT","The source set does not establish current repository or production status.","Perform a code, build, backend, and catalog audit before scheduling or claiming completion."]]},{"type":"heading","level":2,"text":"Conflict Resolution Rules","id":"document-control-conflict-resolution-rules"},{"type":"ul","items":["The newest explicit decision supersedes older conflicting language.","Competitive TAM and Infinity Taps are separate player-facing games under one shared TAM ecosystem, even where older documents call Infinity a mode inside one app.","Core emotional purpose outranks feature quantity: Competitive remains fast, readable, fair, and tense; Infinity remains tactile, alive, relaxing, and non-punitive.","No pay-to-win is absolute. No purchase may alter competitive physics, visibility, matchmaking, tap validity, survival, item odds, rating, or enforcement.","Infinity-earned exclusive rewards cannot be purchased in either product. Shared ownership never erases acquisition source.","Gravity and competitive day/night presentation are independent. Darkness never represents gravity strength in the final implementation.","Configuration absorbs uncertainty. Gravity curves, spawn rules, bot reactions, matchmaking weights, cycle timing, effect density, and audio compression remain data-driven.","One deeply reactive Infinity biome is better than many decorative but shallow biomes; one trustworthy ranked queue is better than many fragmented modes."]},{"type":"heading","level":2,"text":"How to Use This Bible","id":"document-control-how-to-use-this-bible"},{"type":"ul","items":["Product and design: verify new work against the product architecture, emotional contracts, design pillars, and non-negotiable boundaries.","Engineering: derive code-level specifications, data models, migrations, tests, performance budgets, and release gates from the relevant chapters.","Art and animation: use the hero, biome, cosmetic, readability, and reaction standards as the production brief; do not trade competitive clarity for spectacle.","Audio: preserve a recognizable shared TAM motif while keeping tap, pickup, debuff, match, and accessibility cues legible at all times.","Live operations: use seasons and events to extend the universe without invalidating permanent ownership or destabilizing ranked rules.","QA: translate every definition-of-done and appendix acceptance criterion into traceable test cases."]}]},{"id":"source-manifest-and-provenance","number":null,"title":"Source Manifest and Provenance","part":"Front Matter","partName":"Governance, provenance, and navigation","blocks":[{"type":"p","text":"All nine supplied files were inspected. The two files named Game Design Bible and Game Design Bible (1) have the same SHA-256 hash and are exact duplicates. They appear separately below for custody and provenance, but their content is counted once when resolving authority."},{"type":"table","rows":[["Source","Format","Extent","SHA-256 prefix","Contribution"],["Competitive Dynamic Day-Night and Gravity Presentation Bible","PDF","39 pages","5fa52cf3cf90","Approved competitive environment and gravity-presentation specification."],["Game Design Bible (1)","PDF","38 pages","406bba2282e7","Consolidated design, implementation state, and developer acceptance criteria."],["TAM Game Design Bible v1.0","DOCX","808 paragraphs","17e44cb45fa0","Newest comprehensive decision register; primary canonical narrative."],["Game Design Bible","PDF","38 pages","406bba2282e7","Exact duplicate of Game Design Bible (1); retained in provenance, not double-counted."],["TAM Game Bible","DOCX","652 paragraphs","d8aa7d98f6bb","Comprehensive product, content, art, audio, technology, and roadmap synthesis."],["TAM Design Bible v1.0","PDF","30 pages","dc5b2cda2b3c","Condensed high-level design and product framing."],["Game Bible v1.0","DOCX","643 paragraphs","60f0a151ab57","Detailed mechanics, system behavior, implementation snapshot, and handoff."],["Game Design Bible v1.0","PDF","35 pages","889f9f040585","Detailed design, acceptance, roadmap, and production framing."],["Original Expanded Bible","PDF","130 pages","8d75129c310f","Deep specifications for effects, Infinity Taps, monetization, and ranked systems."]]},{"type":"p","text":"SOURCE POLICY Chapter source notes identify the principal canonical basis, but many chapters synthesize details from several bibles. The Source Concordance appendix records major cross-source contributions."}]},{"id":"contents","number":null,"title":"Contents","part":"Front Matter","partName":"Governance, provenance, and navigation","blocks":[{"type":"table","rows":[["Part","Coverage"],["Part I","Canon, identity, audience, and shared product architecture"],["Part II","Competitive TAM mechanics, modes, matchmaking, ranked, and dynamic environment"],["Part III","Infinity Taps, living worlds, discovery, heroes, and exclusive progression"],["Part IV","Progression, achievements, cosmetics, effects, economy, and collection"],["Part V","Music, sound, interface, onboarding, profiles, and social presentation"],["Part VI","Accounts, backend, security, analytics, accessibility, performance, and mobile quality"],["Part VII","MVP definitions, phased roadmap, live operations, risks, and decisions"],["Part VIII","Detailed catalogs, data references, acceptance criteria, terminology, and source concordance"]]},{"type":"heading","level":2,"text":"Detailed Contents","id":"contents-detailed-contents"},{"type":"p","text":"All entries use real heading styles for the Word navigation pane and PDF search/bookmark export. This static chapter map avoids field-update drift between editors."},{"type":"table","rows":[["Part","Chapters","Detailed coverage"],["I","1-6","Governance; executive definition; two-product architecture; vision; audience; universe/brand"],["II","7-14","Competitive core; controls/physics; modes; pickups/hazards; bots; matchmaking/ranked; ranked implementation; day/night specification"],["III","15-20","Infinity core; worlds/zones; living interactions; heroes/collection; Velvet Hex/cast production; Infinity implementation"],["IV","21-25","Progression/economy; achievements/challenges; cosmetics; expanded effect catalog; effect engineering handoff"],["V","26-27","Music/sound/adaptive audio; interface/onboarding/profiles/social presentation"],["VI","28-33","Accounts/backend; fair play/analytics; monetization guardrails; economy proposal; accessibility/performance; mobile/session baseline"],["VII","34-37","MVP/roadmap; production/live ops; risk controls; canonical decisions/open questions"],["VIII","38-50","Terminology; seed catalogs; acceptance; legacy; feature ledger; implemented catalogs; data/config/events; release gates; decisions; concordance"]]},{"type":"p","text":"PART 1"},{"type":"p","text":"PRODUCT CANON AND GOVERNANCE"},{"type":"p","text":"The decisions that define what TAM is, who it serves, how the two products relate, and which boundaries cannot be crossed."}]},{"id":"document-governance-and-decision-status","number":1,"title":"1. Document Governance and Decision Status","part":"Part I","partName":"Canon, identity, audience, and product architecture","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"p","text":"Tap Against Me has evolved quickly through concept design, prototype implementation, backend deployment, multiplayer planning, economy design, audio planning, and the expansion of Infinity Taps. A single design bible is necessary because some ideas were approved, some were refined, and some remain useful but should not silently become requirements."},{"type":"heading","level":2,"text":"1 Status Labels","id":"document-governance-and-decision-status-1-status-labels"},{"type":"table","rows":[["Label","Meaning","How the team should treat it"],["Confirmed","Explicitly approved or repeatedly established as a core rule.","Implement unless a later product decision replaces it."],["Working direction","The current preferred solution, but tuning or implementation details remain open.","Build toward it while preserving configurability."],["Future / test candidate","A valuable concept that requires prototyping, balance testing, or later scope.","Do not include in MVP unless it is cheap and supports the core."],["Legacy / reserved","An earlier concept, alternate naming, or system that is not part of the current core.","Keep for reference; do not reintroduce without an explicit decision."]]},{"type":"heading","level":2,"text":"2 Conflict Resolution","id":"document-governance-and-decision-status-2-conflict-resolution"},{"type":"ul","items":["The newest explicit decision wins. The current direction is two separate player-facing games under one shared TAM ecosystem, even though earlier descriptions treated Infinity Taps as a mode inside one app.","Core emotional purpose outranks feature quantity. Competitive TAM must remain fast, readable, fair, and tense. Infinity Taps must remain relaxing, tactile, alive, and non-punitive.","No pay-to-win is absolute. A monetization idea that affects ranked strength, tap validity, survival, matchmaking, movement, or competitive resources is rejected.","Infinity exclusivity is meaningful. Rewards designated as Infinity-earned cannot be purchased merely because doing so would be convenient for the shop.","Configuration should absorb tuning uncertainty. Gravity curves, item spawn rates, bot reaction delay, zone duration, and audio compression should be data-driven rather than hard-coded."]},{"type":"heading","level":2,"text":"3 What This Bible Is Not","id":"document-governance-and-decision-status-3-what-this-bible-is-not"},{"type":"p","text":"This is not a final production schedule, legal specification, platform-store submission, network protocol reference, or complete balance spreadsheet. It is the master expression of product intent. Engineering specifications, economy tables, art briefs, and sprint plans should derive from it and link back to the relevant design decisions."}]},{"id":"executive-definition","number":2,"title":"2. Executive Definition","part":"Part I","partName":"Canon, identity, audience, and product architecture","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"p","text":"Tap Against Me is a mobile-first, portrait-oriented 2D tapping universe built around the idea that a simple tap can become competition, movement, expression, discovery, and long-term identity."},{"type":"p","text":"CONFIRMED The official slogan is \"Every Tap Against Me Takes You Further.\""},{"type":"p","text":"The phrase \"me\" is intentionally layered. In competitive play, it is the opponent. In solo survival, it is gravity, fatigue, timing, and the player's previous record. In Infinity Taps, it is distance, curiosity, and the limit of what the player has discovered. The title is therefore both a challenge and a promise."},{"type":"heading","level":2,"text":"1 The Two Core Experiences","id":"executive-definition-1-the-two-core-experiences"},{"type":"table","rows":[["Dimension","Competitive Tap Against Me","Infinity Taps"],["Primary emotion","Tension, mastery, rivalry, improvement","Calm, curiosity, tactile satisfaction, discovery"],["Session shape","Short, high-pressure runs and matches","Open-ended, interruption-friendly exploration"],["Failure","Ground contact or mode-specific loss condition","No traditional failure or punishment"],["Progress emphasis","Skill rating, rank, wins, survival, seasonal status","Lifetime taps, biome discovery, world interactions, exclusive finds"],["Population need","Benefits from opponents, bots, ghosts, and matchmaking","Works fully alone and local-first"],["Content demand","Physics, balance, modes, netcode, competitive integrity","Biomes, animals, reactions, secrets, music, ambient content"],["Shared systems","Account, heroes, cosmetics, effects, audio identity, achievements","Account, heroes, cosmetics, effects, audio identity, achievements"]]},{"type":"p","text":"WORKING Publish Competitive TAM and Infinity Taps as separate player-facing games while sharing as much account, catalog, cloud-save, character, cosmetic, achievement, and backend infrastructure as practical."},{"type":"table","rows":[["WHY SEPARATION MATTERS The two experiences share a verb and a universe, but they sell different emotional promises. A player opening a ranked survival game should not be forced through a relaxation-game onboarding flow, and a player seeking a fidget world should not be confronted with rank anxiety. Separate listings and onboarding allow each product to be clear while the shared ecosystem protects development efficiency."]]}]},{"id":"product-architecture-one-ecosystem-two-player-facing-games","number":3,"title":"3. Product Architecture: One Ecosystem, Two Player-Facing Games","part":"Part I","partName":"Canon, identity, audience, and product architecture","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Competitive Product","id":"product-architecture-one-ecosystem-two-player-facing-games-1-competitive-product"},{"type":"p","text":"The competitive product retains the primary name Tap Against Me. It is the sharper, more skill-oriented expression of the brand. It focuses on staying airborne, surviving increasing gravity, managing pickups, competing against human or disclosed AI opponents, and proving improvement through results."},{"type":"ul","items":["Solo survival and personal-best play.","Local play where supported.","Private online matches between known players.","Public matchmaking with population-aware bot backfill.","Ranked ladder with Glicko-style rating and 90-day seasons.","Permanent progression, achievements, badges, profiles, and cosmetics."]},{"type":"heading","level":2,"text":"2 Infinity Product","id":"product-architecture-one-ecosystem-two-player-facing-games-2-infinity-product"},{"type":"p","text":"Infinity Taps is the relaxed exploration expression of the universe. A possible store-facing subtitle is \"A Tap Against Me Adventure,\" but final naming remains a brand decision. It should be understandable as a complete product, not as a lesser practice mode."},{"type":"ul","items":["No loss condition and no forced session endpoint.","Tapping moves the hero through responsive spaces.","Approximately two-minute biome zones create a gentle journey cadence.","Animals, plants, water, terrain, heroes, and hidden events react to taps.","Lifetime tap progression and discovery replace ranked pressure.","Mode-exclusive rewards create status for players who prefer exploration over competition."]},{"type":"heading","level":2,"text":"3 Shared Ecosystem","id":"product-architecture-one-ecosystem-two-player-facing-games-3-shared-ecosystem"},{"type":"p","text":"CONFIRMED The products should share brand identity, characters, heroes, cosmetics, tap effects, music motifs, account technology, and portions of achievement infrastructure."},{"type":"p","text":"WORKING Shared accounts and cloud saves should allow a player's owned heroes, eligible cosmetics, profile identity, and cross-title achievements to appear across both games."},{"type":"ul","items":["Shared does not mean identical. Competitive rating, seasonal rank, Infinity discovery progress, and product-specific tutorials remain separate.","Cross-title ownership must respect source. An Infinity-exclusive skin may be wearable in Competitive TAM after it is earned, but it cannot be purchased in the competitive shop.","Storefront clarity comes first. Each listing must clearly describe its own loop rather than relying on the player to understand the broader universe.","Technical reuse should be invisible. Players should feel continuity, not a stitched-together launcher."]},{"type":"heading","level":2,"text":"4 Recommended Account Boundary","id":"product-architecture-one-ecosystem-two-player-facing-games-4-recommended-account-boundary"},{"type":"table","rows":[["Data","Shared","Product-specific"],["Identity","User ID, display name, profile frame, primary badge","Ranked banner treatment or Infinity exploration title"],["Collection","Owned heroes and globally eligible cosmetics","Product-restricted equipment slots or encounter records"],["Currency","Hero Coin wallet, subject to economy safeguards","Event currencies when necessary"],["Achievements","Universal and cross-title achievements","Ranked, survival, biome, and discovery achievements"],["Progress","Lifetime total taps may be aggregated with source labels","Glicko rating, season rank, biome journal, world distance"],["Settings","Accessibility and account preferences","Control and audio profiles tuned per title"]]}]},{"id":"vision-identity-and-design-pillars","number":4,"title":"4. Vision, Identity, and Design Pillars","part":"Part I","partName":"Canon, identity, audience, and product architecture","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Vision Statement","id":"vision-identity-and-design-pillars-1-vision-statement"},{"type":"p","text":"Build the most expressive tapping universe on mobile: easy to understand in seconds, satisfying to touch repeatedly, deep enough to reward mastery or curiosity, and fair enough that achievement remains meaningful."},{"type":"heading","level":2,"text":"2 Shared Design Pillars","id":"vision-identity-and-design-pillars-2-shared-design-pillars"},{"type":"heading","level":3,"text":"Immediate tactile feedback","id":"vision-identity-and-design-pillars-immediate-tactile-feedback"},{"type":"p","text":"Every tap should produce a readable response through motion, sound, particles, environmental reaction, or character behavior. Dead taps should be rare and intentional."},{"type":"heading","level":3,"text":"Simple input, layered mastery","id":"vision-identity-and-design-pillars-simple-input-layered-mastery"},{"type":"p","text":"The basic action is tapping. Depth comes from timing, location, momentum, survival decisions, exploration, pattern recognition, and collection-not from a crowded control scheme."},{"type":"heading","level":3,"text":"Personality through reaction","id":"vision-identity-and-design-pillars-personality-through-reaction"},{"type":"p","text":"Heroes and environments should react as if they notice the player. Repeated taps should escalate behavior instead of replaying one animation forever."},{"type":"heading","level":3,"text":"Fair status","id":"vision-identity-and-design-pillars-fair-status"},{"type":"p","text":"Ranks, badges, exclusive rewards, and rare discoveries matter only when the method of earning them is trustworthy."},{"type":"heading","level":3,"text":"Respect for session context","id":"vision-identity-and-design-pillars-respect-for-session-context"},{"type":"p","text":"Competitive TAM supports focused short sessions. Infinity Taps supports fidgeting, commuting, listening to music, or briefly returning throughout the day."},{"type":"heading","level":3,"text":"Expandable universe","id":"vision-identity-and-design-pillars-expandable-universe"},{"type":"p","text":"Characters, variants, biomes, effects, achievements, seasons, and music can grow without rewriting the core verb."},{"type":"heading","level":2,"text":"3 Competitive-Specific Pillars","id":"vision-identity-and-design-pillars-3-competitive-specific-pillars"},{"type":"ul","items":["A loss should feel understandable rather than arbitrary.","The player should believe improvement is possible after every run.","Matchmaking should create pressure without creating hopeless pairings.","Bots must behave imperfectly and remain bound by the same physical rules.","Rank must reflect sustained performance, not a single lucky run or paid advantage."]},{"type":"heading","level":2,"text":"4 Infinity-Specific Pillars","id":"vision-identity-and-design-pillars-4-infinity-specific-pillars"},{"type":"ul","items":["The world should feel alive before the player touches it.","Taps influence the world; they do not merely trigger cosmetic overlays.","Nothing in the environment should punish the player with failure.","Discovery rewards observation, repetition, experimentation, and patience.","Exclusive Infinity rewards validate noncompetitive play as a first-class way to engage with TAM."]}]},{"id":"audience-and-emotional-experience","number":5,"title":"5. Audience and Emotional Experience","part":"Part I","partName":"Canon, identity, audience, and product architecture","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Competitive Audience","id":"audience-and-emotional-experience-1-competitive-audience"},{"type":"p","text":"Competitive TAM is for players who enjoy short repeatable challenges, personal-best chasing, synchronous or asynchronous rivalry, visible rank, collectible identity, and controls that become more expressive with practice. The ideal player can understand the premise immediately and still care about improving weeks later."},{"type":"heading","level":2,"text":"2 Infinity Audience","id":"audience-and-emotional-experience-2-infinity-audience"},{"type":"p","text":"Infinity Taps is for players who tap to fidget, regulate attention, relax, fill short pauses, watch satisfying reactions, collect unusual variants, or explore without the threat of losing progress. It should remain engaging when played with sound low, when interrupted, or when the player has no desire to compete."},{"type":"heading","level":2,"text":"3 Dual-Audience Player","id":"audience-and-emotional-experience-3-dual-audience-player"},{"type":"p","text":"Many players will move between both products. A ranked player may use Infinity Taps to decompress. An exploration player may eventually try solo survival because a familiar hero and earned cosmetic carry over. Cross-title design should encourage curiosity without using coercive rewards that make either game feel mandatory."},{"type":"heading","level":2,"text":"4 Emotional Contract","id":"audience-and-emotional-experience-4-emotional-contract"},{"type":"table","rows":[["Player expectation","Competitive promise","Infinity promise"],["My tap matters","It changes velocity, survival, positioning, or match outcome.","It causes visible, audible, or systemic world response."],["My time matters","Results, rating, records, and rewards are recorded fairly.","Lifetime taps, discoveries, encounters, and exclusive unlocks persist."],["My collection matters","Cosmetics show identity without changing power.","Discoveries and exclusives show curiosity and exploration history."],["The game respects me","No hidden paid advantage or impossible matchmaking.","No surprise failure, pressure, or punishment for pausing."]]}]},{"id":"shared-tam-universe-and-brand-language","number":6,"title":"6. Shared TAM Universe and Brand Language","part":"Part I","partName":"Canon, identity, audience, and product architecture","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Naming","id":"shared-tam-universe-and-brand-language-1-naming"},{"type":"ul","items":["Tap Against Me (TAM): the competitive flagship and umbrella universe name.","Infinity Taps: the no-loss exploration title. \"A Tap Against Me Adventure\" is a possible clarifying subtitle, not yet final.","Hero: the current canonical term for playable or collectible characters.","Hero Variant: a visually or thematically distinct version of a hero with separate ownership or unlock status.","Hero Coin: the canonical cosmetic currency. Earlier \"Golden Hero Token\" language can remain as the physical in-match pickup representation."]},{"type":"heading","level":2,"text":"2 Meaning of \"Me\"","id":"shared-tam-universe-and-brand-language-2-meaning-of-me"},{"type":"p","text":"The identity should remain slightly mysterious rather than over-explained in marketing. \"Me\" can be the opponent, gravity, the game, a previous score, or the part of the player that would stop. This interpretation makes the slogan equally valid in ranked competition and peaceful exploration."},{"type":"heading","level":2,"text":"3 Tone","id":"shared-tam-universe-and-brand-language-3-tone"},{"type":"p","text":"TAM should feel playful, energetic, slightly mischievous, and sincere about player achievement. Humor should come from character reactions, rare events, environmental surprises, and over-the-top cosmetic consequences-not from mocking the player for losing."},{"type":"heading","level":2,"text":"4 Visual Language","id":"shared-tam-universe-and-brand-language-4-visual-language"},{"type":"ul","items":["Readable silhouettes suited to small portrait screens.","Bright effects layered over clear gameplay boundaries.","Purple as a recurring identity color, with gold tied to Hero Coins and prestige.","Cute or strange heroes capable of expressive multi-stage reactions.","Environments that feel hand-authored even when assembled procedurally.","Pixel-art or stylized 2D presentation may be used, but readability is more important than strict aesthetic purity."]},{"type":"heading","level":2,"text":"5 Character Lore","id":"shared-tam-universe-and-brand-language-5-character-lore"},{"type":"p","text":"Character lore should be compact, collectible, and discoverable. A hero can have a name, one-sentence identity, a few journal notes, variant-specific flavor, and environmental behavior. Repeated encounters can reveal personality gradually."},{"type":"p","text":"LEGACY Earlier work referenced \"Puffs,\" artifacts, and bubble-like moving targets. These concepts may inform future companions, collectible lore objects, or event modes, but heroes are the current primary character language."},{"type":"p","text":"PART 2"},{"type":"p","text":"COMPETITIVE TAP AGAINST ME"},{"type":"p","text":"The skill-focused survival game: input, physics, pickups, modes, opponents, rating, seasons, presentation, and competitive trust."}]},{"id":"competitive-tap-against-me-core-gameplay","number":7,"title":"7. Competitive Tap Against Me: Core Gameplay","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Core Loop","id":"competitive-tap-against-me-core-gameplay-1-core-loop"},{"type":"ol","items":["The player enters a run or match and begins falling from the sky or from an airborne starting state.","Each valid tap applies upward force, allowing the player to remain airborne.","Gravity continually pulls the hero downward and increases over time or by difficulty state.","The player responds to movement, pickups, arena conditions, and an opponent where applicable.","Touching the ground ends the run or eliminates the player under the active mode rules.","The result feeds records, achievements, rating, seasonal progress, challenges, and cosmetic progression."]},{"type":"p","text":"CONFIRMED The fundamental skill test is staying airborne through tapping. Ground contact ends the standard survival round."},{"type":"heading","level":2,"text":"2 Why the Loop Works","id":"competitive-tap-against-me-core-gameplay-2-why-the-loop-works"},{"type":"p","text":"The loop creates immediate comprehension and escalating tension. Early taps establish rhythm. Mid-run play adds pickup decisions and position control. Late-run play increases physical and cognitive pressure because gravity, speed, or hazards reduce recovery time. The round produces a natural story without requiring complex rules."},{"type":"heading","level":2,"text":"3 Player Skill Expression","id":"competitive-tap-against-me-core-gameplay-3-player-skill-expression"},{"type":"ul","items":["Tap timing and rhythm.","Recovery after a poor tap.","Positioning relative to pickups and arena boundaries.","Recognizing when a boost is worth pursuing.","Managing increased gravity and momentum.","Reading the opponent without losing control of one's own hero.","Maintaining consistency as the run becomes faster and more stressful."]},{"type":"heading","level":2,"text":"4 Standard Failure Readability","id":"competitive-tap-against-me-core-gameplay-4-standard-failure-readability"},{"type":"p","text":"A player should know why they lost. The final seconds should be reviewable through clear motion, a brief result recap, and optionally a simple trace of the last taps or velocity state. Sudden hidden modifiers, ambiguous ground collision, or network corrections that appear as unexplained deaths undermine trust."},{"type":"heading","level":2,"text":"5 Session Targets","id":"competitive-tap-against-me-core-gameplay-5-session-targets"},{"type":"p","text":"Competitive sessions should support rapid rematches and short attention windows. Survival averages will vary by skill; the matchmaking discussion uses examples such as a 15-second player versus a 72-second player to illustrate the need for meaningful skill segmentation. The game should not assume one universal target duration."}]},{"id":"competitive-controls-physics-and-difficulty","number":8,"title":"8. Competitive Controls, Physics, and Difficulty","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Input","id":"competitive-controls-physics-and-difficulty-1-input"},{"type":"p","text":"The primary input is a screen tap. The game must feel responsive without allowing input noise, accidental edge taps, or device sampling differences to create unfair advantages."},{"type":"p","text":"WORKING Tap position may influence horizontal direction or movement bias, especially where left/right navigation is needed. This should remain configurable and be validated against one-thumb accessibility."},{"type":"heading","level":2,"text":"2 Physics Principles","id":"competitive-controls-physics-and-difficulty-2-physics-principles"},{"type":"ul","items":["Upward impulse: a valid tap adds upward velocity or force rather than teleporting the hero.","Momentum: movement should carry naturally enough that recovery and overcorrection matter.","Gravity curve: gravity can intensify over time to create escalation, but the curve must remain learnable.","Ceiling behavior: the game should avoid allowing a player to park safely at the top. A ceiling response, diminishing lift, or arena rule should keep movement active.","Collision clarity: the ground boundary must be visually obvious and collision should match the art.","Frame independence: physics and tap validation must be deterministic or normalized across supported refresh rates."]},{"type":"heading","level":2,"text":"3 Difficulty Escalation","id":"competitive-controls-physics-and-difficulty-3-difficulty-escalation"},{"type":"p","text":"CONFIRMED Gravity increases over time in the core survival concept."},{"type":"p","text":"CANDIDATE Additional escalation tools include stronger wind, fewer beneficial pickups, more poisonous fruit, moving or shrinking safe regions, environmental hazards, and faster arena motion."},{"type":"p","text":"Difficulty should escalate through one or two readable variables at a time. Layering every hazard simultaneously creates noise rather than mastery. Ranked modes require fixed and published rule sets; experimental combinations can live in events or unranked modes."},{"type":"heading","level":2,"text":"4 Tap Validation","id":"competitive-controls-physics-and-difficulty-4-tap-validation"},{"type":"ul","items":["Count only taps received during active gameplay and inside valid input regions.","Prevent menus, ads, notifications, or overlays from generating gameplay taps.","Record tap timestamps for local analysis and server verification where appropriate.","Use reasonable upper bounds and behavioral analysis rather than punishing fast legitimate players solely for high taps per second.","Separate display tap count from authoritative match simulation when network play requires reconciliation."]},{"type":"heading","level":2,"text":"5 Feel Tuning","id":"competitive-controls-physics-and-difficulty-5-feel-tuning"},{"type":"p","text":"The best physics are not necessarily the most realistic. The hero should feel bouncy, expressive, and recoverable early, then increasingly demanding. Hit-stop, squash-and-stretch, subtle camera response, and tap sounds can increase perceived responsiveness without changing simulation power."}]},{"id":"competitive-modes-and-match-structures","number":9,"title":"9. Competitive Modes and Match Structures","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Launch-Critical Modes","id":"competitive-modes-and-match-structures-1-launch-critical-modes"},{"type":"table","rows":[["Mode","Purpose","Population requirement","Launch priority"],["Solo Survival","Personal best, practice, achievement progress, baseline performance profile","None","Essential"],["Local Play","Immediate social play and testing where device format permits","Local participants","Useful"],["Private Online Match","Direct account-to-account validation and friend competition","Known opponent","Essential networking milestone"],["Public Matchmaking","Core scalable competitive experience","Human pool plus bot backfill","High"],["Ranked","Seasonal status and long-term mastery","Stable rules, anti-cheat, enough match confidence","After reliable public play"]]},{"type":"heading","level":2,"text":"2 Match Rule Families","id":"competitive-modes-and-match-structures-2-match-rule-families"},{"type":"p","text":"CONFIRMED The design has discussed Survival, Most Taps, First to Zero, and Dual Victory as possible structures."},{"type":"heading","level":3,"text":"Survival","id":"competitive-modes-and-match-structures-survival"},{"type":"p","text":"Last airborne wins. This is the cleanest expression of the core mechanic and should remain the primary competitive rule until alternate modes prove equally readable."},{"type":"heading","level":3,"text":"Most Taps","id":"competitive-modes-and-match-structures-most-taps"},{"type":"p","text":"Players compete for the most valid taps within a time or survival framework. This mode requires careful anti-macro validation and should not reward meaningless tapping that ignores movement skill."},{"type":"heading","level":3,"text":"First to Zero","id":"competitive-modes-and-match-structures-first-to-zero"},{"type":"p","text":"A life-based mode where one player reduces the other to zero. The exact damage and regeneration model has not been finalized. Earlier concepts included life, regeneration per tap, total life, and tap-rate upgrades; these must never become purchasable competitive power."},{"type":"heading","level":3,"text":"Dual Victory","id":"competitive-modes-and-match-structures-dual-victory"},{"type":"p","text":"A match can recognize multiple accomplishments-for example, outlasting an opponent while also meeting a tap or objective condition. This should be presented as a bonus reward or event rule rather than making standard victories difficult to understand."},{"type":"heading","level":3,"text":"Tournament and Free-for-All","id":"competitive-modes-and-match-structures-tournament-and-free-for-all"},{"type":"p","text":"CANDIDATE Real-time free-for-all, elimination brackets, tournaments, and survival leaderboards are valid expansion directions after 1v1 reliability and population are established."},{"type":"heading","level":2,"text":"3 Rematch and Result Flow","id":"competitive-modes-and-match-structures-3-rematch-and-result-flow"},{"type":"ul","items":["Show winner, survival time, valid taps, key pickups, rating change, challenge progress, and earned rewards.","Provide a fast rematch path.","Do not bury the reason for a rating change.","Allow a player to inspect an opponent profile without interrupting rematch momentum.","Use celebratory cosmetics without obscuring the result."]}]},{"id":"pickups-hazards-and-arena-dynamics","number":10,"title":"10. Pickups, Hazards, and Arena Dynamics","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Green Apples","id":"pickups-hazards-and-arena-dynamics-1-green-apples"},{"type":"p","text":"CONFIRMED Green Apples provide a beneficial jump-force or lift boost."},{"type":"p","text":"The boost should be strong enough to influence routing but not so powerful that one spawn decides a match. Spawn visibility and pickup timing must allow both players to understand the opportunity."},{"type":"heading","level":2,"text":"2 Purple Fruit / Poisonous Fruit","id":"pickups-hazards-and-arena-dynamics-2-purple-fruit-poisonous-fruit"},{"type":"p","text":"CONFIRMED Purple poisonous fruit increases gravity or otherwise debuffs airborne control."},{"type":"p","text":"Poison fruit can create risk, denial, or achievement opportunities. The player should see when poison is active and understand its duration or severity. Achievements such as Life of Poisonous Fruit, Toxic Appetite, Poison-Proof, Maximum Poison, and Bad Decisions support the identity of this system."},{"type":"heading","level":2,"text":"3 Hero Coin Pickup","id":"pickups-hazards-and-arena-dynamics-3-hero-coin-pickup"},{"type":"p","text":"CONFIRMED Golden Hero tokens were discussed as spawning pickups spendable in the shop. The canonical currency name should be Hero Coin; a golden token can be its visual pickup form."},{"type":"p","text":"Competitive coin rewards must be tuned so players do not intentionally sabotage matches to farm. Ranked rewards, completion bonuses, and capped pickup value are safer than unlimited spawning."},{"type":"heading","level":2,"text":"4 Pickup Responsiveness","id":"pickups-hazards-and-arena-dynamics-4-pickup-responsiveness"},{"type":"p","text":"CONFIRMED Current pickup behavior has felt too reactive and quick. Item collection or bot response to items should be slowed and made more human-readable."},{"type":"ul","items":["Add a brief anticipation window or proximity threshold.","Avoid bots snapping to a pickup on the exact frame it appears.","Give pickups readable spawn animation and stable collision.","Allow high-skill interception without making every item deterministic.","Log pickup timestamps and contest outcomes for balance analysis."]},{"type":"heading","level":2,"text":"5 Arena Dynamics","id":"pickups-hazards-and-arena-dynamics-5-arena-dynamics"},{"type":"p","text":"CANDIDATE Wind, moving ground, shrinking regions, moving obstacles, environmental hazards, and themed arenas can expand variety."},{"type":"p","text":"Arena modifiers should be classified as ranked-safe, unranked, or event-only. Ranked-safe modifiers must be symmetrical, clearly telegraphed, and deterministic. Cosmetic arena themes must not hide collision edges or pickups."}]},{"id":"bots-ghosts-and-population-strategy","number":11,"title":"11. Bots, Ghosts, and Population Strategy","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Why Bots Are Needed","id":"bots-ghosts-and-population-strategy-1-why-bots-are-needed"},{"type":"p","text":"A new competitive game cannot assume a healthy matchmaking pool at every rating, region, and hour. Bots prevent empty queues and allow immediate testing. They are a population bridge, not a substitute for authentic competition."},{"type":"p","text":"CONFIRMED Bots are an acceptable solution for public matches when human opponents are unavailable, provided they do not behave like perfect tapping machines."},{"type":"heading","level":2,"text":"2 Bot Fairness Rules","id":"bots-ghosts-and-population-strategy-2-bot-fairness-rules"},{"type":"ul","items":["Bots use the same gravity, tap impulses, momentum, collision, pickups, character stats, abilities, and arena rules as players.","Bots do not read future random events or hidden state.","Bots have reaction delay, attention limits, execution error, and recovery behavior appropriate to their rating.","Bots do not instantly acquire items or perfectly optimize every tap.","Bots should be disclosed as CPU or AI challengers rather than disguised as human players.","Bot difficulty is derived from the player's matchmaking band and recent performance, not from predatory loss manipulation."]},{"type":"heading","level":2,"text":"3 Bot Behavior Model","id":"bots-ghosts-and-population-strategy-3-bot-behavior-model"},{"type":"p","text":"A credible bot should operate from imperfect perception. It estimates vertical velocity, distance to ground, available recovery, nearby pickups, and opponent state. It chooses among survival, pursuit, pickup, denial, and conservative recovery behaviors. Noise should affect timing and target choice, not merely add random failure."},{"type":"heading","level":2,"text":"4 Ghost Opponents","id":"bots-ghosts-and-population-strategy-4-ghost-opponents"},{"type":"p","text":"WORKING Recorded-run ghost opponents may be an even stronger early population solution for asynchronous competition."},{"type":"p","text":"A ghost replays a real player's timestamped input or authoritative movement trace. Ghosts provide human rhythm and mistakes without requiring simultaneous presence. They can power daily challenges, rival replays, friend challenges, and rank-adjacent modes. They should be labeled as recorded runs and protected against stale physics versions."},{"type":"heading","level":2,"text":"5 Ranked Restrictions","id":"bots-ghosts-and-population-strategy-5-ranked-restrictions"},{"type":"p","text":"WORKING Lower and mid tiers may permit disclosed bot backfill when queues are thin. High tiers should increasingly prioritize or require human-versus-human matches."},{"type":"p","text":"The exact cutoff should be based on population data. A player's ranked badge must not imply human-only achievement if a substantial portion of the path was against undisclosed or exploitable bots."}]},{"id":"matchmaking-glicko-rating-tiers-and-seasons","number":12,"title":"12. Matchmaking, Glicko Rating, Tiers, and Seasons","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Rating Model","id":"matchmaking-glicko-rating-tiers-and-seasons-1-rating-model"},{"type":"p","text":"CONFIRMED The preferred rating approach is Glicko-style rather than simple Elo, combined with a rolling survival-performance profile."},{"type":"p","text":"Glicko is useful because it tracks both rating and uncertainty. New or inactive players can move more quickly until the system becomes confident. Rating alone is not enough for TAM because two players may have similar win records while having dramatically different survival capacity."},{"type":"heading","level":2,"text":"2 Performance Profile","id":"matchmaking-glicko-rating-tiers-and-seasons-2-performance-profile"},{"type":"p","text":"Matchmaking should maintain recent and lifetime metrics such as median survival time, trimmed mean survival time, late-run consistency, valid tap rate, pickup behavior, opponent strength, and result variance. The explicit design example is that someone averaging about 15 seconds should not routinely face someone averaging about 72 seconds. A 63-second player facing a 72-second player may be a productive stretch match."},{"type":"heading","level":2,"text":"3 Match Search Expansion","id":"matchmaking-glicko-rating-tiers-and-seasons-3-match-search-expansion"},{"type":"ol","items":["Begin with a narrow Glicko and survival-profile range.","Expand gradually based on queue time.","Prefer a disclosed bot or ghost over an obviously hopeless human mismatch.","Protect new players from high-confidence veterans even when surface rating is similar.","Use connection quality and region after skill compatibility, not instead of it."]},{"type":"heading","level":2,"text":"4 Tiers","id":"matchmaking-glicko-rating-tiers-and-seasons-4-tiers"},{"type":"p","text":"CONFIRMED The ranked ladder should use visible tiers such as Bronze, Silver, Gold, and Platinum, with additional upper tiers as the system matures."},{"type":"p","text":"WORKING The presentation can take inspiration from Hearthstone's approachable tier progression and seasonal climb without copying its exact rules."},{"type":"ul","items":["Tiers should communicate broad achievement; Glicko remains the precise hidden or secondary measure.","Divisions within tiers can create steady milestones.","Promotion moments should be celebratory but not excessively slow.","Rank floors may be used carefully at lower tiers to reduce frustration.","Top-tier placement should depend on credible human competition and stable anti-cheat."]},{"type":"heading","level":2,"text":"5 Season Structure","id":"matchmaking-glicko-rating-tiers-and-seasons-5-season-structure"},{"type":"p","text":"CONFIRMED Ranked seasons reset every 90 days."},{"type":"p","text":"A reset should not erase permanent collection, achievements, lifetime statistics, or Infinity progress. It should compress or partially reset ranked standing so players have a reason to climb again. End-of-season rewards should be cosmetic and scaled by achieved rank."},{"type":"heading","level":2,"text":"6 Seasonal Rewards","id":"matchmaking-glicko-rating-tiers-and-seasons-6-seasonal-rewards"},{"type":"ul","items":["Rank badge or profile frame reflecting the highest achieved tier.","Season-exclusive hero variant, tap effect, particle, entrance, or victory pose.","Hero Coins within a controlled range.","Permanent season record on the profile.","No competitive stat advantage in the next season."]},{"type":"heading","level":2,"text":"7 Rating Integrity","id":"matchmaking-glicko-rating-tiers-and-seasons-7-rating-integrity"},{"type":"ul","items":["Use authoritative match records and idempotent result submission.","Detect repeated opponent farming, intentional disconnect patterns, and impossible tap traces.","Do not punish one disconnect as cheating; use confidence and repeated behavior.","Version rating calculations and preserve auditability.","Explain penalties and rating changes in player-readable terms."]}]},{"id":"competitive-rating-matchmaking-bot-and-season-implementation-reference","number":13,"title":"13. Competitive Rating, Matchmaking, Bot, and Season Implementation Reference","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: Original Expanded Bible pp. 105-130; Game Bible v1.0 competitive sections; dedicated ranked guidance across consolidated bibles."},{"type":"p","text":"CONFIRMED Use Glicko-2 as the underlying skill model and a readable tier/division ladder as the player-facing progression layer. Survival performance protects match quality but does not replace rating."},{"type":"heading","level":2,"text":"Rating Record","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-rating-record"},{"type":"table","rows":[["Field","Initial / canonical direction","Status"],["Rating","1500","WORKING initial value"],["Rating deviation","350","WORKING initial value"],["Volatility","0.06","WORKING initial value"],["Placement matches","5","CONFIRMED starting count"],["Season duration","90 days","CONFIRMED"],["Reset formula","1500 + ((old rating - 1500) x 0.60)","WORKING; compression configurable"]]},{"type":"p","text":"Persist rating, deviation, volatility, visible tier, division, stars/progress, placement state, season ID, peak/final rank, human/bot split, wins/losses, streaks, and match history as separate fields. Never infer matchmaking solely from the visible badge."},{"type":"heading","level":2,"text":"Matchmaking Signals","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-matchmaking-signals"},{"type":"table","rows":[["Signal","Initial weight","Purpose"],["Glicko rating and uncertainty","70%","Primary skill and confidence signal."],["Rolling survival profile","20%","Domain safeguard against obviously hopeless pairings while rating is uncertain."],["Connection and recent constraints","10%","Latency, region, disconnect behavior, version, and practical match quality."]]},{"type":"p","text":"TUNING Weights are a configurable starting model, not immutable mathematics. Target a modeled 40-60% win-probability range when population allows."},{"type":"heading","level":2,"text":"Survival Compatibility Bands","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-survival-compatibility-bands"},{"type":"table","rows":[["Player profile","Starting opponent window","Interpretation"],["0-15 seconds","Approximately +/-8 seconds","Protect true beginners and very short survivors."],["16-30 seconds","Approximately +/-12 seconds","Developing control."],["31-50 seconds","Approximately +/-15 seconds","Intermediate consistency."],["51-75 seconds","Approximately +/-18 seconds","Strong players can face credible stretch opponents."],["76+ seconds","Rating, percentile, and high-skill population model","Do not force rigid time brackets at the top end."]]},{"type":"p","text":"A 15-second player should not normally face a 72-second player. A 63-second player may reasonably face a 72-second player because the result remains credible and instructional."},{"type":"heading","level":2,"text":"Queue Expansion","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-queue-expansion"},{"type":"ol","items":["0-5 seconds: narrow rating, survival, region, version, and connection range; prioritize humans.","5-10 seconds: widen rating and survival slightly while preserving connection quality.","10-15 seconds: widen further inside protected fairness limits and continue prioritizing humans.","After roughly 15 seconds: insert an appropriate bot where rank and mode policy allow; ranked queues may wait longer."]},{"type":"heading","level":2,"text":"Bot Reaction and Decision Model","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-bot-reaction-and-decision-model"},{"type":"table","rows":[["Bot band","Recognition / decision delay","Useful-item pursuit"],["Beginner","600-1,000 ms","25-45%"],["Developing","450-800 ms","Tunable between beginner and intermediate"],["Intermediate","300-650 ms","45-70%"],["Skilled","200-500 ms","65-85%"],["Advanced","140-350 ms","Tunable between skilled and elite"],["Elite","100-280 ms","75-92%"]]},{"type":"ul","items":["Bots use the same gravity, impulses, momentum, collisions, pickup rules, arena rules, information, and legal abilities as humans.","Bots cannot know future spawns, react on the exact spawn frame, recover perfectly, or use hidden movement advantages.","Human-like errors include early/late taps, overcorrection, panic, ignored items, risky pursuit, poor item use, and failed recovery.","Performance varies around a target distribution. A 63-second target bot may commonly finish 52-72 seconds, sometimes fail at 40-50, and occasionally reach 73-82.","Personalities include Floater, Aggressor, Climber, Technician, Trickster, and Panicker; personality changes decisions, never physics."]},{"type":"heading","level":2,"text":"Visible Ladder and Unresolved Division Count","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-visible-ladder-and-unresolved-division-count"},{"type":"p","text":"WORKING Current working default: Bronze through Diamond use divisions V-I; Master is rating-based; Grandmaster is leaderboard-based. A duplicate consolidated PDF instead uses III-I, so division count remains in the Decision Register until formally locked."},{"type":"table","rows":[["Tier","Working presentation","Bot policy direction"],["Bronze","V-I; 3 stars per division","Allowed"],["Silver","V-I; 4 stars per division","Allowed"],["Gold","V-I; 5 stars per division","Reduced frequency"],["Platinum","V-I; 5 stars per division","Rare; human preferred"],["Diamond","V-I; 5 stars per division","Emergency only; reduced prestige impact"],["Master","Rating / leaderboard presentation","Human only"],["Grandmaster","Leaderboard placement","Human only"]]},{"type":"p","text":"Rank floors are recommended at Bronze V, Silver V, Gold V, Platinum V, Diamond V, and Master. Visible win streaks may begin after three wins and grant an example two stars per win in lower/middle tiers; Glicko math never doubles. Streak bonuses stop near Diamond or Master."},{"type":"heading","level":2,"text":"Bot Choice and Ranked Reward Policy","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-bot-choice-and-ranked-reward-policy"},{"type":"p","text":"An unranked preference may expose Allow Bot Opponents: On / Off with an explicit warning that Off can lengthen queues. Ranked may override the preference under a published tier/queue policy; it must never hide the fact that an opponent is a bot."},{"type":"table","rows":[["Rank band","Bot availability","Candidate rating / visible progression treatment"],["Bronze / Silver","Allowed","Normal stars; normal or slightly reduced Glicko gain; reduced loss when losing to a bot."],["Gold / Platinum","Reduced / rare","Reduced Glicko gains; visible progression remains readable; bot frequency capped."],["Diamond","Emergency backfill after extended queue","Reduced gain and loss; repeated bot wins cannot drive leaderboard-critical advancement."],["Master / Grandmaster","Human only","No bot backfill; prestige and leaderboard position rely on verified human matches."]]},{"type":"heading","level":2,"text":"Candidate Seasonal Reset Placement","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-candidate-seasonal-reset-placement"},{"type":"table","rows":[["Previous finish","Working new-season start"],["Bronze","Bronze"],["Silver","Bronze or Silver V"],["Gold","Silver"],["Platinum","Gold"],["Diamond","Platinum"],["Master","Diamond"],["Grandmaster","Diamond or Master placement"]]},{"type":"p","text":"TUNING These visible placements are examples layered on the soft Glicko compression. They require simulation and depend on the unresolved III-I versus V-I division decision."},{"type":"heading","level":2,"text":"Candidate Peak-Rank Reward Ladder","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-candidate-peak-rank-reward-ladder"},{"type":"table","rows":[["Highest tier reached","Proposed permanent reward category"],["Bronze","Hero Coins and seasonal participation badge."],["Silver","Additional Hero Coins and profile badge."],["Gold","Seasonal tap effect."],["Platinum","Animated badge or profile frame."],["Diamond","Exclusive character particle effect."],["Master","Exclusive seasonal hero/character variant."],["Grandmaster","Numbered leaderboard badge and premium cosmetic."]]},{"type":"p","text":"Archive season number, highest rank, final rank, peak Glicko rating, win/loss record, best survival, leaderboard placement, human/bot split, and every granted reward. Reward qualification should use highest rank reached unless formally revised; final rank remains visible separately."},{"type":"heading","level":2,"text":"Authoritative Ranked Result Processing Order","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-authoritative-ranked-result-processing-order"},{"type":"ol","items":["Validate match evidence and pinned ruleset/version.","Confirm disconnect, abandonment, timeout, server-failure, and reconnect state.","Record both survival durations and supporting performance evidence.","Record winner, loser, placement, and exact result reason.","Update rolling performance statistics.","Calculate Glicko-2 rating, deviation, and volatility updates server-side.","Update visible stars, points, or division progress without altering Glicko math.","Apply win-streak changes and eligible visible bonus.","Update seasonal statistics and peak/final tracking.","Update bot statistics and anti-farming counters where applicable.","Check promotion, demotion, floor, placement completion, and upper-tier eligibility.","Grant milestone/seasonal rewards once through ledger/idempotency keys.","Save immutable match history and validation outcome.","Update eligible leaderboards after finalization."]},{"type":"heading","level":2,"text":"Disconnect Evidence","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-disconnect-evidence"},{"type":"p","text":"Log player disconnect timestamp, reconnect attempts, match state/phase, network error, client closure, server error, grace-window outcome, abandonment history, and final result reason. One unstable connection is not cheating; enforcement uses repeated high-confidence patterns and provides an appeal path."},{"type":"heading","level":2,"text":"Leaderboard Families","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-leaderboard-families"},{"type":"ul","items":["Highest verified Glicko rating and Grandmaster placement.","Highest average survival and longest individual verified survival.","Most ranked wins and highest win streak.","Most improved rating during the season.","Friends-only and, after population/privacy validation, regional views."]},{"type":"p","text":"Primary prestige boards use verified ranked matches. Bot-heavy statistics are excluded or clearly separated; Master and Grandmaster prioritize human-versus-human evidence."},{"type":"heading","level":2,"text":"Ranked Remote-Configuration Registry","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-ranked-remote-configuration-registry"},{"type":"p","text":"Remotely configurable values include season dates, tier thresholds, divisions/stars, floors, placement count, search duration, expansion intervals, survival compatibility, bot insertion timing, reaction ranges, awareness/pursuit, bot availability by tier, rewards against bots, rating compression, streak requirement/bonus, seasonal reward table, disconnect grace, and queue-penalty duration. Every match and season pins an immutable config version for replay and audit."},{"type":"heading","level":2,"text":"Ranked MVP and Post-MVP Boundary","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-ranked-mvp-and-post-mvp-boundary"},{"type":"table","rows":[["Scope","Included content"],["Initial MVP","Glicko-2; Bronze-Diamond; division/stars/floors after decision; 5 placements; rolling and recent-10 survival; rating+survival matchmaking; expanding search; bot backfill; 3 bot bands; randomized reactions/item delay; 90-day reset; rewards; history; server result validation; basic anti-farming."],["Post-MVP","Full bot personalities; advanced performance profile; friend/regional/Grandmaster leaderboards; ghosts; replay; spectating; seasonal stats pages; placement prediction; smurf/disconnect analysis; dynamic bot calibration; automated matchmaking tuning; richer reward tracks; tournaments; inactivity decay for upper tiers."]]},{"type":"heading","level":2,"text":"Ranked Definition of Done","id":"competitive-rating-matchmaking-bot-and-season-implementation-reference-ranked-definition-of-done"},{"type":"ul","items":["Two real players complete a ranked match and both Glicko records update correctly on the server.","Rating uncertainty changes update magnitude; visible stars, floors, promotions, and demotions behave as published.","Five placements produce a credible visible starting rank.","Queue widening is gradual, logged, and never normally pairs a 15-second player with a 72-second player.","Bots are visibly identified, fallible, rank-appropriate, and protected against repeat farming.","The 90-day reset soft-compresses rating, increases uncertainty, preserves history, and grants the correct peak-rank reward.","Disconnect, abandonment, verified server failure, duplicate submission, and reconnect rules produce one explainable result."]}]},{"id":"competitive-dynamic-day-night-and-gravity-presentation","number":14,"title":"14. Competitive Dynamic Day-Night and Gravity Presentation","part":"Part II","partName":"Competitive gameplay, ranked systems, and environment","blocks":[{"type":"p","text":"Source basis: Competitive Dynamic Day-Night and Gravity Presentation Bible v1.0, pp. 1-39. Approved design direction; implementation values remain subject to playtesting and performance validation."},{"type":"p","text":"LOCKED Time changes atmosphere. Gravity changes movement. The two systems may advance from the same authoritative match clock, but neither calculates, controls, or explains the other."},{"type":"heading","level":2,"text":"Feature Intention","id":"competitive-dynamic-day-night-and-gravity-presentation-feature-intention"},{"type":"p","text":"The competitive arena should feel like a world moving through time rather than static wallpaper. Sunrise, daylight, sunset, twilight, stars, moonlight, nocturnal ambience, and predawn provide atmosphere and a subtle sense of endurance. Mechanical difficulty remains in the gravity system. The environment remains synchronized, cosmetic, readable, and competitively neutral."},{"type":"ul","items":["Make the competitive world feel alive without competing for attention.","Give long survival runs a visual sense of accomplishment without replacing the timer or score.","Increase match-to-match variety through seed-controlled starting phases.","Protect characters, opponents, pickups, hazards, effects, warnings, and interface information during every phase.","Remove the misleading implication that darkness causes gravity or nighttime is punishment."]},{"type":"heading","level":2,"text":"Locked Cycle Rules","id":"competitive-dynamic-day-night-and-gravity-presentation-locked-cycle-rules"},{"type":"ul","items":["A complete competitive day/night cycle lasts exactly 120 seconds.","Transitions are continuous; the game must not switch abruptly among four background images.","The sun and moon visibly travel through portrait-safe arcs and have no collision or gameplay effect.","Both synchronized competitors, bots, replays, and spectators use the same authoritative phase.","Day/night never changes gravity, tap force, movement, collision, spawn probability, bot behavior, scoring, rating, or latency compensation.","The interface does not inherit world lighting.","Night cannot materially reduce visibility, and premium cosmetics cannot gain a visibility advantage.","The 120-to-0 wrap has no flash, palette reset, sprite teleport, asset hitch, or lighting discontinuity."]},{"type":"heading","level":2,"text":"Authoring Phase Baseline","id":"competitive-dynamic-day-night-and-gravity-presentation-authoring-phase-baseline"},{"type":"table","rows":[["Elapsed time","Normalized range","Phase","Presentation emphasis"],["0-12 s","0.00-0.10","Sunrise","Horizon glow; violet to warm orange; stars fade; morning mist/birds may appear."],["12-42 s","0.10-0.35","Morning / daylight","Cleanest competitive visibility; sun rises; short shadows; daylight creatures and highlights."],["42-60 s","0.35-0.50","Afternoon / sunset","Warmer orange, rose, red, and purple; longer shadows; protect gold/red/yellow pickups."],["60-72 s","0.50-0.60","Twilight","Sun below horizon; moon and stars emerge; artificial lights begin; rim-light support increases."],["72-108 s","0.60-0.90","Night","Moon arc; full stars; nocturnal ambience; readable characters and interactions; moonlight reflections."],["108-120 s","0.90-1.00","Predawn","Moon approaches horizon; stars fade; cool/pale glow reconnects seamlessly to sunrise."]]},{"type":"p","text":"TUNING Phase ranges are authoring guides, not hard scene cuts. Every color, light, shadow, star, ambience, and reaction property should interpolate across boundaries."},{"type":"heading","level":2,"text":"Starting-Phase Strategy","id":"competitive-dynamic-day-night-and-gravity-presentation-starting-phase-strategy"},{"type":"p","text":"The initial implementation begins at fixed sunrise (phase 0.00) so timing, synchronization, contrast, and loop bugs are reproducible. After validation, the server or authoritative match creator selects one curated anchor from the match seed."},{"type":"table","rows":[["Anchor","Normalized phase","Reason for curation"],["Sunrise","0.00","Clear cycle start and repeatable validation."],["Midday","0.25","Neutral high-readability scene."],["Sunset","0.45","Warm-color readability test."],["Early night","0.62","Night transition and artificial-light scene."],["Midnight","0.75","Full night presentation."],["Predawn","0.92","Cool low-light return toward sunrise."]]},{"type":"p","text":"A small deterministic offset may later reduce repetition. Completely uncontrolled random starts are discouraged because they create awkward transitions and inconsistent testing."},{"type":"heading","level":2,"text":"Celestial and Layering Rules","id":"competitive-dynamic-day-night-and-gravity-presentation-celestial-and-layering-rules"},{"type":"ul","items":["Sun and moon travel between opposite horizons on biome-configurable arcs; exact astronomy is less important than clear movement and composition.","Avoid placing celestial bodies behind the densest gameplay region for extended periods.","Recommended draw order: sky gradient, stars, sun/moon, distant clouds, far background, mid-background, near background, gameplay, foreground effects, interface.","No celestial collision, tap response, pickup creation, physics, rarity change, lens flare over gameplay, flash, or blinding effect exists in standard competitive play."]},{"type":"heading","level":2,"text":"Protected Gameplay Readability","id":"competitive-dynamic-day-night-and-gravity-presentation-protected-gameplay-readability"},{"type":"p","text":"Biome lighting may change dramatically, but the gameplay layer follows protected rules rather than simply brightening everything and flattening the hierarchy."},{"type":"ul","items":["Minimum hero and opponent brightness with subtle outlines and nighttime rim lighting.","Fixed or limited-range pickup emissive values and background dimming behind critical objects when necessary.","Controlled saturation and particle brightness directly behind gameplay objects.","Golden Hero Tokens remain distinct during sunset; Green Apples remain distinct from foliage; Purple Fruit remains distinct at twilight and night.","The timer, names, status, gravity meter, item indicators, connection warnings, ranking, pause controls, prompts, and results remain independent from world lighting.","Important objects use shape, iconography, outline, animation, contrast, and color rather than color alone."]},{"type":"heading","level":2,"text":"Gravity Presentation After Decoupling","id":"competitive-dynamic-day-night-and-gravity-presentation-gravity-presentation-after-decoupling"},{"type":"p","text":"Removing sky darkness as the gravity indicator requires a richer physical language. Increasing gravity may add faster downward acceleration, stronger downward particle drift, heavier squash, forceful recovery, limited threshold camera impulse, faster debris, descent streaks, downward distortion, environmental sway, impact anticipation, a subtle extreme-pressure vignette, a more active gravity meter, and denser low-frequency audio."},{"type":"p","text":"Low-gravity states use longer hang time, slower particle descent, floating accessories, upward dust/pollen, extended arcs, soft impacts, reduced squash, and wider trailing motion."},{"type":"p","text":"LOCKED Purple Fruit presentation is player-local and distinct from the time-based gravity ramp: a purple pulse, downward streak, gravity icon/timer, short low-frequency impact, and stronger downward-motion feedback are valid. It must never recolor the global sky or affect the opponent's environment."},{"type":"heading","level":2,"text":"Authoritative Environment Data","id":"competitive-dynamic-day-night-and-gravity-presentation-authoritative-environment-data"},{"type":"table","rows":[["Field","Purpose"],["match_id","Connects environment state to the authoritative match."],["environment_seed","Reproduces starting phase, decorative variants, clouds, stars, and seeded events."],["day_night_profile_id","Selects biome gradients, curves, celestial arcs, ambience, and fallback settings."],["cycle_duration","120.0 seconds for standard competitive play."],["starting_phase","Curated normalized phase selected by the authoritative match creator."],["authoritative_match_start_time","Source of elapsed match time and phase reconstruction."],["biome_id","Selects the competitive biome."],["environment_variant_id","Selects an allowed seeded visual variant."]]},{"type":"p","text":"Clients calculate phase as `(starting_phase + elapsed / cycle_duration) modulo 1`. The server does not send colors every frame. Under 50 ms drift may be ignored; 50-250 ms is smoothed; larger drift is corrected rapidly. Reconnect restores the authoritative phase with a short blend where possible."},{"type":"heading","level":2,"text":"Controller Responsibilities","id":"competitive-dynamic-day-night-and-gravity-presentation-controller-responsibilities"},{"type":"table","rows":[["Component","Owns","Must not own"],["MatchEnvironmentController","Authoritative configuration, phase, synchronization, biome profile coordination.","Gravity calculation."],["DayNightProfile","Gradients, curves, celestial arcs, ambience, performance fallbacks.","Player-specific or match-result state."],["CelestialController","Sun/moon position, opacity, glow, horizon hiding, safe composition.","Collision or gameplay effects."],["SkyRenderer","Gradient, stars, clouds, background-only lighting and low-cost modes.","Gameplay contrast or physics."],["GameplayReadabilityController","Hero/pickup contrast, outlines, rim light, minimum brightness, accessibility response.","Collision or simulation."],["GravityPresentationController","Particles, squash, pressure, audio, Purple Fruit presentation from effective gravity.","Sky phase."],["BiomeReactionController","Seeded day/night creatures, lights, plants, reflections, atmosphere.","Gameplay spawns or hazards."],["EnvironmentalAudioController","Crossfaded ambience below gameplay audio.","Restarting or controlling competitive music."]]},{"type":"heading","level":2,"text":"Performance and Accessibility","id":"competitive-dynamic-day-night-and-gravity-presentation-performance-and-accessibility"},{"type":"table","rows":[["Tier","Preserved identity","Reduced work"],["High","Full gradient, celestial movement, readability, ambience.","Uses glow, more stars, dynamic shadows, reflections, particles."],["Medium","Full gradient, sun/moon, readability, phase identity.","Reduced stars, shadows, particles, and simplified reflections."],["Low","Gradient/ramp sky, sun/moon, minimal stars, protected readability.","Static/disabled dynamic shadows, minimal particles, no expensive reflections."]]},{"type":"ul","items":["Reduced motion: simplify clouds, parallax, animals, gravity streaks, particles, and camera impulses while color progression continues.","Reduced effects: trim glow, stars, reflections, fireflies, fog, and shadow animation.","Night visibility: increase outline, rim light, pickup outline, and background separation without revealing hidden information.","Photosensitivity: no rapid celestial flashes, cycle lightning, star flicker, full-screen pulse, or abrupt exposure shift."]},{"type":"heading","level":2,"text":"Eight Delivery Phases","id":"competitive-dynamic-day-night-and-gravity-presentation-eight-delivery-phases"},{"type":"heading","level":3,"text":"0 - Audit and decoupling","id":"competitive-dynamic-day-night-and-gravity-presentation-0-audit-and-decoupling"},{"type":"p","text":"Find every gravity-derived tint/shader/global, document existing curves, create separate environment and gravity values, and prove neither reads the other."},{"type":"heading","level":3,"text":"1 - Core cycle MVP","id":"competitive-dynamic-day-night-and-gravity-presentation-1-core-cycle-mvp"},{"type":"p","text":"One test biome; fixed sunrise; normalized timer; gradient; sun, moon, stars; exact seamless 120-second wrap; stable UI; target Android test."},{"type":"heading","level":3,"text":"2 - Readability and art","id":"competitive-dynamic-day-night-and-gravity-presentation-2-readability-and-art"},{"type":"p","text":"Six phase palettes, rim light, pickup protection, token/apple/fruit tests, star/cloud/shadow tuning, and neutral editor lighting."},{"type":"heading","level":3,"text":"3 - Online synchronization","id":"competitive-dynamic-day-night-and-gravity-presentation-3-online-synchronization"},{"type":"p","text":"Environment seed, authoritative phase/time, drift correction, reconnect, private match, bot, replay, and spectator validation."},{"type":"heading","level":3,"text":"4 - Starting-phase variety","id":"competitive-dynamic-day-night-and-gravity-presentation-4-starting-phase-variety"},{"type":"p","text":"Curated anchors from the match seed, phase-distribution analytics, readability validation, and seamless transitions from every anchor."},{"type":"heading","level":3,"text":"5 - Biome reactions and ambience","id":"competitive-dynamic-day-night-and-gravity-presentation-5-biome-reactions-and-ambience"},{"type":"p","text":"Profile resources, day/night reactions, artificial lights, reflections, crossfades, deterministic events, and density limits."},{"type":"heading","level":3,"text":"6 - Gravity presentation","id":"competitive-dynamic-day-night-and-gravity-presentation-6-gravity-presentation"},{"type":"p","text":"Normalized strength, downward particles, squash, thresholds, Purple Fruit feedback, gravity audio, and accessibility controls."},{"type":"heading","level":3,"text":"7 - Optimization and release","id":"competitive-dynamic-day-night-and-gravity-presentation-7-optimization-and-release"},{"type":"p","text":"GPU/shader/overdraw, Android tiers, battery/thermal, 30/60 FPS, interruption/reconnect, all objects/skins/effects, analytics, and no hitches."},{"type":"heading","level":2,"text":"QA Matrix","id":"competitive-dynamic-day-night-and-gravity-presentation-qa-matrix"},{"type":"table","rows":[["Matrix","Required cases"],["Timing","Phase 0; every curated anchor; expected state at 30, 60, and 90 seconds; exact 120-second wrap; multiple loops; 30 FPS; 60 FPS; frame drops."],["Gravity independence","Change base gravity; disable ramp; freeze cycle while gravity continues in debug; Purple Fruit for A, B, and both; extreme gravity in day and night."],["Synchronization","Two physical devices; mixed frame rates and quality tiers; latency spike; packet loss; background/return; late spectator; replay zero/scrub; bot, ghost, private, and ranked match."],["Readability phases","Sunrise, day, sunset, twilight, night, and predawn."],["Readability objects","Default, bright, dark, and purple hero; Green Apple; Purple Fruit; Golden Hero Token; hazards; tap effects; character particles; opponent outline; timer; gravity meter; network warning."],["Performance","Entry, mid, and high Android tiers; battery saver; thermal throttle; maximum particles; two complex loadouts; night max stars/lights; sunset gradient/clouds; repeated restarts."]]},{"type":"heading","level":2,"text":"Day/Night Analytics","id":"competitive-dynamic-day-night-and-gravity-presentation-day-night-analytics"},{"type":"table","rows":[["Event","Required properties"],["Match Environment Initialized","match_id; mode; biome_id; profile_id; starting_phase; environment_seed; graphics_quality; device_performance_class"],["Match Ended","survival_duration; ending_phase; maximum_gravity; starting_phase; graphics_quality; average_fps; minimum_fps"],["Environment Resynchronized","drift_amount; correction_method; match_elapsed_time; device_type"],["Accessibility Setting Used","reduced_motion; reduced_effects; night_visibility; outline_strength"]]},{"type":"p","text":"Review whether starting phase correlates with loss/exit rate, low-end devices drop frames in specific phases, sunset changes pickup collection, corrections happen too often, or accessibility settings correlate with outcomes. Correlation triggers investigation; it does not prove cause or justify collecting unnecessary personal data."},{"type":"heading","level":2,"text":"Production Acceptance","id":"competitive-dynamic-day-night-and-gravity-presentation-production-acceptance"},{"type":"ul","items":["Exact seamless 120-second cycle with visibly moving sun and moon.","Gravity, Purple Fruit, and environment progression are fully independent.","Two devices maintain the same phase without per-frame server environment updates.","Night never obscures players, pickups, hazards, or interface; Golden Hero Tokens survive sunset, Green Apples survive green biomes, and Purple Fruit survives twilight/night.","Saved match data reproduces the environment for replay and spectating.","Low settings preserve identity; target Android hardware meets frame, thermal, battery, and load-hitch requirements.","Ambient layers never mask gameplay cues; music never restarts at cycle phases.","No purchase changes competitive visibility or environment advantage.","The editor supports a neutral-lighting workflow and a gameplay-lighting preview.","Gravity is communicated through physical feedback rather than darkness.","Background reactions remain cosmetic, deterministic where required, and non-distracting."]},{"type":"heading","level":2,"text":"Future Cosmetic Expansion","id":"competitive-dynamic-day-night-and-gravity-presentation-future-cosmetic-expansion"},{"type":"p","text":"Architecture may later support seasonal sun/moon variants, moon phases, aurora, meteor showers, comets, holiday skies, biome celestial bodies, distant storms, eclipses, private-match atmosphere, tournament skies, ranked-season themes, ending-phase victory screens, full-cycle statistics/achievements, secret long-survival cosmetics, spectator presentation, and cinematic replay controls. Every addition remains synchronized, readable, cosmetic, and non-pay-to-win."},{"type":"p","text":"PART 3"},{"type":"p","text":"INFINITY TAPS AND THE LIVING WORLD"},{"type":"p","text":"The no-loss exploration and fidget game: movement, reactions, zones, discovery, heroes, journal progress, and earned-only status."}]},{"id":"infinity-taps-core-experience","number":15,"title":"15. Infinity Taps: Core Experience","part":"Part III","partName":"Infinity Taps, living worlds, discovery, and heroes","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"p","text":"Infinity Taps is a no-loss, noncompetitive, local-first exploration and fidget experience where tapping moves the hero and causes the world to react."},{"type":"p","text":"CONFIRMED There is no traditional lose condition. Environmental hazards may create spectacle or movement changes, but they must not fail or punish the player."},{"type":"heading","level":2,"text":"1 Core Loop","id":"infinity-taps-core-experience-1-core-loop"},{"type":"ol","items":["The hero begins on the ground in a welcoming environment.","The player taps to move left, right, upward, or through the environment based on tap position and current movement state.","The world reacts: water splashes, plants move, animals respond, objects produce sound, and heroes acknowledge interaction.","The player travels through zones, discovers biomes, encounters heroes and variants, triggers secrets, and fills a journal.","Lifetime taps and distance accumulate even when no major discovery occurs.","Exclusive Infinity rewards unlock through play and cannot be purchased."]},{"type":"heading","level":2,"text":"2 Fidget-First Design","id":"infinity-taps-core-experience-2-fidget-first-design"},{"type":"p","text":"The experience must remain satisfying when the player is not pursuing an objective. The tap sound, movement arc, particle response, and environmental acknowledgement should be enough to support repetitive use. Goals enhance the loop but must not turn it into disguised ranked pressure."},{"type":"heading","level":2,"text":"3 Currency Rule","id":"infinity-taps-core-experience-3-currency-rule"},{"type":"p","text":"CONFIRMED Hero Coins do not spawn as normal pickups in Infinity Taps. The player earns one Hero Coin per 1,000 valid taps."},{"type":"p","text":"This rate gives the mode economic acknowledgement without making it the fastest currency farm. The counter should clearly distinguish lifetime taps, current-session taps, and the next Hero Coin threshold."},{"type":"heading","level":2,"text":"4 Pause and Persistence","id":"infinity-taps-core-experience-4-pause-and-persistence"},{"type":"ul","items":["The player may stop at any moment without losing progress.","The world can resume near the last safe location or biome checkpoint.","Temporary boosts may expire during active play but should not punish app interruption.","Rare encounter state should be saved long enough to avoid frustration from accidental app suspension.","Offline progress should not generate taps; Infinity Taps is active, not idle."]},{"type":"heading","level":2,"text":"5 MVP Identity","id":"infinity-taps-core-experience-5-mvp-identity"},{"type":"p","text":"WORKING The first Infinity Taps prototype should be a small zen playground: one biome, no failure, basic movement, reactive water, bush and tree behavior, one or two animals, a persistent tap counter, several exclusive achievements, and one hidden cosmetic or hero variant."}]},{"id":"infinity-taps-world-structure-zones-and-biomes","number":16,"title":"16. Infinity Taps World Structure, Zones, and Biomes","part":"Part III","partName":"Infinity Taps, living worlds, discovery, and heroes","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Zone Rhythm","id":"infinity-taps-world-structure-zones-and-biomes-1-zone-rhythm"},{"type":"p","text":"CONFIRMED Zones should be approximately two minutes long so a player can experience most of a song or musical arrangement before transitioning."},{"type":"table","rows":[["Approximate time","Purpose","Content"],["0:00-0:30","Establish the biome","Visual reveal, primary ambient layer, common animals, basic interactions"],["0:30-1:30","Exploration body","Collectibles, heroes, secrets, environmental chains, temporary boosts"],["1:30-2:00","Transition","Landmark, intensified layer, departure animation, next-biome foreshadowing"]]},{"type":"p","text":"Two minutes is a target cadence, not a rigid timer. A player should be able to linger for an encounter or secret without feeling forcibly removed. The system can measure distance, interaction completion, and time to determine a natural transition."},{"type":"heading","level":2,"text":"2 World Progression","id":"infinity-taps-world-structure-zones-and-biomes-2-world-progression"},{"type":"table","rows":[["Region family","Biomes / layers discussed","Distinctive interaction opportunities"],["Ground and pastoral","Basic Field, Meadow, Farmland","Grass, flowers, rabbits, fences, crops, puddles"],["Woodland","Forest, Jungle","Trees, leaves, vines, birds, squirrels, hidden heroes"],["Elevation","Mountain, cliffs, cloud approach","Wind, echoes, loose rocks, altitude transition"],["Dry regions","Desert, dunes","Sand bursts, heat shimmer, buried objects, desert animals"],["Volcanic","Volcanic Region","Lava, ash, obsidian, golem events, heat-reactive effects"],["Frozen","Arctic, Antarctic, snow fields","Snow piles, ice cracks, snow creatures, aurora ambience"],["Ocean surface","Beach, Surface Water, Sunlight Zone","Splashes, waves, fish, shells, floating objects"],["Deep ocean","Twilight, Midnight, Abyssal, Trench / Mariana-inspired depths","Bioluminescence, pressure ambience, rare creatures, hidden ruins"],["Sky","Cloud Layer, Upper Atmosphere","Cloud puffs, birds, storms, wind, aerial heroes"],["Space","Orbit, Moon, planets, distant worlds","Low gravity, stars, alien encounters, cosmic tap effects"]]},{"type":"heading","level":2,"text":"3 Biome Transition Rules","id":"infinity-taps-world-structure-zones-and-biomes-3-biome-transition-rules"},{"type":"ul","items":["Music should crossfade or layer rather than abruptly restart.","Colors and ambient particles should preview the next region.","Animals and objects can migrate between compatible border zones.","The hero's movement state should remain continuous unless a transition is intentionally theatrical.","The player should understand that they traveled somewhere, not selected a background from a menu."]},{"type":"heading","level":2,"text":"4 Temporary Movement Boosts","id":"infinity-taps-world-structure-zones-and-biomes-4-temporary-movement-boosts"},{"type":"p","text":"CONFIRMED Discussed Infinity boosts include velocity increases, tap-and-hold \"jet engine,\" anti-gravity, and extra-bouncy movement."},{"type":"table","rows":[["Boost","Behavior","Typical duration","Design guardrail"],["Velocity Increase","Raises travel speed and momentum.","10-25 seconds","Must remain controllable and not skip meaningful encounters unintentionally."],["Tap-and-Hold / Jet Engine","Holding produces sustained thrust and a dramatic engine effect.","10-25 seconds","Clearly separate from standard tap input and prevent accidental activation."],["Anti-Gravity","Reverses or changes the normal tap/gravity relationship; taps may force the hero downward.","10-25 seconds","No failure; use as playful traversal, not punishment."],["Extra Bouncy","Greatly increases jump height and elastic response.","10-25 seconds","Camera and collision must handle exaggerated movement safely."]]},{"type":"heading","level":2,"text":"5 Rare Encounters","id":"infinity-taps-world-structure-zones-and-biomes-5-rare-encounters"},{"type":"ul","items":["Alien or unusual creature encounters in space and distant worlds.","Hero variants tied to specific biomes or weather.","Extremely rare tap-effect discoveries, including historical 0.001% concepts.","Environmental storytelling such as footprints, abandoned objects, or creatures leading the player to a hidden area.","Seasonal worlds that temporarily alter animals, music, and interaction outcomes."]}]},{"id":"living-world-interaction-system","number":17,"title":"17. Living World Interaction System","part":"Part III","partName":"Infinity Taps, living worlds, discovery, and heroes","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"p","text":"The central Infinity Taps question is: \"I wonder what happens if I tap that.\" The world should already be moving before the tap; the player interrupts, influences, or plays with a living scene rather than activating a static backdrop."},{"type":"heading","level":2,"text":"1 Interaction Depth Model","id":"living-world-interaction-system-1-interaction-depth-model"},{"type":"table","rows":[["Layer","Player behavior","World response"],["Immediate","First tap","Fast readable movement, sound, splash, shake, glance, chirp, or particle response"],["Escalated","Several taps","Larger animation, relocation, dropped object, altered sound, or social reaction"],["Persistent","Repeated rapid taps","Special behavior, escape, hiding, mini-event, cooldown, or secret"],["Contextual","Tap under special conditions","Different result based on biome, weather, time, hero, nearby object, or equipped effect"],["Chain","Tap creates another object's reaction","Connected sequence that makes the environment feel systemic"]]},{"type":"heading","level":2,"text":"2 Animal Behavior","id":"living-world-interaction-system-2-animal-behavior"},{"type":"table","rows":[["Animal","First response","Repeated / rare response"],["Rabbit","Looks toward tap, twitches ears, small hop","Hops away, enters burrow, kicks dirt, leads to a hidden object, or returns with an accessory"],["Bird","Chirps, turns, hops to another branch","Flies away, drops a feather, triggers a flock, lands on the hero, or leads to a nest"],["Squirrel","Freezes and watches","Climbs, throws an acorn, hides an item, steals a harmless object, or begins a short chase"],["Frog","Croaks or shifts","Jumps farther, dives into water, lands on a lily pad, or joins a musical sequence"],["Fish","Changes direction under a ripple","Jumps, scatters a school, reveals a larger fish, treasure, aquatic hero, or rare creature"]]},{"type":"p","text":"CONFIRMED Animal interactions must remain playful. Tapping should not visually injure animals."},{"type":"heading","level":2,"text":"3 Environmental Objects","id":"living-world-interaction-system-3-environmental-objects"},{"type":"table","rows":[["Object","Basic reaction","Escalated possibilities"],["Water","Small splash and ripple","Overlapping waves, larger splash, fish reaction, freezing crack, puddle effect, submerged reveal"],["Bush","Wiggles","Leaves, berries, insects, or small animals emerge; hidden passage or collectible may appear"],["Tree leaves","Leaves fall from tapped area","More leaves, fruit, petals, snow, birds, squirrels, or branch motion"],["Tree trunk / branch","Shake or bend","Object falls, animal relocates, chain reaction begins"],["Grass / flowers","Bend or sway","Petals, dandelion seeds, bloom sequence, butterflies or bees"],["Rock / ground","Sound, pebble roll, dust, compression","Fossil, insect, buried object, crack, material-specific secret"],["Snow","Compresses or puffs","Piles form, melt later, or support a snow creature event"],["Sand / mud","Burst, dent, or splatter","Tracks, buried item, creature emergence, or temporary pattern"]]},{"type":"heading","level":2,"text":"4 Interaction Chains","id":"living-world-interaction-system-4-interaction-chains"},{"type":"ul","items":["A tap shakes a tree; an acorn falls; a squirrel collects it; following the squirrel reveals a hero.","A water splash startles a fish; the fish jumps; a frog moves; the lily pad exposes a collectible.","Repeated snow taps create a pile; the pile qualifies for a rare evil snowman emergence.","Lava pools cool into obsidian; enough qualified interaction can awaken an obsidian golem.","Flowers release seeds; wind carries them; new flowers bloom elsewhere in the zone."]},{"type":"heading","level":2,"text":"5 Repeated-Tap Personality","id":"living-world-interaction-system-5-repeated-tap-personality"},{"type":"p","text":"Characters should not loop one reaction forever. A resting hero might open one eye, look around, sit up, become annoyed, throw a pillow, and relocate. An animal might progress from curiosity to playfulness to escape. After the final response, a short cooldown preserves personality and reduces animation spam."},{"type":"heading","level":2,"text":"6 Discovery Journal","id":"living-world-interaction-system-6-discovery-journal"},{"type":"p","text":"The journal records biomes, heroes, variants, animals, behaviors, landmarks, secrets, environmental reactions, rare events, and unresolved mysteries. Entries can use partial completion such as \"Rabbit Behaviors: 3 of 7\" so the player understands that experimentation remains possible without revealing the exact solution."},{"type":"ul","items":["World Traveler","Into the Clouds","Beyond the Sky","One Small Tap","Going Deep","At the Bottom","First Contact"]}]},{"id":"heroes-variants-encounters-and-collection","number":18,"title":"18. Heroes, Variants, Encounters, and Collection","part":"Part III","partName":"Infinity Taps, living worlds, discovery, and heroes","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Hero Role","id":"heroes-variants-encounters-and-collection-1-hero-role"},{"type":"p","text":"Heroes are playable identity, collectible content, environmental actors, and the bridge between the two products. A hero should be recognizable in competitive play and still feel alive when encountered naturally in Infinity Taps."},{"type":"heading","level":2,"text":"2 Encounter Presentation","id":"heroes-variants-encounters-and-collection-2-encounter-presentation"},{"type":"p","text":"CONFIRMED When the player finds an unowned hero or variant in Infinity Taps, tapping it should provide an opportunity to purchase or unlock that exact hero or variant."},{"type":"ol","items":["The hero first reacts inside the world.","A compact identification card appears without immediately freezing exploration.","The card shows hero name, variant name, rarity, ownership state, and acquisition method.","A second deliberate action opens the full purchase or unlock view.","Closing the view returns the player to the same encounter state where practical."]},{"type":"heading","level":2,"text":"3 Owned Hero Encounter","id":"heroes-variants-encounters-and-collection-3-owned-hero-encounter"},{"type":"ul","items":["The hero waves, emotes, or acknowledges the player.","It may briefly accompany the player or trigger a small interaction.","Repeat encounters can reveal lore, friendship progress, poses, dialogue, or journal details.","A minor discovery bonus may be granted without turning repeat spawns into currency farming."]},{"type":"heading","level":2,"text":"4 Owned Base, Unowned Variant","id":"heroes-variants-encounters-and-collection-4-owned-base-unowned-variant"},{"type":"p","text":"The game must identify the exact variant rather than treating ownership of the base hero as full ownership. Some variants are purchasable after discovery; others require an Infinity challenge, friendship threshold, seasonal event, secret interaction, or direct earn-only condition."},{"type":"heading","level":2,"text":"5 Acquisition Categories","id":"heroes-variants-encounters-and-collection-5-acquisition-categories"},{"type":"table","rows":[["Category","Rule","Example use"],["Standard purchase","Discover and buy with Hero Coins.","Common or catalog heroes"],["Encounter-exclusive purchase","Can only be bought while or after found in the world.","Biome-linked variants"],["Challenge unlock","Complete a defined exploration or tap objective.","Traversal or interaction specialist"],["Friendship unlock","Meet and interact repeatedly.","Personality-driven hero"],["Secret unlock","Trigger an unusual environmental chain.","Hidden variant"],["Seasonal encounter","Available during a limited season or event.","Holiday or seasonal form"],["Infinity-exclusive earn","Cannot be bought; must be earned in Infinity Taps.","Prestige exploration reward"]]},{"type":"heading","level":2,"text":"6 Rarity and Discovery","id":"heroes-variants-encounters-and-collection-6-rarity-and-discovery"},{"type":"p","text":"Rarity should describe encounter frequency, acquisition difficulty, or presentation complexity-not competitive power. A rare hero can have more elaborate animation or a demanding discovery condition without superior ranked statistics."},{"type":"heading","level":2,"text":"7 Character Identity Systems","id":"heroes-variants-encounters-and-collection-7-character-identity-systems"},{"type":"ul","items":["Base hero and named variants.","Idle animation, movement style, tap response, victory pose, and entrance.","Short lore card plus discoverable notes.","Compatible particle, tap, trail, and profile presentation.","Optional friendship or encounter history in Infinity Taps."]}]},{"id":"velvet-hex-character-variant-and-cast-production-reference","number":19,"title":"19. Velvet Hex Character, Variant, and Cast Production Reference","part":"Part III","partName":"Infinity Taps, living worlds, discovery, and heroes","blocks":[{"type":"p","text":"Source basis: Game Design Bible (1) / duplicate Game Design Bible pp. 14-17; TAM Design Bible pp. 18-19; current workspace skin catalog and supplied art assets."},{"type":"p","text":"CHARACTER PURPOSE Characters are the emotional and collectible face of TAM. They must be instantly recognizable in motion, readable on a phone, expressive under squash-and-stretch animation, and mechanically equivalent in competitive play."},{"type":"heading","level":2,"text":"Velvet Hex Canon","id":"velvet-hex-character-variant-and-cast-production-reference-velvet-hex-canon"},{"type":"p","text":"Velvet Hex - A stitched tuxedo fiend that trades cuddles for tiny curses."},{"type":"table","rows":[["Facet","Production requirement"],["Core silhouette","Tuxedo-cat body; plush/slime-like triangular mass; cat ears; two demon horns; pointed/spade-like tail; button/X eyes; white tuxedo chest; purple bow tie; small fangs where readable."],["Personality","Cute, mischievous, strange, cuddly, skeptical, faintly dangerous, and expressive without cruelty."],["Movement identity","Squash, stretch, wobble, float, and splat-like landings while the silhouette remains identifiable at native sprite scale."],["Material flexibility","The body may read as stitched plush, slime, ice, toxic ooze, royal fabric, molten matter, spectral material, arcade energy, or costume without losing the anchor features."],["Competitive footprint","Every skin and hero uses the approved equivalent collision/gameplay footprint unless a future non-monetized ability system is separately balanced and declared."],["Pixel-art standard","Retro 1990s arcade-inspired pixel art, small native sprites, visible clusters, limited theme palette, crisp nearest-neighbor integer scaling, true alpha, and no anti-aliased/painterly filter treatment."]]},{"type":"heading","level":2,"text":"Standard Six-Frame Jump Sheet","id":"velvet-hex-character-variant-and-cast-production-reference-standard-six-frame-jump-sheet"},{"type":"table","rows":[["Frame","Pose","Purpose"],["1","Neutral / ready","Baseline idle or airborne-ready silhouette."],["2","Compression / squash","Anticipation immediately before upward force."],["3","Launch / stretch","Elongation as the impulse begins."],["4","Rising / airborne","Body regains its recognizable shape during ascent."],["5","Apex / suspended","Readable hang-time pose before descent."],["6","Landing / impact","Squash plus theme-specific particles or impact treatment."]]},{"type":"p","text":"PRODUCTION LOCK All variants use identical frame dimensions, baseline, pivot points, frame order, collision reference, and export layout so a texture/skin swap does not require animation-code changes. Final native dimensions, proportions, and per-frame pixel budget remain an art-production decision until formally approved."},{"type":"heading","level":2,"text":"Named Velvet Hex Variant Register","id":"velvet-hex-character-variant-and-cast-production-reference-named-velvet-hex-variant-register"},{"type":"table","rows":[["Variant","Defining treatment","Evidence / status"],["Classic Velvet Hex","Black-and-white tuxedo slime/plush demon; purple horns, button/X eyes, bow tie, white chest, fangs, pointed tail.","Canonical silhouette anchor; current default catalog item."],["Scarlet / Vampire Hex","Dracula-inspired red/black/purple coat or trench treatment; red horns; vampire teeth; tuxedo chest and tie retained.","Documented production variant; current store ID not present."],["Beach Hex","Bright tropical/beachwear treatment while retaining chest, bow tie, silhouette, and animation layout.","Documented production variant; current store ID not present."],["Toxic Hex","Neon toxic-green ooze, bubbles, drips, green ear highlights, contaminated horns, toxic landing splash.","Documented and current 100-Hero-Coin catalog item."],["Golden / Royal Hex","Gold and purple royal trim, crown/horn ornament, cloak accents, and gold-edged silhouette.","Documented; current Golden Hex catalog item at 100 Hero Coins."],["Arcade Hex","Neon cyan/magenta/purple, arcade icons, scanline/energy motifs, and pixel sparks.","Documented and current 100-Hero-Coin catalog item."],["Frozen Hex","Deep ice coverage, shard horns, ice-cube eyes, frosted edge buildup, blue bow tie, snow/ice particles, readable tuxedo chest.","Documented and current 100-Hero-Coin catalog item; production correction applies."],["Molten Hex","Glowing cracks and molten/fire material while preserving silhouette/readability.","Candidate promoted into current 100-Hero-Coin catalog."],["Ghost Hex","Pale spectral/translucent treatment without reducing trackability or collision readability.","Candidate promoted into current 100-Hero-Coin catalog."],["Corrupted Hex","Controlled pixel corruption/glitch accents localized around a readable body core.","Candidate promoted into current 100-Hero-Coin catalog."],["Strawberry Slime","Pink/red seeded slime identity with playful food-material treatment.","Candidate promoted into current 100-Hero-Coin catalog."],["Abyssal Hex","Deep-sea teal bioluminescence and self-lit detail.","Current 100-Hero-Coin catalog item; earlier Infinity-exclusive Abyssal Velvet concept creates an acquisition conflict to resolve."],["Meadow Hex","Soft green field/floral treatment.","Current 100-Hero-Coin catalog item; earlier Infinity-exclusive Meadow Velvet concept creates an acquisition conflict to resolve."],["First Contact Hex","Alien/contact treatment with bright green accents.","Current 100-Hero-Coin catalog item; earlier Infinity-exclusive First Contact concept creates an acquisition conflict to resolve."],["Cosmic Hex","Animated/variable nebula material and premium cosmic presentation.","Current 200-Hero-Coin catalog item."],["Prismatic Hex","Completionist prestige treatment.","Current earned-only item; price -1; never purchasable or bundled."]]},{"type":"p","text":"OPEN ACQUISITION CONFLICT The current store sells Abyssal, Meadow, and First Contact variants, while the Original Expanded Bible uses closely matching names for Infinity-exclusive rewards. Do not silently treat both as the same item. Resolve by renaming, making distinct designs/IDs, or changing acquisition before exclusivity claims ship."},{"type":"heading","level":2,"text":"Frozen Hex Production Correction","id":"velvet-hex-character-variant-and-cast-production-reference-frozen-hex-production-correction"},{"type":"p","text":"Frozen Hex uses the same complete six-frame sheet and clean transparent/light presentation as approved Classic, Scarlet, Beach, Toxic, Royal, and Arcade sheets. Dark atmospheric backgrounds, missing frames, inconsistent pivots, shallow ice coverage, or concept-sheet framing are concept-art errors, not production standards."},{"type":"heading","level":2,"text":"Cast and Entity Role Register","id":"velvet-hex-character-variant-and-cast-production-reference-cast-and-entity-role-register"},{"type":"table","rows":[["Entity family","Role and behavior","Player-facing status"],["Velvet Hex","Brand anchor, playable hero, collection identity, reaction performer, and variant platform across both products.","Canonical / partially implemented through current skins and assets."],["Future named heroes","Distinct silhouettes, personality, lore, reaction trees, exact variants, acquisition source, and equivalent Competitive footprint.","Roster TBD; do not fabricate launch names or promise count."],["Evil Snowman","Harmless cosmetic rare-event creature eligible after a qualifying snow accumulation; appears, performs, and departs/melts.","Candidate environmental entity, not a playable hero unless separately promoted."],["Obsidian Golem","Harmless cosmetic rare-event creature eligible after a qualifying magma/obsidian pool; poses and crumbles.","Candidate environmental entity, not a playable hero unless separately promoted."],["Tiny companions","Slime, ghost, frog, alien, snow creature, fire sprite, bat, cloud, or similar brief followers/reaction performers.","Candidate cosmetic/Infinity content; compatibility and permanence defined per item."],["Ambient animals","Rabbit, squirrel, fish, frog, bird, whale, butterfly, deep-sea creature, and biome wildlife with playful staged reactions.","Infinity living-world content; never visually injured by taps."],["Rare travelers / aliens / spirits","Named or mysterious encounters that may recur across zones/worlds, reveal lore, or unlock earned content.","Candidate discovery content; exact roster and odds open."],["Bots / ghosts","Competitive opponent presentations governed by separate fairness, disclosure, behavior, and rating rules.","Not collectible heroes merely because they use a hero skin."]]},{"type":"p","text":"Every named entity record should include stable entity ID, display name, entity class, role, products, biome/world eligibility, variants, personality tags, animation set, reaction states, audio set, acquisition/discovery policy, rarity, ownership behavior, Journal behavior, accessibility notes, and content version."}]},{"id":"infinity-taps-detailed-world-discovery-and-implementation-reference","number":20,"title":"20. Infinity Taps Detailed World, Discovery, and Implementation Reference","part":"Part III","partName":"Infinity Taps, living worlds, discovery, and heroes","blocks":[{"type":"p","text":"Source basis: Original Expanded Bible pp. 45-79 and 81; TAM Game Design Bible v1.0 Sections 13-16; Game Bible v1.0 Infinity chapters."},{"type":"p","text":"LOCKED Infinity Taps is a no-loss, noncompetitive, local-first tapping, fidget, and exploration product. It is not survival with failure removed. It has no lives, rising survival gravity, health bar, forced timer, PvP pressure, idle punishment, or traditional loss screen."},{"type":"heading","level":2,"text":"Emotional Contract","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-emotional-contract"},{"type":"p","text":"The player opens Infinity to tap, move, regulate attention, watch satisfying reactions, discover a living world, and build permanent identity without being judged. Ordinary taps must feel good even when no achievement, currency, or rare event occurs. Goals enhance curiosity; they must not turn the product into disguised ranked pressure."},{"type":"ul","items":["Every valid tap produces readable motion, sound, haptic, particle, character, or environmental acknowledgement.","The player may stop at any moment and resume without failure, lost progress, or a scolding return flow.","The world is already alive before the player touches it; tapping interrupts, influences, or plays with an existing scene.","Discovery rewards observation, repetition, experimentation, patience, direction, and context.","Some of the shared universe's most interesting cosmetics belong exclusively to noncompetitive exploration."]},{"type":"heading","level":2,"text":"Core Loop","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-core-loop"},{"type":"ol","items":["Resume the last safe biome, zone, and local state.","Tap relative to the hero to move left, right, upward, downward where appropriate, or through an environment-specific movement state.","Increment session and lifetime tap totals after input validation.","Move, squash, stretch, wobble, or otherwise respond immediately.","Trigger the equipped tap effect and character-particle response.","Cause water, plants, terrain, animals, objects, heroes, structures, weather, or hidden triggers to react.","Advance distance, zone, biome, altitude, depth, discovery, encounter, journal, achievement, and reward checks.","Save safely at intervals and when the app backgrounds or exits."]},{"type":"heading","level":2,"text":"Movement Languages","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-movement-languages"},{"type":"table","rows":[["Context","Tap-driven movement","Presentation intention"],["Ground","Hop, bounce, bound, and bias left/right by tap position.","Forgiving and rhythmic; never trap the hero in geometry."],["Mountain / vertical terrain","Climb, rebound, launch from ledges, and use short boosts.","Direction and height feel exploratory, not punishing."],["Water","Swimming bursts; taps can move horizontally, upward, or deeper.","Bubbles, drag, current, and creature reactions replace standard falling."],["Low gravity / space","Long drifting arcs with smaller corrections.","Slow particles, floating accessories, and broad movement paths."],["Velocity boost","Short 10-25 second speed state.","A playful remix of movement, audio, camera, and reaction timing."],["Jet-engine hold","Temporary tap-and-hold sustained thrust.","A deliberate exception to repeated tapping; biome/boost specific."],["Anti-gravity / extra-bouncy","Temporary altered arc and rebound behavior.","No competitive fairness requirement, but always readable and comfortable."]]},{"type":"heading","level":3,"text":"Candidate Infinity Boost Backlog","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-candidate-infinity-boost-backlog"},{"type":"p","text":"CANDIDATE Boosts normally last approximately 10-25 seconds and temporarily remix movement, reaction timing, camera feedback, particles, and one music layer without introducing failure. Exact durations and stacking remain open."},{"type":"table","rows":[["Boost","Movement / interaction change","Audio and safety intent"],["Velocity Increase","Raises horizontal speed and momentum so the hero races through part of a biome.","Faster rhythmic layer; camera remains comfortable and interactions remain reachable."],["Jet Engine","Holding the screen creates continuous upward thrust; a fuel/heat presentation may limit the state.","Rising synth; no overheat failure, damage, or lost progress."],["Anti-Gravity","Reverses the ordinary impulse interpretation so taps push downward instead of upward.","May reverse or invert part of the motif; controls are explicitly taught."],["Extra Bouncy","Greatly increases jump height and ground rebound for absurd launches.","Spring percussion; geometry prevents trapping or camera sickness."],["Heavy Gravity","Creates smaller jumps but more dramatic landings and environmental reactions.","Heavier impact layer; never becomes survival pressure."],["Tap Burst","Every tap emits a short interaction shockwave affecting nearby leaves, water, bushes, and animals.","Clear radius and cooldown; playful reactions only."],["Moon Bounce","Lowers gravity for slow, exaggerated arcs and gentle correction.","Wide, airy music layer; never stalls the player permanently."],["Magnetism","Pulls nearby Infinity-specific collectibles or hidden objects toward the hero.","Does not affect competitive pickups, paid rarity, or exclusive eligibility outside its declared content."]]},{"type":"heading","level":2,"text":"Tap Counting and Hero Coins","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-tap-counting-and-hero-coins"},{"type":"p","text":"CONFIRMED Infinity normally awards one Hero Coin for every 1,000 valid active taps. Hero Coins do not spawn as ordinary Infinity pickups. Preserve the remainder across sessions."},{"type":"ul","items":["Show lifetime taps, current-session taps, and progress toward the next 1,000 threshold distinctly.","Count approved touch/mouse events only while the world is active; menus, overlays, duplicate events, and implausible automation do not count.","Do not hard-limit normal fast fidget tapping; use generous plausibility analysis.","Offline play increments local progress, but trusted currency reconciliation must prevent save editing from minting unlimited server value.","No offline idle accumulation exists: Infinity rewards active tapping, not elapsed time while closed."]},{"type":"heading","level":2,"text":"Zone Rhythm","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-zone-rhythm"},{"type":"p","text":"CONFIRMED A typical zone targets approximately two minutes of ordinary traversal so the player can experience most of its musical arrangement. This is a cadence, never a timer or forced transition."},{"type":"table","rows":[["Working time band","Zone role"],["0:00-0:30","Establish the biome, movement language, music, wildlife, and obvious environmental interactions."],["0:30-1:30","Exploration, collectibles, heroes, secrets, repeated-tap depth, interaction chains, and temporary boosts."],["1:30-2:00","Visually and musically preview/transition toward the next zone while preserving movement and avoiding a hard menu cut."]]},{"type":"heading","level":2,"text":"World and Biome Framework","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-world-and-biome-framework"},{"type":"p","text":"A biome is not a background. It defines movement feel, signature interactions, wildlife, palette, ambience, music instrumentation, secret vocabulary, hero pool, boosts, landmarks, rare encounters, and exclusive rewards."},{"type":"table","rows":[["World layer","Canonical / proposed content"],["Starting Earth surface","Welcoming Meadow/field with grass, flowers, hills, clouds, butterflies, water, bushes, trees, rabbits, and a first hero encounter."],["Surface expansion","Farmland, Forest, Mountain, Desert, Volcanic region, Beach, Crystal Caverns, Neon City, Mushroom Grove, Snow/Arctic, and Antarctic as a distinct polar region."],["Ocean","Surface water, sunlight zone, twilight zone, midnight zone, abyssal zone, and deepest trench with vents, rare wildlife, ancient structures, and exclusive rewards."],["Sky","Birds, balloons, aircraft, storms, rainbows, floating islands, sky heroes, and rare shooting stars."],["Space","Satellites, stations, meteors, comets, asteroids, astronauts, alien ships, signals, moons, and low-gravity travel."],["Other worlds","Mars-like desert, ice, slime, crystal, gas-giant platforms, machine world, low-gravity garden, dark void, candy-colored alien world, and future seasonal worlds."]]},{"type":"p","text":"SCOPE The proposed early eight-biome set (Meadow, Forest, Snow, Beach, Crystal Caverns, Neon City, Mushroom Grove, Space) is a content recommendation, not permission to build eight shallow biomes before the one-biome vertical slice is excellent."},{"type":"heading","level":2,"text":"Living World Interaction Depth","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-living-world-interaction-depth"},{"type":"p","text":"The central question is: 'I wonder what happens if I tap that.' Reactions support multiple thresholds, cooldowns, context conditions, randomized alternatives, and secret combinations. Not every object needs maximum depth at launch, but the data model must support it."},{"type":"table","rows":[["Depth level","Example behavior"],["First tap","Immediate acknowledgement: splash, wiggle, blink, sound, leaf fall, look, or small motion."],["Repeated taps","Escalation: larger response, annoyance, play, movement, transformation, accumulation, or a different animation."],["Context","Time, direction, current biome, equipped effect, owned hero, weather, nearby object, previous discovery, or cooldown changes the result."],["Chain","One reaction affects another object or creature and produces a discoverable sequence."],["Secret / rare","A hidden threshold, unusual order, location, or long-term condition unlocks an encounter, journal entry, or earned item."]]},{"type":"ul","items":["Shake a tree; an acorn falls; a squirrel collects it; following the squirrel reveals a hero.","Splash water; a fish jumps; a frog moves; its lily pad exposes a collectible.","Build a snow pile; cross a threshold; perform one qualified Evil Snowman check.","Accumulate magma; cool it into obsidian; awaken a cosmetic Obsidian Golem; let it crumble harmlessly.","Release flower seeds; let wind carry them; grow a temporary patch elsewhere in the zone."]},{"type":"heading","level":2,"text":"Animals and Hero Reactions","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-animals-and-hero-reactions"},{"type":"p","text":"LOCKED Animal interactions are playful. Tapping never visually injures an animal, creates failure, or turns curiosity into punishment."},{"type":"p","text":"Characters should not replay one reaction forever. A resting hero may open one eye, look around, sit up, become annoyed, throw a pillow, then relocate. An animal may move from curiosity to playfulness to escape. Cooldowns preserve personality and prevent spam."},{"type":"p","text":"When an unowned hero or exact variant appears, the first interaction happens in-world. A compact identification card then shows hero, variant, rarity, ownership, and acquisition method. Only a second deliberate action opens purchase or unlock details. Closing should return to the same encounter where practical. Owned heroes may wave, accompany briefly, reveal lore, friendship, poses, or journal details."},{"type":"heading","level":2,"text":"Discovery Journal","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-discovery-journal"},{"type":"ul","items":["Biomes and worlds visited; zones and landmarks reached.","Animals found and distinct behaviors witnessed, including partial progress such as Rabbit Behaviors: 3 of 7.","Heroes and exact variants encountered, owned, purchased, earned, or still mysterious.","Environmental reactions, interaction chains, rare events, secret locations, and unresolved mysteries.","Highest altitude, greatest depth, lifetime taps, session records, worlds traveled, and special movement states.","Cosmetics found, acquisition source, permanent ownership, and mode-exclusive status."]},{"type":"p","text":"Common entries may show clear requirements. Secret entries may use silhouettes, riddles, partial hints, or remain completely hidden until first discovery. The Journal should encourage observation without reducing every mystery to a checklist."},{"type":"heading","level":2,"text":"Rare Discovery and Pity","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-rare-discovery-and-pity"},{"type":"p","text":"Encounter tiers may include common ambient, uncommon named, rare traveler, biome-exclusive, seasonal, secret, and legendary. Extremely low odds can create wonder, but cannot create plausible years of engagement with no path to success."},{"type":"p","text":"OPEN The original expanded design gives an example check every 100 valid taps with a 0.1% base chance (roughly one success per 100,000 taps before pity). The exact check interval, base odds, pity curve, drought reset, and category-specific protection remain open and must be simulated before launch."},{"type":"ul","items":["Roll on meaningful intervals or threshold crossings, not every rendered particle.","Track eligibility, time/taps since last success, and hidden pity progress.","Increase opportunity after a long qualifying drought without displaying exact secret thresholds.","Use idempotent grants so reconnects and retries cannot duplicate rare ownership.","Store discovery source and condition so the collection can explain how an item was earned."]},{"type":"p","text":"HISTORICAL TEST CANDIDATES The Original Expanded Bible also proposes 0.001% per eligible tap, slowly increasing chance after 50,000 eligible taps, and a guaranteed configured maximum. Another framing rolls once per 100 valid taps. These examples are not mutually approved and must be simulated as competing models, not combined accidentally."},{"type":"p","text":"A sustained rate around 15-20 taps per second is an example integrity-review threshold, not an automatic punishment threshold. Fast fidget players must not be treated as cheaters merely for tapping rapidly; use device/input evidence, duration, variability, menu state, server plausibility, and repeated patterns. Offline Hero Coin and premium/exclusive unlock evidence may remain pending until trusted synchronization completes."},{"type":"heading","level":2,"text":"Infinity-Exclusive Rewards","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-infinity-exclusive-rewards"},{"type":"p","text":"LOCKED Designated Infinity skins, variants, trails, tap effects, particles, frames, badges, titles, and companions cannot be purchased with money, Hero Coins, a pass, a supporter bundle, or an advertisement."},{"type":"table","rows":[["Unlock family","Examples"],["Tap milestones","Lifetime totals, session totals, long fidget sessions, unusual rhythms."],["World discovery","Every starting-field landmark; every Earth biome; all ocean depths; all launch planets."],["Encounter","Hidden forest spirit, named creature, rare hero variant, unusual weather, cosmic visitor."],["Depth / altitude","Deepest trench, volcanic chamber, cloud line, orbit, moon, planet."],["Collection","Every creature/behavior in a biome; complete chain set; Journal completion."],["Conditional secret","Tap a meteor in a specific state; follow an animal chain; combine effects or environmental conditions."]]},{"type":"p","text":"Items display source text such as 'Abyssal Velvet - Reached the deepest trench in Infinity Taps - Cannot be purchased.' They may be wearable in Competitive TAM after being earned, but the competitive shop never sells them."},{"type":"heading","level":3,"text":"Proposed Infinity-Exclusive Seed Catalog","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-proposed-infinity-exclusive-seed-catalog"},{"type":"table","rows":[["Reward","Type","Proposed unlock requirement"],["Meadow Velvet","Skin","Discover every landmark in the starting field."],["Forest Spirit","Trail","Encounter the hidden forest spirit."],["Volcanic","Tap effect","Reach the deepest volcanic chamber."],["Abyssal Velvet","Skin","Reach the deepest ocean trench."],["Bioluminescent","Trail","Discover five deep-sea creatures."],["Moon Dust","Tap effect","Land on the Moon."],["Alien Signal","Effect","Witness a rare alien transmission."],["First Contact","Skin","Encounter an alien character."],["World Traveler","Profile frame","Visit every launch-version biome."],["Endless Ripple","Effect","Reach 100,000 Infinity Taps."],["Million Tap","Aura","Reach 1,000,000 Infinity Taps."],["Cosmic Velvet","Skin","Discover all initial space regions."]]},{"type":"p","text":"PROPOSED / CONFLICT CHECK These are seed concepts, not current catalog commitments. Meadow, Abyssal, and First Contact names conflict with currently purchasable store variants; exclusivity requires distinct IDs/designs or a corrected store/acquisition decision before release."},{"type":"p","text":"On rare-world spawn, save the opportunity immediately, leave enough time to collect it, preserve it across accidental close where feasible, grant permanently, suppress meaningless duplicates, and attach a unique transaction key such as `infinity_unlock:skin_velvet_abyssal`. The store service rejects any price assignment where `purchasable == false`."},{"type":"heading","level":2,"text":"Save and Shared-Account Boundary","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-save-and-shared-account-boundary"},{"type":"ul","items":["Current world, biome, zone/checkpoint, horizontal distance, altitude, depth, highest altitude, and greatest depth.","Lifetime/session taps and remainder toward the next 1,000-tap coin.","Discovered biomes, worlds, heroes, variants, animals, behaviors, landmarks, events, secrets, and cosmetics.","Rare-discovery eligibility, pity, last qualifying check, last successful discovery, and pending grants.","Product source, ruleset/content version, local timestamp, cloud revision, and idempotency IDs."]},{"type":"p","text":"The shared user owns an eligible hero once, but Competitive rating and season state remain Competitive-only; Infinity world and Journal progress remain Infinity-only. Cross-device merge must not blindly choose the larger or newer save when that would duplicate currency or erase discoveries."},{"type":"heading","level":2,"text":"Infinity Vertical-Slice Release Gate","id":"infinity-taps-detailed-world-discovery-and-implementation-reference-infinity-vertical-slice-release-gate"},{"type":"ul","items":["No input, hazard, geometry, boost, or environmental event produces a loss screen.","Directional movement is satisfying with no reward layer enabled.","Water splashes, a bush wiggles, tree leaves fall, and repeated interactions vary.","At least one animal has three distinct interaction stages.","One found hero or variant uses the two-step in-world identification/acquisition flow.","Lifetime taps persist and one Hero Coin is awarded exactly once at 1,000 valid taps."]},{"type":"p","text":"PART 4"},{"type":"p","text":"PROGRESSION, IDENTITY, AND ECONOMY"},{"type":"p","text":"The shared collection ecosystem: currencies, achievements, badges, challenges, cosmetics, tap effects, particles, and ethical monetization."}]},{"id":"progression-currencies-and-reward-economy","number":21,"title":"21. Progression, Currencies, and Reward Economy","part":"Part IV","partName":"Progression, economy, cosmetics, effects, and collection","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Progression Dimensions","id":"progression-currencies-and-reward-economy-1-progression-dimensions"},{"type":"table","rows":[["Dimension","Competitive TAM","Infinity Taps","Shared profile"],["Skill","Glicko rating, tier, wins, survival, records","Not ranked","Best milestones"],["Activity","Matches, valid taps, challenges","Lifetime taps, distance, sessions","Total taps with source detail"],["Discovery","Pickups, event modes, achievements","Biomes, animals, heroes, secrets","Journal and collection summary"],["Collection","Cosmetics, heroes, badges","Exclusive finds, heroes, variants","Owned catalog"],["Season","Ranked climb and season rewards","Seasonal worlds or encounters","Season history"]]},{"type":"heading","level":2,"text":"2 Hero Coin","id":"progression-currencies-and-reward-economy-2-hero-coin"},{"type":"p","text":"Hero Coin is the main cosmetic currency. It can be earned through achievements, competitive rewards, controlled pickups, challenges, seasonal progression, and Infinity's one-per-1,000-valid-taps rule. The currency must not purchase ranked power."},{"type":"heading","level":2,"text":"3 Economy Sources","id":"progression-currencies-and-reward-economy-3-economy-sources"},{"type":"ul","items":["Achievement rewards.","Daily and weekly challenge rewards.","Match completion and limited performance bonuses.","Seasonal ladder milestones.","Golden Hero token pickups under capped rules.","Infinity tap milestones.","Starter purchase and other clearly priced cosmetic bundles."]},{"type":"heading","level":2,"text":"4 Economy Sinks","id":"progression-currencies-and-reward-economy-4-economy-sinks"},{"type":"ul","items":["Heroes and purchasable variants.","Tap effects and color variants.","Character particle effects and trails.","Profile frames, username treatments, badges where not achievement-exclusive, and emotes.","Entrances, victory poses, landing effects, arena themes, and presentation items."]},{"type":"heading","level":2,"text":"5 Economy Guardrails","id":"progression-currencies-and-reward-economy-5-economy-guardrails"},{"type":"ul","items":["No direct purchase of rating, survival force, tap validity, movement speed, damage, life, regeneration, pickup priority, or matchmaking advantage.","Do not make basic visual readability a paid feature.","Infinity-exclusive earnables remain unavailable for purchase.","Seasonal exclusivity should be disclosed before purchase and not falsely returned as identical content later.","Currency pricing must be understandable; avoid manipulative multi-currency conversion chains."]},{"type":"heading","level":2,"text":"6 Long-Term Collection","id":"progression-currencies-and-reward-economy-6-long-term-collection"},{"type":"p","text":"The collection should show how an item was obtained: shop, achievement, season, ranked reward, Infinity discovery, secret, or supporter bundle. Source labeling strengthens prestige and helps players understand what remains possible."}]},{"id":"achievements-badges-and-challenges","number":22,"title":"22. Achievements, Badges, and Challenges","part":"Part IV","partName":"Progression, economy, cosmetics, effects, and collection","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"p","text":"CONFIRMED Achievements are permanent long-term goals. Daily and weekly challenges rotate. Badges are permanent profile collectibles."},{"type":"heading","level":2,"text":"1 Profile Display Rules","id":"achievements-badges-and-challenges-1-profile-display-rules"},{"type":"ul","items":["One primary badge appears beside the username and in prominent competitive presentation.","Up to three additional showcase badges appear on the full profile.","Tiered achievement families display the highest earned tier by default.","Earlier tiers remain in collection history.","Server validation must ensure a loadout can display only badges the user actually earned."]},{"type":"heading","level":2,"text":"2 Achievement Categories","id":"achievements-badges-and-challenges-2-achievement-categories"},{"type":"table","rows":[["Category","Purpose","Examples discussed"],["Fruit","Reward pickup behavior, risk, and unusual poison outcomes.","Life of Poisonous Fruit, Fruit Salad, Toxic Appetite, Poison-Proof, Apple a Day"],["Survival","Reward duration, control, recovery, and repeated runs.","First Flight, Learning to Fly, Gravity Defier, Sky Eternal, Close Call"],["Coins and Shop","Reward earning, spending, and cosmetic collection.","Coin Collector, Golden Hoard, Token Hunter, Big Spender, Shop Regular, Fully Dressed"],["Multiplayer","Reward first wins, sustained competition, and opponent variety.","First Victory and additional catalog entries"],["Progression","Reward onboarding and long-term milestones.","Getting Started and tiered milestone families"],["Secret","Reward experimentation and unexpected behavior.","Was That Worth It?, Floor Inspector, Maximum Poison, Perfectly Balanced, Velvet's Nine Lives, Too Greedy"],["Infinity Exploration","Reward travel, depth, space, behaviors, and discoveries.","World Traveler, Into the Clouds, Beyond the Sky, One Small Tap, Going Deep, At the Bottom, First Contact"],["Seasonal","Provide time-bound goals without removing permanent progress.","Season participation, rank, world-event, and collection achievements"]]},{"type":"heading","level":2,"text":"3 Current Implementation Note","id":"achievements-badges-and-challenges-3-current-implementation-note"},{"type":"p","text":"CONFIRMED The deployed backend health response reports 55 achievement definitions."},{"type":"p","text":"The design discussion preserved many exact names but not every threshold and reward. Engineering should export the authoritative achievement catalog from shared/achievements.js and reconcile it against this bible before content lock. The count of 55 should not be treated as a permanent ceiling."},{"type":"heading","level":2,"text":"4 Tiering","id":"achievements-badges-and-challenges-4-tiering"},{"type":"p","text":"Achievement families may use Bronze, Silver, Gold, and Mythic or equivalent tiers. Thresholds should reflect real behavior distributions. A tier should never require a paid item unless a free acquisition path exists and the achievement is explicitly about collection rather than competitive skill."},{"type":"heading","level":2,"text":"5 Challenge Structure","id":"achievements-badges-and-challenges-5-challenge-structure"},{"type":"ul","items":["Daily challenges should be short, varied, and completable without extreme luck.","Weekly challenges may span multiple modes or encourage deeper goals.","Infinity challenges should avoid forcing competitive play; competitive challenges should not require Infinity-exclusive content.","Challenges may award Hero Coins, progress, profile items, or limited cosmetics.","Secret achievements should not appear as explicit checklist chores before discovery."]},{"type":"heading","level":2,"text":"6 Reward Philosophy","id":"achievements-badges-and-challenges-6-reward-philosophy"},{"type":"p","text":"Achievements should reward behavior, mastery, experimentation, and identity. The strongest rewards are not merely currency; they are badges, effects, skins, encounters, profile treatments, and stories the player can associate with a specific accomplishment."}]},{"id":"cosmetics-tap-effects-and-character-particles","number":23,"title":"23. Cosmetics, Tap Effects, and Character Particles","part":"Part IV","partName":"Progression, economy, cosmetics, effects, and collection","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Cosmetic Categories","id":"cosmetics-tap-effects-and-character-particles-1-cosmetic-categories"},{"type":"ul","items":["Hero skins and variants.","Character particle effects and auras.","Tap effects.","Movement trails, water trails, and space trails.","Spawn, entrance, landing, elimination, and victory animations.","Arena and background themes.","Fruit skins and pickup presentation.","Profile frames, badges, username colors, titles, and emotes.","Ambient sound themes and idle animations.","Companion creatures or pets where they do not clutter competitive readability."]},{"type":"heading","level":2,"text":"2 Established Tap Effects","id":"cosmetics-tap-effects-and-character-particles-2-established-tap-effects"},{"type":"table","rows":[["Effect","Behavior","Price / unlock note"],["Pulsing Rings","Expanding rings at the tap point. Basic purple; custom color picker; RGB-changing variant.","Purple: 100 Hero Coins. Additional custom colors: 50. RGB: 300."],["Rainstorm","Rain falls around the tap. Extremely rare lightning can strike and temporarily scorch the ground.","200 Hero Coins. Historical lightning chance: 0.001%."],["Snowfall","Snow falls and piles temporarily before melting. Qualified piles can produce an evil snowman.","200 Hero Coins. Rare event after pile threshold."],["Magma / Lava","Lava or magma pools form and cool; qualified buildup may produce an obsidian golem.","Working price: 200 Hero Coins."],["Fire","Flame response at the tap point with possible color or theme variants.","Base concept: 75 Hero Coins; variants may include purple, blue, ghost, pixel, or golden fire."],["Autumn Leaves","Leaves fall and collect; a sufficient pile can burst or trigger a larger response.","Working price: 200 Hero Coins."]]},{"type":"heading","level":2,"text":"3 Suggested Tap Effect Catalog","id":"cosmetics-tap-effects-and-character-particles-3-suggested-tap-effect-catalog"},{"type":"p","text":"These are idea-bank candidates rather than launch requirements."},{"type":"ul","items":["Bubble Pop; Pixel Lightning; Starfall; Galaxy Portal; Ghost Hands; Slime Splash; Ink Blot; Paint Burst.","Flower Bloom; Mushroom Growth; Crystal Growth; Mini Earthquake; Water Splash; Ocean Wave; Sand Burst.","Candy Explosion; Confetti Cannon; Musical Notes; Retro Arcade Hit; Glitch Effect; Shadow Creatures.","Tiny Footprints; Magic Runes; Black Hole; Cloud Puff."]},{"type":"heading","level":2,"text":"4 Character Particle Concepts","id":"cosmetics-tap-effects-and-character-particles-4-character-particle-concepts"},{"type":"ul","items":["Purple smoke.","Golden sparkles.","Slime droplets.","Pixel stars.","Poison bubbles.","Tiny ghosts.","Lightning pixels.","Falling flower petals."]},{"type":"heading","level":2,"text":"5 Effect Design Rules","id":"cosmetics-tap-effects-and-character-particles-5-effect-design-rules"},{"type":"ul","items":["Tap effects respond to the tap location; character particles remain attached to the hero.","Rare events should be delightful but not required for basic progression.","Competitive effects must not obscure the ground, opponent, pickups, or collision boundaries.","Persistent effects should have strict object limits and cleanup rules.","Color customization must maintain contrast and avoid flashing hazards.","Effect combinations should be previewable before purchase or equip."]},{"type":"heading","level":2,"text":"6 Infinity Exclusives","id":"cosmetics-tap-effects-and-character-particles-6-infinity-exclusives"},{"type":"p","text":"CONFIRMED Effects, skins, trails, variants, badges, frames, colors, companions, emotes, idle animations, and other rewards designated as Infinity-earned cannot be purchased."},{"type":"p","text":"Examples discussed include Meadow Velvet Skin, Forest Spirit Trail, volcanic-themed rewards, water trails, space trails, and hidden variants. Exact final names should be locked during content production."}]},{"id":"expanded-tap-effects-and-character-particle-catalog","number":24,"title":"24. Expanded Tap Effects and Character Particle Catalog","part":"Part IV","partName":"Progression, economy, cosmetics, effects, and collection","blocks":[{"type":"p","text":"Source basis: Original Expanded Bible pp. 5-44; TAM Game Design Bible cosmetic catalog; current store catalog for shipped effects."},{"type":"heading","level":2,"text":"Cosmetic System Boundary","id":"expanded-tap-effects-and-character-particle-catalog-cosmetic-system-boundary"},{"type":"p","text":"Tap effects appear at the valid tap location. Character particles attach to and follow the hero. Trails, idle components, jump/fall/landing bursts, environment variants, and elimination presentation may be packaged within one character-particle slot. Every component is cosmetic."},{"type":"ul","items":["Never alter jump force, gravity, movement speed, collision, pickup range, spawn probabilities, score, rating, coin earnings, or rare-discovery odds.","The local player may see full intensity; other players receive a reduced, readable version or may disable remote cosmetics.","Provide density, opacity, flash, screen-shake, sound, haptic, and other-player effect controls.","Pool repeated objects, cap particles and accumulation zones, shorten lifetimes, merge nearby zones, and degrade gracefully on low-tier devices.","A rare creature or environmental event creates delight, never power, currency, damage, path blocking, or a hidden competitive signal."]},{"type":"heading","level":2,"text":"Established Environmental Tap Effects","id":"expanded-tap-effects-and-character-particle-catalog-established-environmental-tap-effects"},{"type":"table","rows":[["Effect","Suggested price","Detailed behavior"],["Pulsing Rings","100 base; 50 per custom color; 300 RGB","Expanding fade ring. Custom hue/saturation/brightness/RGB/darkness/opacity. RGB modes: Random, Smooth Rainbow, Custom Palette. Avoid flashing."],["Rain","200","Localized shower. Rare 0.001% weather-lightning concept creates controlled flash, thunder, temporary scorch, smoke, and reactions without damage."],["Snow","200","Temporary dusting/pile stages. Repeated taps accumulate; capped pile melts. One qualifying threshold check may produce a harmless Evil Snowman."],["Magma","200","Splash, puddle, pool, cooling, and obsidian stages. One qualifying threshold check may produce an Obsidian Golem that poses then crumbles."],["Fire","75","Affordable quick flame, sparks, embers, and smoke; repeated taps may grow a capped temporary flame."],["Autumn Leaves","200","Color/shape/rotation variety, temporary piles, and a landing/movement burst that never changes real movement."]]},{"type":"heading","level":2,"text":"Additional Tap Effect Backlog","id":"expanded-tap-effects-and-character-particle-catalog-additional-tap-effect-backlog"},{"type":"p","text":"The following catalog is candidate content, not a launch commitment. Approximately one-third of effects should have accumulation or rare-event depth; if every effect summons something, discovery loses meaning."},{"type":"table","rows":[["Effect","Coins","Immediate response","Deeper behavior"],["Bubble Pop","100","Translucent bubbles float and can be tapped again to pop.","Rare giant bubble may briefly carry the hero cosmetically."],["Pixel Lightning","175","Arcade electrical bolt chains to nearby surfaces; repeated taps build static.","Maximum charge creates a chain and may reveal a tiny electric creature; visually distinct from weather lightning."],["Starfall","200","A falling star strikes the tap point and leaves a temporary glow.","Consecutive taps form constellations; completed patterns may trigger a cosmetic event."],["Galaxy Portal","250","A small cosmic portal opens, spirals particles inward, and closes.","Rare alien hand, eye, or creature may peer through."],["Ghost Hands","175","Translucent hands or paws wave, clap, point, or grab harmlessly.","Nearby taps can summon a temporary ghost audience."],["Slime Splash","150","Colored slime splashes and temporarily sticks to surfaces.","Repeated taps grow a puddle; landing creates only a visual bounce; rare tiny slime may emerge."],["Ink Blot","125","Random ink shapes spread, drip, and fade.","Rare forms resemble faces, creatures, or symbols."],["Paint Burst","100 / 200 / 300","Single-color, custom-palette, or rainbow paint temporarily coats the environment.","Multiple taps paint a larger temporary area; color always fades."],["Flower Bloom","200","Flowers grow rapidly at the tap point and build a temporary garden.","Butterflies or a rare giant strange flower may appear."],["Mushroom Growth","200","Mushrooms vary in size, color, and shape; clusters release spores.","Rare mushroom creature wakes and walks away."],["Crystal Growth","225","Crystals rise, grow with repeated taps, shimmer, then dissolve.","Rare crystal guardian or tiny crystal animal may appear."],["Mini Earthquake","175","A cosmetic crack, dust, and stones expand with repeated taps.","Harmless rock creature may peek out; screen shake is optional and off by default."],["Water Splash","150","Droplets splash and form temporary puddles with reflections.","Landing splashes; rare frog or water creature may appear."],["Ocean Wave","225","A wave and foam sweep outward; consecutive taps make it slightly larger.","Tiny boat, fish, or message bottle may ride a rare wave."],["Sand Burst","175","Sand erupts and forms temporary piles the hero can visually scatter.","Scarab, buried object, or miniature sand creature may emerge."],["Candy Explosion","200","Wrapped candy, gumdrops, jellybeans, and lollipops bounce and fade.","Rare candy monster or pinata-like creature may appear."],["Confetti Cannon","100","Themeable confetti creates a performance-friendly celebration.","Sustained tapping builds a larger but capped burst."],["Musical Notes","150 per sound set","Tap position changes pitch; notes pair with piano, chiptune, bells, drums, or slime-pop sets.","Fast tapping can create simple melodies; strong fit for fidget play."],["Retro Arcade Hit","125","Localized POW/TAP text, pixel stars, score-like numbers, CRT touches, and comic bursts.","Premium variant may randomize retro words and symbols; numbers never represent real score."],["Glitch Effect","250","Localized pixel fragmentation and RGB separation distort the tapped area.","Repeated taps create temporary corruption; rare glitch character may appear; never distort the whole screen."],["Shadow Creatures","225","Small shadows crawl, wave, run, or hide.","Several taps form a group; rare one becomes a named encounter."],["Tiny Footprints","75 each / 250 bundle","Cat, demon, slime, bird, dinosaur, or alien prints form a temporary trail.","Prints remain cosmetic and fade."],["Magic Runes","225","Runes rotate and fade; nearby runes can connect into a magic circle.","Completed circle may summon a harmless creature or portal."],["Black Hole","300","A small void pulls cosmetic particles inward and closes quickly.","Repeated taps strengthen visual pull; strange object may be expelled; never affect gameplay objects."],["Cloud Puff","125","Small clouds drift and can form larger temporary groups.","Rare face, animal shape, or tiny storm cloud may form."],["Fireworks","200 / 250 / 350","Delayed fireworks use basic, custom-color, or shape-bundle variants.","Repeated taps coordinate a display; avoid flashes that compromise comfort."],["Miniature Meteor","225","A small meteor creates a temporary crater and smoke.","Repeated taps create a shower; rare alien object or creature may emerge."],["Hearts and Affection","75","Pixel, gothic, broken, slime, or rainbow hearts float upward.","Nearby characters may react positively."],["Bat Swarm","175","Tiny bats scatter from the tap point and build a larger capped swarm.","Rare named bat companion may appear briefly."],["Tiny Companion Reaction","250-400","A tiny slime, ghost, frog, alien, snow creature, or fire sprite performs one quick animation.","Premium complexity depends on character animation and context support."]]},{"type":"table","rows":[["Price band","Content expectation"],["75-100","Simple, immediate, affordable effect."],["125-175","Additional movement, variation, theme, or modest interaction."],["200-250","Accumulation, environment memory, chain, or rare-event eligibility."],["300-400","Highly customizable, complete, or elaborate premium expression."]]},{"type":"p","text":"First-priority candidates because they are distinct without excessive production cost: Bubble Pop, Slime Splash, Musical Notes, Flower Bloom, Retro Arcade Hit, Magic Runes, Galaxy Portal, Tiny Footprints, Confetti Cannon, and Glitch Effect."},{"type":"heading","level":2,"text":"Character Particle Seed Catalog","id":"expanded-tap-effects-and-character-particle-catalog-character-particle-seed-catalog"},{"type":"table","rows":[["Effect","Coins","Components / environment behavior"],["Purple Slime Droplets","100","Stretching droplets; ground splatter; underwater slime bubbles."],["Shadow Smoke","150","Dark curling trail with purple highlights and idle wisps."],["Golden Sparkles","150","Gold stars, jump burst, and apex linger."],["Poison Bubbles","125","Purple/green bubbles with occasional skull symbols."],["Pixel Stars","100","Blocky 1990s arcade palette and jump starburst."],["Fire Trail","175","Flames and embers intensify in fast falls; underwater becomes steam or reduced flame."],["Blue Ghost Fire","200","Harmless spirit flames orbit and trail."],["Snowflake Trail","150","Snow density reacts to speed; frost idle; snow landing puff."],["Autumn Leaf Trail","150","Multi-color rotating leaves and landing burst."],["Flower Petals","150 per theme","Cherry, rose, sunflower, or fantasy petals with slow drift."],["Bubble Trail","125","Upward bubbles, underwater density, and direction-change pops."],["Ocean Foam","150","Land splash becomes underwater bubble stream."],["Lightning Static","200","Speed-reactive sparks and jump bolt; no full-screen flashes."],["Rainbow Trail","300","Short smooth, pastel, or retro spectrum with strict fade."],["RGB Pixel Trail","300","Random, cycling, or custom-palette arcade pixels."],["Glitch Fragments","250","Localized pixel breakup and RGB separation."],["Cosmic Dust","250","Stars, tiny planets, cosmic dust, and idle orbit."],["Mini Comets","225","Short-tailed comets; denser during fast falls."],["Black Hole Orbit","300","Tiny cosmetic particles orbit and absorb into a small void."],["Tiny Bats","200","Brief followers scatter; idle bat may hang nearby."],["Ghost Companions","250","Tiny expressive ghosts wave, circle, or dissolve."],["Tiny Slimes","250","Short-lived bouncing creatures that may match the skin."],["Cat Paw Prints","100","Surface prints or translucent aerial paw symbols."],["Demon Footprints","125","Purple burning marks with horn/tail motifs."],["Hearts","75-125","Standard, gothic, pixel, broken, or rainbow hearts."],["Musical Notes","150","Notes trail and may pulse with tap sounds."],["Confetti","125","Speed-reactive bursts under strict particle limits."],["Candy Trail","175","Bouncing sweets that fade quickly."],["Crystal Shards","175","Color variants sparkle and dissolve."],["Mushroom Spores","175","Soft glow and occasional tiny mushroom icons."],["Fireflies","175","Independent orbiting lights, especially strong at idle."],["Cloud Trail","150","Cartoon puffs with rare recognizable shapes."],["Rain Cloud Companion","250","Delayed-follow cloud with cosmetic non-accumulating rain."],["Halo Light","225","Soft rays and a brief apex halo."],["Dark Aura","200","Purple-black aura with rising particles; never hides the hero."],["Crown Sparkles","250 / earned","Prestige crown and gold particles."],["Retro Score Numbers","150","Cosmetic +10, TAP!, NICE!, WOW! text with no score meaning."],["CRT Afterimage","225","Cyan/magenta/purple arcade afterimages."],["Matrix Code","200","Abstract fictional symbols, not readable messages."],["Floating Runes","225","Orbiting symbols briefly connect on jump."],["Moon Dust","125","Gray/purple trail and broad landing puff."],["Alien Spores","200","Green/purple particles with occasional eye shapes."]]},{"type":"heading","level":2,"text":"Premium Complete Sets","id":"expanded-tap-effects-and-character-particle-catalog-premium-complete-sets"},{"type":"table","rows":[["Set","Suggested price","Included package"],["Velvet Hex Shadow","400","Purple slime movement, shadow-smoke idle aura, purple rune jump burst, slime landing splash."],["Cosmic Traveler","500","Cosmic dust, idle orbiting stars, comet jump burst, miniature black-hole landing effect."],["Frozen Spirit","400","Snowflake trail, frost aura, ice-crystal jump burst, snow landing puff."],["Infernal","400","Fire trail, ember aura, flame jump burst, magma landing splash."],["Retro Arcade","500","RGB pixels, CRT afterimage, pixel-star jump burst, TAP! landing text."]]},{"type":"p","text":"A complete set still occupies one character-particle slot. Seasonal particle families may include Halloween, Winter, Spring, Summer, Space, Arcade, Volcano, and Ocean; earned seasonal effects remain permanently owned after the season."}]},{"id":"tap-effect-and-character-particle-engineering-handoff","number":25,"title":"25. Tap Effect and Character Particle Engineering Handoff","part":"Part IV","partName":"Progression, economy, cosmetics, effects, and collection","blocks":[{"type":"p","text":"Source basis: Original Expanded Bible pp. 6-17 and 40-44; current store/equipment evidence. Expands the preceding cosmetic chapters without promoting example values to locked balance."},{"type":"heading","level":2,"text":"Data-Driven Tap Effect Definition","id":"tap-effect-and-character-particle-engineering-handoff-data-driven-tap-effect-definition"},{"type":"table","rows":[["Field","Purpose / example"],["id / display_name","Stable semantic ID such as tap_effect_rain plus localizable player-facing name."],["price / acquisition","Hero Coin price or earned-only source; mutually consistent with purchasable/exclusive fields."],["effect_scene","Scene/resource path for the immediate tap response."],["supports_custom_color","Whether approved hue/palette controls are exposed."],["supports_accumulation","Whether temporary terrain zones remember deposits."],["rare_event_id / chance","Optional rare-event eligibility. Historical rain example 0.00001 = 0.001%; tune and simulate."],["max_active_instances","Per-effect cap; historical starting example 8."],["duration_seconds","Lifetime before clean removal; historical starting example 4.0 seconds."],["quality / accessibility","Full/reduced/minimal/off resources plus flash, shake, sound, haptic, opacity, and remote-player behavior."],["enabled / version","Safe content switch, definition version, and migration/rollback identity."]]},{"type":"heading","level":2,"text":"Manager and Event Architecture","id":"tap-effect-and-character-particle-engineering-handoff-manager-and-event-architecture"},{"type":"table","rows":[["Component","Responsibility"],["TapEffectManager","Listen for valid `tap_registered(screen_position, world_position)`, resolve the equipped definition, spawn presentation, apply environment variant, request rare eligibility, and enforce caps."],["TapEffectDefinition","Own data and resource references; gameplay scripts never branch on every cosmetic ID."],["TapEffectInstance","One pooled visual instance with lifetime, quality, and cleanup behavior."],["TemporaryEnvironmentManager","Track bounded snow/magma/leaf/water/paint/etc. accumulation zones rather than permanent per-particle objects."],["RareEffectManager","Evaluate one qualified threshold/check, persist state, issue harmless presentation, and route permanent grants idempotently."],["CosmeticLoadoutManager","Validate ownership, compatibility, product eligibility, and one equipped item per slot."],["CharacterParticleManager","Compose trail, idle, jump, fall, landing, aura, and environment variants from movement signals."],["ParticleObjectPool","Reuse emitters, decals, followers, and temporary creatures without allocation spikes."],["PerformanceSettings","Apply device tier, local/remote density, accessibility overrides, and degradation order."]]},{"type":"p","text":"Required general movement signals include `character_jump_started`, `character_falling_started`, `character_landed`, `character_idle_started`, and `character_movement_changed(velocity)`. Movement code emits state; it never references a particular cosmetic ID."},{"type":"heading","level":2,"text":"Temporary Accumulation Zones","id":"tap-effect-and-character-particle-engineering-handoff-temporary-accumulation-zones"},{"type":"p","text":"Snow, magma/lava, leaves, paint, water, sand, flowers, mushrooms, crystals, and similar effects must not leave one permanent physics object per particle. Instead, record bounded terrain zones and update a small number of staged visuals."},{"type":"table","rows":[["Zone field","Meaning"],["zone_id / effect_type","Stable location bucket and material family."],["current_amount / maximum_amount","Clamped accumulation state."],["last_updated_time","Fade, melt, cooling, cleanup, and merge decisions."],["current_visual_stage","Empty, trace, pile/pool, large, cooling/melting, or effect-specific stage."],["rare_spawn_checked","Prevents a roll for every particle and repeated rolls in one qualified pile."],["source/effect owner","Supports local/remote presentation limits and cleanup without granting power."]]},{"type":"p","text":"CANDIDATE THRESHOLD Historical design checks Evil Snowman or Obsidian Golem once when a qualifying snow pile or magma pool reaches 75% capacity, using an example 3-5% chance. A failed check becomes eligible again only after the old zone fully melts/disappears and a new qualified zone forms. These are tuning candidates, not locked probabilities."},{"type":"heading","level":2,"text":"Particle Loadout, Anchors, and Compatibility","id":"tap-effect-and-character-particle-engineering-handoff-particle-loadout-anchors-and-compatibility"},{"type":"p","text":"Conceptual loadout fields: `character_id`, `skin_id`, `particle_effect_id`, `tap_effect_id`, and `primary_badge_id`. Add acquisition source, content version, product eligibility, and entitlement revision in durable records."},{"type":"table","rows":[["Anchor","Typical attachment"],["ParticleAnchorCenter","Auras and centered orbiting components."],["ParticleAnchorBack","Trails and backward-moving emission."],["ParticleAnchorFeet","Landing bursts, ground contact, prints, and impact decals."],["ParticleAnchorHead","Crowns, halos, clouds, and head-follow components."],["ParticleAnchorTail","Tail-specific sparks, ribbons, and character-aware effects."]]},{"type":"p","text":"Character-specific effects declare compatible hero/skin IDs in shop copy; universal effects declare universal behavior. The preview must exercise horizontal movement, jump, fall, idle, landing, and full/reduced quality before purchase or equip."},{"type":"heading","level":2,"text":"Quality, Multiplayer, and Performance","id":"tap-effect-and-character-particle-engineering-handoff-quality-multiplayer-and-performance"},{"type":"table","rows":[["Quality","Required behavior"],["Full","Complete trail, idle, orbiting, jump/fall, landing, environment variation, and approved secondary particles."],["Reduced","Lower emission, shorter trail, fewer orbiters, simplified landing, and no secondary particles."],["Minimal","One basic trail or immediate tap response; no idle aura or environment variation."],["Off","Cosmetic particles/effects suppressed where permitted; gameplay cues remain independently visible."]]},{"type":"ul","items":["Prefer GPUParticles2D where supported; provide CPUParticles2D or a simplified fallback.","Pool repeating objects, cap particle count/emission/decals/zones/temporary creatures, merge nearby zones, and stop unnecessary off-screen work.","Local player may see full presentation. Remote players use reduced count, shorter lifetime, no persistent large objects, no screen distortion, and no cosmetic audio unless enabled.","Expose Other Player Particles: Full | Reduced | Off, while preserving mandatory gameplay signals independently.","Rare events remain eligible at lower quality but render with a lightweight presentation; a setting cannot change rare odds or ownership eligibility."]},{"type":"heading","level":2,"text":"Recommended First Twelve Character Particles","id":"tap-effect-and-character-particle-engineering-handoff-recommended-first-twelve-character-particles"},{"type":"table","rows":[["Priority","Effect","Reason in initial mix"],["1","Purple Slime Droplets","Brand-aligned affordable identity."],["2","Shadow Smoke","Velvet Hex thematic trail/idle language."],["3","Golden Sparkles","Prestige and collection readability."],["4","Pixel Stars","Low-cost arcade/retro identity."],["5","Fire Trail","Strong movement-state treatment."],["6","Snowflake Trail","Seasonal/environment-aware treatment."],["7","Bubble Trail","Water-friendly playful motion."],["8","Autumn Leaves","Seasonal landing/movement variation."],["9","Tiny Bats","Characterful follower particles."],["10","Rainbow Trail","Premium spectrum expression."],["11","Glitch Fragments","Premium arcade/corrupted identity."],["12","Cosmic Dust","Premium space/world expansion identity."]]},{"type":"p","text":"PART 5"},{"type":"p","text":"AUDIO, INTERFACE, AND PLAYER PRESENTATION"},{"type":"p","text":"The sensory and navigational layer that makes every tap legible, satisfying, accessible, and expressive."}]},{"id":"music-sound-and-adaptive-audio","number":26,"title":"26. Music, Sound, and Adaptive Audio","part":"Part V","partName":"Music, sound, interface, onboarding, and profiles","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Shared Musical Identity","id":"music-sound-and-adaptive-audio-1-shared-musical-identity"},{"type":"p","text":"The TAM audio identity should be playful, energetic, slightly mischievous, and endlessly replayable. The core palette combines bright electronic percussion, bouncy synth bass, plucked marimba, kalimba or pizzicato-like melody, soft arcade tones, and organic accents such as claps, snaps, wood knocks, bells, whistles, and ambience."},{"type":"heading","level":2,"text":"2 Main Menu","id":"music-sound-and-adaptive-audio-2-main-menu"},{"type":"p","text":"The main menu should present a calmer, cleaner version of the TAM identity: upbeat, welcoming, lightly mischievous, and simple enough to support login, profile, shop, and mode selection without fatigue."},{"type":"heading","level":2,"text":"3 Competitive / Solo Run Music","id":"music-sound-and-adaptive-audio-3-competitive-solo-run-music"},{"type":"p","text":"Competitive and solo survival music should be faster, sharper, more focused, and rhythmically driving. Use punchy electronic percussion, a driving synth bass, quick plucked melodies, soft arcade tones, and short organic accents. Intensity may build as survival time increases or a match becomes close, but the track must not obscure tap timing or sound cues."},{"type":"heading","level":2,"text":"4 Infinity Taps Music","id":"music-sound-and-adaptive-audio-4-infinity-taps-music"},{"type":"p","text":"CONFIRMED Infinity Taps should use biome-specific music while preserving a shared core motif."},{"type":"p","text":"A practical adaptive structure uses one recognizable theme plus biome layers. Forest may introduce wood, birds, and softer percussion; snow may use bells and airy textures; beach may add water and light hand percussion; desert may add dry shakers and sparse plucks; space may thin the rhythm and widen the ambience."},{"type":"heading","level":2,"text":"5 Zone-Based Music","id":"music-sound-and-adaptive-audio-5-zone-based-music"},{"type":"p","text":"The approximately two-minute zone length allows the player to hear most of a track or arrangement. Music should establish the biome, expand during exploration, and transition during the final portion. Crossfades and synchronized stems are preferable to abrupt restarts."},{"type":"heading","level":2,"text":"6 Interactive Sound","id":"music-sound-and-adaptive-audio-6-interactive-sound"},{"type":"ul","items":["Water taps produce splash size and pitch variation.","Bushes, leaves, wood, stone, snow, sand, mud, and metal use distinct tactile sound families.","Animals have layered first-tap, repeated-tap, and rare-event sounds.","Heroes have identity stingers or short reactive motifs.","Rare effects such as lightning, snowman emergence, golem awakening, or alien contact receive memorable one-shot cues.","Tap audio should use variation pools to avoid machine-gun repetition."]},{"type":"heading","level":2,"text":"7 Current Asset Footprint and Compression","id":"music-sound-and-adaptive-audio-7-current-asset-footprint-and-compression"},{"type":"p","text":"CONFIRMED Eight songs currently total approximately 27 MB."},{"type":"table","rows":[["Instruction","Developer direction"],["Preserve masters","Keep original WAV or FLAC masters outside the shipped build."],["Primary export","Use Ogg Opus, stereo, 48 kHz, VBR. Default around 96 kbps."],["Bitrate by track","Calm tracks: approximately 80-96 kbps. Energetic tracks: approximately 96-112 kbps."],["Fallback","Use Ogg Vorbis quality 4-5 if the engine or loop workflow does not support Opus reliably."],["Memory behavior","Stream long tracks or keep compressed in memory; do not decompress every full song on load."],["Loop quality","Preserve exact loop points, trim unnecessary silence, and test gapless transitions on device."],["Avoid","Do not repeatedly re-encode, drop to 22.05 kHz, or force mono merely to save a small amount."],["Target","Reduce the current 27 MB music set to roughly 10-15 MB without noticeable in-game quality loss."]]},{"type":"heading","level":2,"text":"8 Audio Accessibility","id":"music-sound-and-adaptive-audio-8-audio-accessibility"},{"type":"ul","items":["Independent music, sound-effect, ambience, and interface volume controls.","Visual substitutes for important competitive audio cues.","Reduced-intensity option for sharp or startling rare-event sounds.","No gameplay advantage from listening at high volume."]}]},{"id":"interface-onboarding-profiles-and-social-presentation","number":27,"title":"27. Interface, Onboarding, Profiles, and Social Presentation","part":"Part V","partName":"Music, sound, interface, onboarding, and profiles","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Competitive Onboarding","id":"interface-onboarding-profiles-and-social-presentation-1-competitive-onboarding"},{"type":"ol","items":["Brand intro and account or guest entry.","A short interactive lesson: tap to rise, stop tapping to fall, avoid the ground.","Introduce Green Apple and Purple Fruit only after the player understands flight.","Complete a solo run and establish an initial performance profile.","Present private play, public matchmaking, profile, achievements, shop, and settings."]},{"type":"heading","level":2,"text":"2 Infinity Onboarding","id":"interface-onboarding-profiles-and-social-presentation-2-infinity-onboarding"},{"type":"ol","items":["Place the hero in a small living environment immediately.","Prompt one tap near the hero, one tap on water, and one tap on an animal or plant.","Show the lifetime tap counter and next Hero Coin threshold.","Reveal the journal only after the player triggers a first discovery.","Avoid presenting failure language, ranked systems, or a dense objective list."]},{"type":"heading","level":2,"text":"3 Main Navigation","id":"interface-onboarding-profiles-and-social-presentation-3-main-navigation"},{"type":"ul","items":["Play / Solo / Competitive or equivalent product-specific entry.","Heroes and Collection.","Inventory / Loadout.","Shop.","Achievements and Challenges.","Profile.","Journal in Infinity Taps.","Settings, accessibility, account, terms, and support."]},{"type":"p","text":"LEGACY Earlier UI planning also referenced Explore, Wiki, landing page, guest play, and 404/fallback screens. These remain useful product surfaces, but exact navigation should follow the separate-title architecture."},{"type":"heading","level":2,"text":"4 Profile","id":"interface-onboarding-profiles-and-social-presentation-4-profile"},{"type":"ul","items":["Display name, primary badge, up to three showcase badges, profile frame, and equipped hero.","Competitive statistics: rating, tier, season best, wins, survival records, and recent form.","Infinity statistics: lifetime taps, distance, biomes, behaviors, heroes encountered, and rare discoveries.","Collection provenance: earned in Infinity, ranked reward, season, achievement, shop, or supporter bundle.","Privacy controls for recent matches, detailed statistics, and social discovery."]},{"type":"heading","level":2,"text":"5 Match Presentation","id":"interface-onboarding-profiles-and-social-presentation-5-match-presentation"},{"type":"p","text":"Player introductions, match results, leaderboards, and opponent cards should use badges, frames, hero variants, entrances, and titles to create identity. Presentation must remain brief enough to support rapid rematches."},{"type":"heading","level":2,"text":"6 Purchase Presentation","id":"interface-onboarding-profiles-and-social-presentation-6-purchase-presentation"},{"type":"p","text":"When a hero is found in Infinity, the first tap should not instantly launch a full-screen shop. Use a small card and require a deliberate second action. Purchases must show price, ownership, source, permanence, and whether the item is available elsewhere."},{"type":"p","text":"PART 6"},{"type":"p","text":"TECHNOLOGY, TRUST, AND MOBILE QUALITY"},{"type":"p","text":"The shared account, authoritative backend, security, analytics, moderation, accessibility, performance, battery, and network foundations."}]},{"id":"accounts-multiplayer-backend-and-security","number":28,"title":"28. Accounts, Multiplayer, Backend, and Security","part":"Part VI","partName":"Backend, security, analytics, accessibility, and mobile quality","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Current Technical Foundation","id":"accounts-multiplayer-backend-and-security-1-current-technical-foundation"},{"type":"p","text":"The current project is built in Godot with gameplay and support scripts covering analytics, authentication, badges, bots, catalog, challenges, configuration, networking, online matches, pickups, players, stats, save services, Supabase authentication, and UI."},{"type":"table","rows":[["Component","Current direction / state"],["Client","Godot mobile-first client with gameplay, bot, catalog, achievement, save, auth, and network scripts."],["Authentication","Supabase account system with email verification and planned Google OAuth."],["Backend","Cloudflare Worker service at tap-against-me.dontwatchmedia.workers.dev."],["Database","Cloudflare D1 production database initialized with expected application tables."],["Multiplayer","Lobby and room code exists; production validation between separate devices/accounts is the next major proof."],["Achievements","Shared achievement definitions; backend health currently reports 55."],["Testing","53 integration tests were reported passing after backend validation."]]},{"type":"heading","level":2,"text":"2 Production Security State","id":"accounts-multiplayer-backend-and-security-2-production-security-state"},{"type":"p","text":"The production backend was migrated away from the earlier hand-rolled or HS256-oriented verification path toward Supabase JWKS validation using the current EC/ES256 signing key. The one-shot schema bootstrap was completed and then disabled."},{"type":"ul","items":["Production D1 schema initialized.","ADMIN_KEY removed from Cloudflare secrets after bootstrap.","POST /v1/schema returns 404 in production.","Preview URLs disabled.","Production secrets limited to required Supabase configuration.","Badge loadouts are sanitized so users can display only server-known earned badges."]},{"type":"heading","level":2,"text":"3 Immediate Engineering Milestones","id":"accounts-multiplayer-backend-and-security-3-immediate-engineering-milestones"},{"type":"ol","items":["Connect the Godot client to the production Supabase project and Worker base URL through environment-safe configuration.","Complete real email signup, confirmation, login, refresh, logout, and recovery flows.","Verify automatic D1 user and profile provisioning after authenticated access.","Configure and validate Google OAuth on mobile.","Run production private matches between two physical phones using two distinct accounts.","Validate reconnect, timeout, result submission, duplicate submission, and version mismatch behavior.","Integrate shared account and catalog logic that supports two player-facing games without combining product-specific progress."]},{"type":"heading","level":2,"text":"4 Multiplayer Authority","id":"accounts-multiplayer-backend-and-security-4-multiplayer-authority"},{"type":"p","text":"WORKING The server should be authoritative for match identity, results, rewards, rating updates, and impossible-state validation. The client may predict movement for responsiveness."},{"type":"ul","items":["Use deterministic or replayable simulation inputs where feasible.","Assign client-generated idempotency keys to result submissions.","Store physics and ruleset version with match records.","Reject duplicate rewards and duplicate match writes.","Preserve enough telemetry to investigate disputes without storing unnecessary personal data."]},{"type":"heading","level":2,"text":"5 Shared Account Across Two Titles","id":"accounts-multiplayer-backend-and-security-5-shared-account-across-two-titles"},{"type":"p","text":"The backend should represent product source explicitly. A shared user owns a hero once, but ranked rating belongs to Competitive TAM and biome progress belongs to Infinity Taps. Achievement events should include source and ruleset version so cross-title goals remain auditable."}]},{"id":"fair-play-anti-cheat-moderation-and-analytics","number":29,"title":"29. Fair Play, Anti-Cheat, Moderation, and Analytics","part":"Part VI","partName":"Backend, security, analytics, accessibility, and mobile quality","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Anti-Cheat Philosophy","id":"fair-play-anti-cheat-moderation-and-analytics-1-anti-cheat-philosophy"},{"type":"p","text":"TAM should protect meaningful status without treating skilled or high-frequency tapping as suspicious by default. Detection should combine server authority, input plausibility, replay analysis, device behavior, repeated patterns, and economy anomalies."},{"type":"heading","level":2,"text":"2 Signals","id":"fair-play-anti-cheat-moderation-and-analytics-2-signals"},{"type":"ul","items":["Impossible tap intervals sustained beyond human or hardware limits.","Perfectly periodic taps with no contextual adjustment.","Movement traces inconsistent with submitted inputs.","Impossible pickup reaction timing.","Repeated disconnects only when losing.","Duplicate or reordered result submissions.","Currency gain inconsistent with achievements, taps, or matches.","Bot or emulator behavior used to automate Infinity tap rewards."]},{"type":"heading","level":2,"text":"3 Enforcement","id":"fair-play-anti-cheat-moderation-and-analytics-3-enforcement"},{"type":"ul","items":["Use flags and review thresholds before permanent action.","Separate competitive restrictions from account-wide collection where proportionate.","Explain when a match is invalidated or rating is withheld.","Allow appeals for severe actions.","Never sell a shortcut around enforcement or verification."]},{"type":"heading","level":2,"text":"4 Moderation Scope","id":"fair-play-anti-cheat-moderation-and-analytics-4-moderation-scope"},{"type":"p","text":"Social features should begin conservatively. Display names, profile text, and emotes require filtering and reporting. Direct chat is not necessary for the core game and would create moderation burden. Friend invites and preset emotes can provide social connection with lower risk."},{"type":"heading","level":2,"text":"5 Analytics","id":"fair-play-anti-cheat-moderation-and-analytics-5-analytics"},{"type":"table","rows":[["Area","Key measures"],["Competitive feel","Run duration distribution, death height, recovery rate, gravity phase, rematch rate"],["Matchmaking","Queue time, skill gap, survival gap, bot share, disconnect rate, upset rate"],["Pickups","Spawn-to-collect time, contest rate, benefit magnitude, bot reaction delay"],["Infinity engagement","Session length, taps per session, interaction diversity, biome dwell, journal completion"],["Living world","First-tap rate, repeated-tap rate, chain completion, rare-event discovery"],["Economy","Coin earn/spend, item conversion, purchase regret/refund, exclusive source integrity"],["Audio","Track completion, zone transition exits, download size, memory use, mute rates"]]},{"type":"p","text":"Analytics should answer design questions, not merely maximize time spent. Infinity Taps in particular should not be optimized into compulsive pressure that contradicts its calming purpose."}]},{"id":"monetization-and-advertising-guardrails","number":30,"title":"30. Monetization and Advertising Guardrails","part":"Part VI","partName":"Backend, security, analytics, accessibility, and mobile quality","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"p","text":"CONFIRMED Tap Against Me must not be pay-to-win. Purchases are cosmetic or presentation-focused."},{"type":"heading","level":2,"text":"1 Current Product Offers","id":"monetization-and-advertising-guardrails-1-current-product-offers"},{"type":"table","rows":[["Offer","Price","Contents / rule"],["Hero Coin Starter Pack","$0.99","A small beginner currency package to help purchase an early cosmetic."],["Ad-Free Pass","$2.99","Removes ads for 30 days; not a permanent removal."],["Seasonal Pass","$4.99","Season-specific progression with cosmetics unlockable only during that season."],["Supporter Bundle","$9.99","Character bundle, character particle effect, tap effect, and 60 days without ads."]]},{"type":"heading","level":2,"text":"2 Prohibited Purchases","id":"monetization-and-advertising-guardrails-2-prohibited-purchases"},{"type":"ul","items":["Damage, life, regeneration, gravity resistance, tap strength, movement speed, pickup magnetism, or stamina that affects fair competition.","Improved matchmaking, protected rank, purchased rating, or reduced rating loss.","Higher valid tap allowance or anti-cheat exemptions.","Infinity-exclusive earnable rewards.","Required readability or accessibility features."]},{"type":"heading","level":2,"text":"3 Advertising","id":"monetization-and-advertising-guardrails-3-advertising"},{"type":"p","text":"WORKING Ads should never interrupt an active competitive match or a rare Infinity encounter."},{"type":"ul","items":["Place ads at natural session boundaries such as post-match or voluntary reward opportunities.","Do not use deceptive close buttons or accidental purchases.","Respect the 30-day ad-free entitlement across eligible shared products if technically and economically intended; this requires a final entitlement decision.","Rewarded ads may offer modest cosmetic currency or convenience, never ranked power."]},{"type":"heading","level":2,"text":"4 Seasonal Ethics","id":"monetization-and-advertising-guardrails-4-seasonal-ethics"},{"type":"p","text":"The seasonal pass may use exclusive cosmetics, but the player must see the season end date, reward track, required effort, and whether items can ever return. Competitive season rewards should remain earnable through play and separate from paid pass ownership."}]},{"id":"monetization-and-hero-coin-economy-proposal-reference","number":31,"title":"31. Monetization and Hero Coin Economy Proposal Reference","part":"Part VI","partName":"Backend, security, analytics, accessibility, and mobile quality","blocks":[{"type":"p","text":"Source basis: Original Expanded Bible pp. 83-97; consolidated monetization guardrails. All prices and earn rates below are proposals requiring economy simulation, legal/platform review, catalog-depth validation, and explicit approval."},{"type":"p","text":"LOCKED Money may change appearance, collection, profile expression, ad entitlement, or supporter recognition. It may never change gravity, input, jump force, recovery, lives, item odds, achievement speed, ranking, visibility, abilities, or competitive outcome."},{"type":"heading","level":2,"text":"Direct Product Concepts","id":"monetization-and-hero-coin-economy-proposal-reference-direct-product-concepts"},{"type":"table","rows":[["Offer","Candidate price","Proposed contents / rule"],["One-time Hero Starter Pack","$0.99","200 Hero Coins, once per account; later proposal supersedes an earlier 150-Hero-Coin example."],["30-Day Ad-Free Pass","$2.99","Time-limited manually repurchased entitlement; exact ad policy remains open; trusted timestamp and restore required."],["Season Pass","$4.99 / ~3 months","Free and premium cosmetic/profile tracks; no gameplay power; unlocked items remain permanent; expiry clearly communicated."],["Supporter Bundle","$9.99","Coordinated hero/skin, particle, tap effect, supporter badge, 60 days ad-free, and optional 100-Hero-Coin bonus; permanent cosmetics, expiring ad-free."]]},{"type":"p","text":"OPEN AD POLICY The no-coercion boundary is locked, but whether non-optional advertisements ship at all remains a product decision. If ads exist, placements, frequency, minors/consent, rewarded flows, ad-free coverage, offline behavior, and regional policy require separate approval."},{"type":"heading","level":2,"text":"Candidate Repeatable Hero Coin Ladder","id":"monetization-and-hero-coin-economy-proposal-reference-candidate-repeatable-hero-coin-ladder"},{"type":"table","rows":[["Package","Price","Hero Coins","Approx. bonus","Cost / 100"],["Pocket","$0.99","100","Base","$0.99"],["Pouch","$4.99","600","20%","$0.83"],["Chest","$9.99","1,300","30%","$0.77"],["Vault","$24.99","3,500","40%","$0.71"],["Treasury","$99.99","15,000","50%","$0.67"]]},{"type":"p","text":"CATALOG DEPTH GATE Do not launch the $99.99 Treasury until the shop contains enough desirable content for 15,000 Hero Coins to fund several coherent collections. Do not label it Best Value or push it aggressively; $9.99 or $24.99 is the more credible recommended tier."},{"type":"heading","level":2,"text":"Candidate Cosmetic Price Bands","id":"monetization-and-hero-coin-economy-proposal-reference-candidate-cosmetic-price-bands"},{"type":"table","rows":[["Cosmetic family","Proposed Hero Coin band","Acquisition note"],["Basic color variation","50-100","Affordable customization."],["Basic tap effect","100-200","Immediate response with modest complexity."],["Premium tap effect","250-400","Customization, accumulation, interaction, or elaborate presentation."],["Basic character particle","200-350","Trail or limited multi-state package."],["Premium character particle","400-600","Complete trail/idle/jump/landing package."],["Standard hero skin","400-700","Full production-quality variant."],["Premium animated skin","800-1,200","Material/animation complexity beyond a standard swap."],["Character cosmetic bundle","1,200-2,000","Coordinated skin and effects with transparent itemized grants."],["Premium themed collection","2,000-3,500","Multiple coordinated items; no exclusive earned-only content."]]},{"type":"heading","level":2,"text":"Candidate Free-Earning Targets","id":"monetization-and-hero-coin-economy-proposal-reference-candidate-free-earning-targets"},{"type":"table","rows":[["Activity","Proposed Hero Coins","Pacing intention"],["One casual session","10-25","A normal play session visibly advances an affordable item."],["Active day","50-100","Free play remains meaningful beside the $0.99/100 base rate."],["Completed daily challenges","15-30","Combined daily assignments and bonus."],["Completed weekly challenges","75-150","Larger cadence reward without mandatory daily attendance."],["Average achievement","5-25","Proportional to ordinary effort and rarity."],["Major achievement","25-100","Recognizes difficult or long-term accomplishment."]]},{"type":"p","text":"The historical pacing interpretation is roughly one to four active days for a basic effect, one to two weeks for a standard skin, and two to four weeks for a premium animated skin. Treat these as hypotheses to simulate against the actual 60 achievements, challenge rotation, one-coin-per-1,000-Infinity-taps rule, catalog prices, retention, and fraud controls."},{"type":"heading","level":2,"text":"Acquisition Classes and Transaction Safeguards","id":"monetization-and-hero-coin-economy-proposal-reference-acquisition-classes-and-transaction-safeguards"},{"type":"ul","items":["Normal shop cosmetics may be earned or purchased with Hero Coins; paid and earned currency may share a wallet only if regional/legal accounting remains correct.","Achievement cosmetics, Infinity exclusives, ranked/season rewards, and other designated earned items never become ordinary coin purchases unless the exclusivity promise is explicitly retired before release.","Seasonal and supporter item source remains inspectable after the entitlement window; already unlocked cosmetics are permanent.","Every platform purchase is validated, restorable where applicable, idempotent, and distinguished as consumable, non-consumable, subscription, or time entitlement.","Ad-free expiration uses trusted time, not only the phone clock. Cancellation, failed validation, refund/reversal, reinstall, and account merge are defined and logged.","Every Hero Coin transaction records source, reason, signed amount, catalog/config version, idempotency key, resulting balance, and reversal link where applicable."]}]},{"id":"accessibility-performance-and-mobile-quality","number":32,"title":"32. Accessibility, Performance, and Mobile Quality","part":"Part VI","partName":"Backend, security, analytics, accessibility, and mobile quality","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Input Accessibility","id":"accessibility-performance-and-mobile-quality-1-input-accessibility"},{"type":"ul","items":["Support one-thumb play and configurable tap regions.","Offer left-handed and right-handed UI layouts.","Allow reduced movement sensitivity or larger directional zones.","Provide optional haptics strength and complete haptics disable.","Avoid requiring sustained high tap rates for all content; use alternate goals and pacing."]},{"type":"heading","level":2,"text":"2 Visual Accessibility","id":"accessibility-performance-and-mobile-quality-2-visual-accessibility"},{"type":"ul","items":["High-contrast ground and collision boundaries.","Color-independent indicators for beneficial and harmful fruit.","Reduced flashing and reduced particle-density modes.","Text scaling and readable mobile font sizes.","Effect preview warnings for rapid flashes or screen shake."]},{"type":"heading","level":2,"text":"3 Motion and Sensory Settings","id":"accessibility-performance-and-mobile-quality-3-motion-and-sensory-settings"},{"type":"ul","items":["Camera shake strength.","Screen flash intensity.","Particle density.","Background motion.","Rare-event intensity.","Music, ambience, effects, UI, and haptics controls."]},{"type":"heading","level":2,"text":"4 Performance Targets","id":"accessibility-performance-and-mobile-quality-4-performance-targets"},{"type":"p","text":"The game should target smooth, consistent physics on a broad range of Android devices. Competitive simulation quality is more important than maximum particle density. Use object pooling, effect caps, streamed music, compressed textures, deterministic cleanup, and scalable environmental population."},{"type":"heading","level":2,"text":"5 Network Quality","id":"accessibility-performance-and-mobile-quality-5-network-quality"},{"type":"ul","items":["Show connection state without distracting from play.","Use prediction and reconciliation that do not create unexplained ground deaths.","Define timeout and reconnect rules before ranked launch.","Record latency and version data with match results.","Avoid matching across unacceptable latency merely to reduce queue time."]},{"type":"heading","level":2,"text":"6 Battery and Data","id":"accessibility-performance-and-mobile-quality-6-battery-and-data"},{"type":"p","text":"Infinity Taps may be used for long fidget sessions. It needs low-power options, frame-rate caps, reduced ambience, and predictable data use. Downloadable biome music or optional asset packs can be considered later, but the base experience should remain complete."}]},{"id":"mobile-viewport-session-and-interaction-baselines","number":33,"title":"33. Mobile Viewport, Session, and Interaction Baselines","part":"Part VI","partName":"Backend, security, analytics, accessibility, and mobile quality","blocks":[{"type":"p","text":"Source basis: TAM Game Bible and cross-source mobile/accessibility guidance. Values are working planning targets, not a promise that players must stay for a minimum duration."},{"type":"table","rows":[["Baseline","Working value","Design consequence"],["Reference viewport","360 x 640 portrait","Core gameplay, HUD, dialogs, safe areas, and touch targets remain usable at this baseline before adapting upward."],["Quick survival session","15 seconds-3 minutes","Fast restart, low navigation cost, immediate input, concise result."],["Ranked set","3-10 minutes","Queue, intros, rematches, and result progression respect short mobile availability."],["Infinity session","30 seconds-30+ minutes","Equally valid as a brief regulation/fidget break or long exploration session; no stopping penalty."],["Collection/store session","1-5 minutes","Fast preview, compare, acquisition source, equip, and return to prior context."],["Season/challenge check","1-3 minutes","Clear progress and claim state without forcing play or fear-of-missing-out loops."]]},{"type":"p","text":"Test the viewport across cutouts, gesture/navigation bars, tall/narrow phones, tablets, foldables, text scaling, localization expansion, and one-handed reach. The 360 x 640 baseline is a layout floor, not permission to hard-code coordinates or crop wider/taller devices."},{"type":"heading","level":2,"text":"Mobile Interruption Contract","id":"mobile-viewport-session-and-interaction-baselines-mobile-interruption-contract"},{"type":"ul","items":["Incoming calls, notifications, audio-route changes, lock/unlock, split-screen, backgrounding, low-memory recreation, and network handoff produce an explainable pause, reconnect, resume, or result.","Infinity saves before/while backgrounding and returns without scolding, timer loss, or missed exclusive opportunity where pending state can be preserved.","Competitive play cannot continue accepting hidden touches under overlays; reconnect/abandonment policy distinguishes technical interruption from repeated intentional quitting.","Music and ambience resume/crossfade safely; short effects do not replay as duplicate grants or startling bursts after resume.","Quality tier may reduce spectacle under thermal/memory pressure but never remove required gameplay cues or change simulation."]},{"type":"p","text":"PART 7"},{"type":"p","text":"DELIVERY, LIVE OPERATIONS, AND DECISIONS"},{"type":"p","text":"MVP boundaries, release gates, phased development, content cadence, risks, canonical decisions, and open questions."}]},{"id":"mvp-definition-and-development-roadmap","number":34,"title":"34. MVP Definition and Development Roadmap","part":"Part VII","partName":"Roadmap, live operations, risks, and decisions","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Scope Principle","id":"mvp-definition-and-development-roadmap-1-scope-principle"},{"type":"p","text":"The project is already deep in networking and multiplayer work. The correct move is not to discard that foundation. Competitive TAM is closer to a playable proof; Infinity Taps needs substantially more content. Development should finish the current networking milestone while prototyping Infinity at deliberately small scale."},{"type":"heading","level":2,"text":"2 Competitive TAM MVP","id":"mvp-definition-and-development-roadmap-2-competitive-tam-mvp"},{"type":"table","rows":[["Area","MVP requirement"],["Core gameplay","Reliable tap-to-rise physics, gravity escalation, ground failure, restart, and records."],["Modes","Solo survival and private online 1v1; public queue may use bot backfill."],["Items","Green Apple, Purple Fruit, and controlled Hero Coin pickup behavior."],["Bots","At least several imperfect difficulty profiles using the same rules."],["Accounts","Email account flow, Google login, distinct profiles, cloud persistence."],["Multiplayer","Two physical phones, two accounts, match discovery/invite, synchronized play, results."],["Progress","Initial achievements, badges, Hero Coin wallet, cosmetic loadout."],["Presentation","Main menu, profile, shop, settings, results, rematch."],["Fairness","Authoritative result validation, duplicate protection, basic anti-cheat flags."],["Audio","Menu and gameplay music, tap and physics cues, compressed asset pipeline."]]},{"type":"heading","level":2,"text":"3 Infinity Taps MVP","id":"mvp-definition-and-development-roadmap-3-infinity-taps-mvp"},{"type":"table","rows":[["Area","MVP requirement"],["Environment","One polished biome or zen playground."],["Movement","Tap-directed traversal with no loss condition."],["Reactivity","Water, bush, tree/leaves, ground, and at least one additional object."],["Animals","One or two animals with multi-stage reactions."],["Progress","Persistent session and lifetime tap counts; one Hero Coin per 1,000 valid taps."],["Discovery","Small journal, a few behaviors, several achievements."],["Hero content","One discoverable hero or variant and one hidden Infinity-exclusive reward."],["Audio","One adaptive biome track or layered arrangement plus environmental sound."],["Persistence","Resume safely without losing discoveries or rare encounter state."]]},{"type":"heading","level":2,"text":"4 Recommended Phases","id":"mvp-definition-and-development-roadmap-4-recommended-phases"},{"type":"table","rows":[["Phase","Timing","Outcome"],["Phase 0 - Foundation","Current / substantially complete","Godot project, backend, database, auth foundation, achievement definitions, tests, deployment security"],["Phase 1 - Competitive Vertical Slice","Near term","Polish solo physics, items, UI, bot feel, records, one gameplay track"],["Phase 2 - Real Account and Private Match","Near term","Email and Google login, two-device match, production result persistence"],["Phase 3 - Public Queue","Short term","Matchmaking, bot backfill, ghost experiments, queue UX, basic anti-cheat"],["Phase 4 - Ranked Seasons","Medium term","Glicko, tiers, 90-day season, rewards, leaderboards, human-only upper-tier policy"],["Infinity Phase 1 - Zen Playground","Parallel small prototype","One biome, living reactions, animals, tap counter, hidden reward"],["Infinity Phase 2 - Biome Journey","After core proof","Two-minute zones, multiple biomes, boosts, adaptive music, journal expansion"],["Infinity Phase 3 - Infinite Adventure","Long term","Animals, heroes, chains, hidden events, seasonal worlds, deep ocean, planets, rare encounters"]]},{"type":"heading","level":2,"text":"5 Release Gate","id":"mvp-definition-and-development-roadmap-5-release-gate"},{"type":"p","text":"Do not launch ranked merely because online matches connect. Ranked requires stable physics versioning, credible matchmaking, explainable results, disconnect rules, reward integrity, and sufficient bot disclosure. Do not launch Infinity with many empty biomes; one deeply reactive biome is more faithful than ten decorative backgrounds."}]},{"id":"content-production-and-live-operations","number":35,"title":"35. Content Production and Live Operations","part":"Part VII","partName":"Roadmap, live operations, risks, and decisions","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Content Units","id":"content-production-and-live-operations-1-content-units"},{"type":"table","rows":[["Unit","Minimum definition"],["Hero","Silhouette, movement, idle, reactions, lore line, ownership record, loadout compatibility"],["Variant","Distinct visual/theme, source, encounter or purchase rule, journal entry"],["Biome","Visual set, collision set, ambient population, interaction set, music layer, transition"],["Animal","Idle behavior, navigation, first tap, repeated tap, rare response, cooldown"],["Tap effect","Tap response, persistence, rare event, cleanup, preview, competitive visibility rating"],["Particle","Hero attachment, movement response, density levels, preview, performance budget"],["Achievement","ID, title, description, event source, threshold, tier, reward, secret flag"],["Season","Theme, dates, ranked rules, reward table, pass track, event content, end-state handling"]]},{"type":"heading","level":2,"text":"2 Seasonal Cadence","id":"content-production-and-live-operations-2-seasonal-cadence"},{"type":"p","text":"Competitive ranked seasons last 90 days. Each season should offer a distinct cosmetic identity and may introduce a controlled new feature, hero, effect, arena, or world event. The season must not destabilize core physics without sufficient unranked testing."},{"type":"heading","level":2,"text":"3 Infinity Seasonal Worlds","id":"content-production-and-live-operations-3-infinity-seasonal-worlds"},{"type":"p","text":"Infinity can reflect seasons through weather, animal behavior, music layers, heroes, and rare events. Seasonal worlds should enrich the living environment rather than simply recolor it. Permanent journal history should record that the player witnessed the event."},{"type":"heading","level":2,"text":"4 Content Reuse","id":"content-production-and-live-operations-4-content-reuse"},{"type":"ul","items":["A hero created for ranked presentation can later receive Infinity encounter behavior.","A tap effect created for the shop can gain biome-specific interactions.","A music motif can be rearranged for menu, competitive, and biome use.","A seasonal cosmetic may have different unlock paths per title, but ownership must remain unambiguous."]},{"type":"heading","level":2,"text":"5 Quality Bar","id":"content-production-and-live-operations-5-quality-bar"},{"type":"p","text":"Content should be judged by response depth, readability, personality, and source clarity. A new animal with one looping animation is less valuable than an existing rabbit with seven discoverable behaviors. A new effect that hides the ground is not acceptable merely because it looks impressive."}]},{"id":"risks-scope-controls-and-design-safeguards","number":36,"title":"36. Risks, Scope Controls, and Design Safeguards","part":"Part VII","partName":"Roadmap, live operations, risks, and decisions","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"table","rows":[["Risk","Failure mode","Safeguard"],["Two products become unrelated projects","Duplicate systems, inconsistent ownership, slower delivery","Share accounts, catalog schema, hero IDs, effects, achievements framework, and audio motif; separate player-facing loops and progression."],["Infinity becomes a background viewer","World feels dead after novelty fades","Require multi-stage reactions, chains, ambient behavior, and journal depth before adding more biomes."],["Competitive population is too small","Long queues or unfair matches","Bots, ghosts, private matches, solo records, gradual search expansion, and transparent AI labeling."],["Bots feel unfair","Players distrust results","Same rules, reaction delay, imperfect perception, no future knowledge, telemetry-driven tuning."],["Monetization weakens prestige","Exclusive rewards lose meaning","Protect Infinity earn-only and ranked rewards; show item source."],["Effects damage readability","Competitive deaths feel unfair","Effect visibility rating, reduced-particle option, collision overlays, ranked-safe whitelist."],["Achievement catalog drifts","Client and server disagree","Single shared definitions, versioned events, automated tests, export authoritative catalog."],["Music size grows rapidly","Large app and memory footprint","Opus/Vorbis import preset, stream tracks, reuse stems, target bitrate, loop QA."],["Networking milestone is abandoned","Existing investment is wasted","Finish two-device private-match proof before broad content expansion."],["Scope expands before feel is proven","Many systems, weak core","Vertical slices and release gates; one deep biome before many shallow biomes."]]},{"type":"heading","level":2,"text":"1 Non-Negotiable Safeguards","id":"risks-scope-controls-and-design-safeguards-1-non-negotiable-safeguards"},{"type":"ul","items":["No pay-to-win.","No traditional failure in Infinity Taps.","No hidden bot impersonation.","No purchasable Infinity-exclusive earnables.","No unreadable competitive ground or collision state.","No ranking launch before result and matchmaking integrity.","No biome expansion that outruns interaction depth."]}]},{"id":"canonical-decision-register-and-open-questions","number":37,"title":"37. Canonical Decision Register and Open Questions","part":"Part VII","partName":"Roadmap, live operations, risks, and decisions","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 primary canonical narrative, synthesized from the full supplied Bible set."},{"type":"heading","level":2,"text":"1 Canonical Decisions","id":"canonical-decision-register-and-open-questions-1-canonical-decisions"},{"type":"ul","items":["Official slogan: Every Tap Against Me Takes You Further.","Android-first, portrait-oriented, mobile-friendly 2D design.","Competitive TAM centers on tapping to remain airborne; ground contact ends the standard survival round.","Infinity Taps is noncompetitive, no-loss, fidget and exploration-focused.","Current product direction: separate player-facing titles under one shared TAM ecosystem.","Hero is the current canonical character term.","Hero Coin is the canonical currency term; golden token may be its pickup representation.","Infinity Taps awards one Hero Coin per 1,000 valid taps and does not normally spawn coins.","Infinity-earned designated cosmetics and variants cannot be purchased.","Animals and environment have first-tap and repeated-tap reactions.","Found unowned heroes or variants can present purchase or unlock opportunities in-world.","Zones target approximately two minutes.","Infinity boosts include velocity, jet engine hold, anti-gravity, and extra-bouncy.","Competitive matchmaking uses Glicko-style rating plus rolling survival performance.","Visible tiers include Bronze, Silver, Gold, Platinum, and future upper tiers.","Ranked seasons reset every 90 days.","Bots are acceptable for population support but use the same rules and imperfect behavior.","One primary badge plus up to three showcase badges.","Monetization is cosmetic-only with the established $0.99, $2.99, $4.99, and $9.99 offers.","Eight current music tracks total about 27 MB and should be shipped through a compressed streaming pipeline."]},{"type":"heading","level":2,"text":"2 Open Product Questions","id":"canonical-decision-register-and-open-questions-2-open-product-questions"},{"type":"ol","items":["Final public naming of the Infinity product and whether the subtitle \"A Tap Against Me Adventure\" is used.","Whether Hero Coin is one wallet across both titles or has title-specific earning caps and entitlements.","Exact ranked tier names above Platinum, division count, rank floors, and human-only cutoff.","Exact reset compression formula for 90-day seasons.","Whether First to Zero and Most Taps become permanent modes, events, or are removed.","Final horizontal-control model for competitive taps.","Exact Green Apple and Purple Fruit values, durations, and spawn rules.","Which Infinity boosts are universal versus biome-specific.","Whether encounter-exclusive purchases remain available after discovery or only during the encounter.","Whether 30-day ad-free and 60-day supporter entitlements apply across both products.","Complete reconciliation of the 55 implemented achievements with final design names, thresholds, and rewards.","Final art style, hero proportions, and animation budget.","Whether optional controller support remains a future platform feature."]},{"type":"heading","level":2,"text":"3 Recommended Next Decision Workshop","id":"canonical-decision-register-and-open-questions-3-recommended-next-decision-workshop"},{"type":"p","text":"The next design lock should focus on four items: competitive physics values, two-device private-match acceptance criteria, shared-account data boundaries, and the one-biome Infinity vertical slice. Those decisions unlock engineering and content production without requiring every future biome, hero, or season to be specified."},{"type":"p","text":"PART 8"},{"type":"p","text":"DETAILED REFERENCE APPENDICES"},{"type":"p","text":"Traceable catalogs, implementation snapshots, data contracts, release evidence, unresolved decisions, legacy context, and source custody."}]},{"id":"appendix-a-terminology","number":38,"title":"38. Appendix A. Terminology","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 canonical appendix."},{"type":"table","rows":[["Term","Definition"],["TAM","Tap Against Me; the competitive flagship and shared universe shorthand."],["Infinity Taps","The no-loss exploration and fidget title within the TAM ecosystem."],["Hero","Playable or collectible character."],["Variant","A distinct version of a hero with separate source or ownership."],["Hero Coin","Cosmetic currency; not competitive power."],["Golden Hero Token","Earlier term; recommended as the visible pickup form of Hero Coin."],["Valid Tap","A tap accepted by the active gameplay rules and input window."],["Survival Time","Duration before ground contact or elimination."],["Glicko","Rating family that tracks rating and uncertainty."],["Performance Profile","Rolling survival and behavior metrics used alongside rating."],["Primary Badge","The single badge displayed beside the username."],["Showcase Badges","Up to three additional profile badges."],["Zone","An approximately two-minute Infinity travel segment."],["Biome","A themed environment with unique visuals, audio, objects, animals, and reactions."],["Interaction Chain","A tap response that causes another object or character to react."],["Infinity-exclusive","An item that must be earned through Infinity Taps and cannot be purchased."],["Ranked-safe","A cosmetic or modifier that preserves clarity, symmetry, and competitive integrity."]]}]},{"id":"appendix-b-achievement-seed-catalog","number":39,"title":"39. Appendix B. Achievement Seed Catalog","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 canonical appendix."},{"type":"p","text":"The following names were explicitly discussed. The deployed backend currently reports 55 definitions; this appendix is the recovered design-name set and must be reconciled with code for complete thresholds and rewards."},{"type":"heading","level":2,"text":"Fruit and Poison","id":"appendix-b-achievement-seed-catalog-fruit-and-poison"},{"type":"ul","items":["Life of Poisonous Fruit","Anti-Gravity","Fruit Salad","Toxic Appetite","Poison-Proof","Apple a Day","Orchard Raider","Clean Eating","No Boost Needed","Bad Decisions"]},{"type":"heading","level":2,"text":"Survival and Control","id":"appendix-b-achievement-seed-catalog-survival-and-control"},{"type":"ul","items":["First Flight","Learning to Fly","Gravity Defier","Sky Eternal","Terminal Velocity","Close Call","Living on the Edge","Perfect Control","Untouchable","One More Tap"]},{"type":"heading","level":2,"text":"Coins and Shop","id":"appendix-b-achievement-seed-catalog-coins-and-shop"},{"type":"ul","items":["Coin Collector","Golden Hoard","Token Hunter","Big Spender","Shop Regular","Fully Dressed"]},{"type":"heading","level":2,"text":"Multiplayer and Progression","id":"appendix-b-achievement-seed-catalog-multiplayer-and-progression"},{"type":"ul","items":["First Victory","Getting Started"]},{"type":"heading","level":2,"text":"Secret","id":"appendix-b-achievement-seed-catalog-secret"},{"type":"ul","items":["Was That Worth It?","Floor Inspector","Maximum Poison","Perfectly Balanced","Velvet's Nine Lives","Too Greedy"]},{"type":"heading","level":2,"text":"Infinity Exploration","id":"appendix-b-achievement-seed-catalog-infinity-exploration"},{"type":"ul","items":["World Traveler","Into the Clouds","Beyond the Sky","One Small Tap","Going Deep","At the Bottom","First Contact"]},{"type":"table","rows":[["CATALOG RECONCILIATION REQUIREMENT Export achievement ID, title, description, event source, threshold, tier, reward, secret flag, and product scope from the authoritative shared definitions. Resolve duplicate or incomplete historical names before release."]]}]},{"id":"appendix-d-developer-acceptance-criteria","number":40,"title":"40. Appendix D. Developer Acceptance Criteria","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 canonical appendix."},{"type":"heading","level":2,"text":"D.1 Competitive Core","id":"appendix-d-developer-acceptance-criteria-d-1-competitive-core"},{"type":"ul","items":["A player can begin, tap to rise, fall under gravity, collide with the visible ground, receive an accurate result, and restart without state corruption.","Physics behavior is consistent at supported frame rates and recorded with a ruleset version.","Green Apple and Purple Fruit effects are readable, configurable, and logged.","A bot uses the same physics and cannot react to an item before a human-readable spawn window."]},{"type":"heading","level":2,"text":"D.2 Two-Device Private Match","id":"appendix-d-developer-acceptance-criteria-d-2-two-device-private-match"},{"type":"ul","items":["Two physical Android phones sign in with different accounts.","One account can find, invite, or match with the other.","Both clients enter the same authoritative match.","Tap inputs and movement remain acceptably synchronized under normal latency.","Ground contact and winner agree on both clients and the server.","The result writes once, rewards once, and updates both profiles.","Disconnect, timeout, duplicate submission, and rematch paths are tested."]},{"type":"heading","level":2,"text":"D.3 Infinity Vertical Slice","id":"appendix-d-developer-acceptance-criteria-d-3-infinity-vertical-slice"},{"type":"ul","items":["No input or environmental event creates a loss screen.","Water splashes, a bush wiggles, tree leaves fall, and reactions vary with repeated taps.","At least one animal has three distinct interaction stages.","A found hero or variant displays an in-world identification and acquisition path.","Lifetime taps persist; one Hero Coin is awarded at the 1,000-valid-tap threshold.","One Infinity-exclusive reward is earnable and absent from direct purchase catalogs.","The biome track transitions or loops cleanly and environmental sounds vary."]},{"type":"heading","level":2,"text":"D.4 Economy and Entitlements","id":"appendix-d-developer-acceptance-criteria-d-4-economy-and-entitlements"},{"type":"ul","items":["The server rejects duplicate reward transactions.","Badge loadouts accept only earned badges.","Infinity-exclusive source flags block shop purchase.","Ad-free expiration is stored and interpreted consistently.","No cosmetic changes simulation values in ranked rulesets."]},{"type":"heading","level":2,"text":"D.5 Audio Import","id":"appendix-d-developer-acceptance-criteria-d-5-audio-import"},{"type":"ul","items":["Masters remain lossless and outside the shipping asset set.","Shipped music uses the agreed Opus or Vorbis preset.","Long tracks stream and do not cause load spikes.","Loop points are tested on target Android hardware.","The eight-track set is reduced toward the 10-15 MB target without obvious artifacts."]}]},{"id":"appendix-e-legacy-and-reserved-concepts","number":41,"title":"41. Appendix E. Legacy and Reserved Concepts","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: TAM Game Design Bible v1.0 canonical appendix."},{"type":"table","rows":[["Concept","Historical idea","Current treatment"],["Puffs","Earlier character or companion language with passive bonuses, artifact discovery, currency, abilities, rarity, and profile customization.","Reserve as companion or alternate creature class; do not replace current Hero terminology without a deliberate change."],["Artifacts","Collectible objects tied to exploration, buffs, rarity, or journal progression.","Could return as non-power lore collectibles or event objects; avoid ranked stat advantage."],["Bubble / moving targets","Earlier active-tapping target loop with accuracy and unpredictable targets.","Possible event mode or Infinity interaction, not the current airborne core."],["Stamina / cooldown","Earlier tapping-system consideration.","Only reintroduce if needed for feel or accessibility; avoid making the core feel artificially throttled."],["MMO systems","Rankings, guilds, shared events, trading, cooperative and competitive goals.","Long-term universe possibilities; trading and guilds are well outside current scope."],["Controller support","Optional controller input was mentioned.","Future accessibility or platform expansion; mobile touch remains primary."],["Life / regeneration upgrades","Earlier mode concepts included life, regeneration per tap, and total life.","May support a specific alternate mode but cannot be purchasable ranked power."]]},{"type":"table","rows":[["FINAL PRODUCT STATEMENT Tap Against Me is a shared universe where tapping can mean survival, rivalry, expression, relaxation, or discovery. Competitive TAM asks how long and how well the player can resist the ground and another challenger. Infinity Taps asks how far curiosity can carry them through a world that notices every touch. In both, every tap takes the player further."]]}]},{"id":"feature-status-phase-and-next-gate-ledger","number":42,"title":"42. Feature Status, Phase, and Next-Gate Ledger","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Canonical intent from all supplied bibles; implementation evidence from the supplied implementation snapshots and current workspace catalogs. Runtime production status still requires a build/backend audit."},{"type":"p","text":"READ THIS FIRST The design-state and evidence-state columns are independent. 'LOCKED / PLANNED' means the requirement is firm but not demonstrated as built. 'WORKING / IMPLEMENTED' means code may exist while the intended rule is still being refined. This ledger is the fastest reference for what should happen, what evidence exists, and what must happen next."},{"type":"table","rows":[["Feature","Exact intent","Design state","Evidence state","Phase and next gate"],["Tap input and airborne resistance","Tap applies readable upward resistance against a fall; ground contact ends Competitive runs.","LOCKED","IMPLEMENTED baseline","Phase 0: validate feel, frame-rate invariance, input filtering, deterministic replay."],["Rising gravity","Difficulty increases through authoritative, configurable gravity rather than sky darkness.","LOCKED / TUNING","IMPLEMENTED baseline","Phase 0: approve curve/caps and pin physics version."],["Green Apple","Beneficial pickup with clear spawn, collection, sound, visual, and result tracking.","CONFIRMED / TUNING","IMPLEMENTED baseline","Phase 0: verify effects, bot parity, network authority, accessibility cues."],["Poison Fruit","Readable gravity/debuff pickup with explicit duration, stacking, cleanse, and result evidence.","CONFIRMED / TUNING","IMPLEMENTED baseline","Phase 0: resolve final modifier and stacking matrix."],["Golden Hero Token","High-value collectible/reward with distinct sunset-safe visual language.","CONFIRMED / TUNING","IMPLEMENTED baseline","Phase 0/3: validate grant ledger and rename legacy token language where necessary."],["Solo survival","Rapid-start, rapid-retry competitive ruleset used to prove the core feel.","CONFIRMED","IMPLEMENTED baseline","Phase 0: complete result, record, interruption, and device-quality gates."],["Private two-device match","Two accounts complete the same authoritative match with synchronized rules and results.","CONFIRMED","UNKNOWN / AUDIT","Phase 1: prove latency, reconnect, duplicate submission, and progression sync."],["Public matchmaking","Find a compatible human, expand predictably, then use disclosed bot backfill where allowed.","CONFIRMED","PLANNED / AUDIT","Phase 4: population test, queue policy, regions, latency ceiling, bot thresholds."],["Glicko-2 ranked","Underlying rating plus readable tier/division ladder, placements, history, and server-side updates.","CONFIRMED","PLANNED","Phase 4: resolve division count and thresholds; validate reference calculations."],["Ranked seasons","Ninety-day competitive seasons with soft compression and permanent history.","CONFIRMED","PLANNED","Phase 4/5: approve rewards, peak/final policy, rollover rehearsal."],["Bots","Human-like population bridge using the same physics/items, delays, mistakes, personalities, and disclosure.","CONFIRMED / TUNING","PARTIAL per source","Phase 4: seeded behavior simulation, fairness review, upper-tier restrictions."],["Ghost opponents","Asynchronous or replay-driven opponent presentation without pretending to be live.","CANDIDATE","NOT STARTED / AUDIT","Post-MVP: define evidence, disclosure, rating eligibility, replay determinism."],["Competitive day/night","Continuous 120-second cosmetic cycle synchronized from authoritative match data and independent of gravity.","LOCKED","PLANNED / AUDIT","Dedicated phases 1-7: baseline, controller, profiles, anchors, ambience, biome reaction, optimization."],["Infinity no-loss contract","Open-ended local-first tapping and directional exploration with no fail screen, punishment, or urgency.","LOCKED","PLANNED","Phase 2: one-biome vertical slice must pass every no-loss gate."],["Infinity movement languages","Land, water, sky, space, and later biomes interpret direction with distinct impulse/drag/camera feel.","CONFIRMED / TUNING","PLANNED","Phase 2: prove land plus one transition; tune without reward dependency."],["Infinity tap milestone","One Hero Coin per 1,000 valid lifetime taps with persistent remainder and idempotent grant.","LOCKED","PLANNED","Phase 2: 999/1000/1001 and cross-device crash/merge tests."],["Living-world reactions","Objects, terrain, water, plants, animals, and heroes support stages, context, cooldown, chains, and secrets.","CONFIRMED","PLANNED","Phase 2: water, bush, tree, one three-stage animal, one chain."],["Discovery Journal","Persistent biomes, landmarks, behaviors, heroes/variants, secrets, records, and partial-progress entries.","CONFIRMED","PLANNED","Phase 2: schema, entry visibility, save migration, first-biome coverage."],["Rare discoveries and pity","Rare events retain wonder while drought protection prevents implausible long-term failure.","WORKING / OPEN TUNING","NOT STARTED","Simulate base odds, interval, pity, reset, secrecy, and grant idempotency."],["Infinity-exclusive rewards","Designated items are earned only in Infinity, retain source labels, and are never sold anywhere.","LOCKED","PLANNED","Phase 2: one exclusive earned in slice and automated absence-from-store invariant."],["Heroes and variants","Exact hero and variant identities have personality, acquisition source, ownership, encounter, and reaction state.","CONFIRMED","PARTIAL catalog/art","Phase 3: approve launch roster, exact variant IDs, preview/encounter/acquisition flows."],["Shared account/cross-save","One shared identity and eligible ownership with separate Competitive and Infinity progression records.","CONFIRMED","UNKNOWN / AUDIT","Phase 1/2: guest conversion, provider links, merge, deletion, recovery, entitlements."],["Hero Coin ledger","Auditable shared currency transactions; cached balance never replaces the authoritative ledger.","LOCKED","PARTIAL / AUDIT","Phase 3: idempotency, reversal, reconcile, offline pending grant, fraud tests."],["Achievements","Stable versioned criteria, retroactive and online evidence, once-only rewards, badges, and hidden rules.","CONFIRMED","DATA-DEFINED: 60","Phase 3: runtime-reachability suite for all 60; correct stale 55-count references."],["Badges","Earned identity display with one primary and up to three showcase badges; never gameplay power.","CONFIRMED","DATA-DEFINED: 60","Phase 3: equip/profile runtime, animation/accessibility, source mapping validation."],["Daily/weekly challenges","UTC rotations with server-witnessable progress, clear online labels, and once-only grants.","CONFIRMED / TUNING","DATA-DEFINED: 12 daily, 9 weekly","Phase 3: issuance, expiry, impossible-assignment, bonus, offline/reconnect tests."],["Store and equipment","Permanent ownership separated from equipped selection; previews and purchase restoration; no power sales.","LOCKED boundary","PARTIAL: 23 records","Phase 3: fix duplicate 'none' ID collision; validate every grant, bundle, restore, and slot."],["Current tap-effect loadout","One equipped cosmetic tap effect: Shockring, Starburst, Ripple, or No Effect.","CONFIRMED","IMPLEMENTED / catalog evidence","Phase 3: verify persistence, preview, remote density, no-physics golden test."],["Expanded tap effects","Thirty candidate effects with bounded accumulation, optional rare depth, accessibility, and performance caps.","CANDIDATE","PLANNED","Phase 3+: prioritize ten distinct low-risk effects; data-drive behavior."],["Character particles/trails","One cosmetic slot may contain trail, idle, jump/fall, landing, and environment variants.","CONFIRMED boundary","PARTIAL: 3 purchasable trails","Phase 3+: validate slot semantics, 43-effect backlog, density tiers, remote-player controls."],["Audio and adaptive music","Shared motif with product-specific tone, legible cues, variation, bus controls, and Opus-first delivery.","CONFIRMED","PARTIAL / AUDIT","Phase 0-5: approve motif, cue matrix, compression, streaming, interruption, comfort."],["Accessibility","Text, contrast, color-independent cues, reduced motion/flash/shake, haptics, audio, remote effects, input comfort.","LOCKED boundary","UNKNOWN / AUDIT","Every phase: device/settings matrix and accessibility acceptance evidence."],["Performance quality tiers","Android-first 30/60 FPS presentation tiers preserve gameplay information while reducing spectacle.","CONFIRMED / TUNING","PARTIAL / AUDIT","Define device floor and budgets; soak, thermal, battery, load, memory tests."],["Monetization/ads","Cosmetic, transparent, optional, restorable; no pay-to-win or required ads; supporter/pass concepts remain policy work.","LOCKED guardrails / OPEN packaging","PARTIAL / AUDIT","Phase 3/5: legal/store review, exact offers, opt-in placements, refund/support flows."],["Live operations","Seasons and events extend cosmetics/world activity without erasing ownership or destabilizing ranked physics.","CONFIRMED","PLANNED","Phase 5: capacity plan, event rollback, reruns, content versioning, permanent history."]]},{"type":"p","text":"Maintenance rule: whenever evidence changes, update the evidence state, missing scope, next gate, acceptance evidence, and linked decision together. Never mark a feature IMPLEMENTED merely because a menu entry, JSON row, or isolated class exists."}]},{"id":"current-implemented-achievement-catalog","number":43,"title":"43. Current Implemented Achievement Catalog","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Workspace data/achievements.json. This is an implementation snapshot, not proof that every entry has passed live validation."},{"type":"p","text":"IMPLEMENTATION SNAPSHOT The current catalog contains 60 achievement records. IDs and tracked-stat names are implementation contracts; display copy, targets, rewards, and enablement may be migrated or tuned only through versioned data."},{"type":"p","text":"Retroactive achievements must evaluate durable lifetime statistics. Online-only achievements require authoritative match evidence. Hidden achievements must not leak their exact criteria through client logs, public analytics payloads, or unearned UI copy. Tier groups must grant every completed lower tier exactly once."},{"type":"table","rows":[["ID","Display name","Category","Requirement","Reward","Flags"],["fruit_poison_25","Poison Fruit Consumer (Bronze)","fruit","poison_fruits_consumed >= 25","3 coins; badge_poison_bronze","retro"],["fruit_poison_100","Poison Fruit Consumer (Silver)","fruit","poison_fruits_consumed >= 100","5 coins; badge_poison_silver","retro"],["fruit_poison_500","Life of Poisonous Fruit","fruit","poison_fruits_consumed >= 500","10 coins; badge_poison_gold","retro"],["fruit_poison_2500","Poison Fruit Consumer (Mythic)","fruit","poison_fruits_consumed >= 2500","50 coins; badge_poison_mythic","retro"],["fruit_apple_500","Anti-Gravity","fruit","apples_collected >= 500","10 coins; badge_golden_apple","retro"],["fruit_salad","Fruit Salad","fruit",">= 1","5 coins; badge_fruit_salad","standard"],["fruit_toxic_appetite","Toxic Appetite","fruit","round_poison_fruits >= 5","10 coins; badge_toxic_slime","standard"],["fruit_poison_proof","Poison-Proof","fruit",">= 1","15 coins; badge_poison_shield","standard"],["fruit_apple_a_day","Apple a Day","fruit","apple_collection_day_streak >= 7","15 coins; badge_apple_calendar","retro"],["cookie_10","Star Baker (Bronze)","cookie","space_cookies_eaten >= 10","3 coins; badge_cookie_bronze","retro"],["cookie_50","Star Baker (Silver)","cookie","space_cookies_eaten >= 50","6 coins; badge_cookie_silver","retro"],["cookie_250","Gravity Optional","cookie","space_cookies_eaten >= 250","15 coins; badge_cookie_gold","retro"],["cookie_1000","The Whole Jar","cookie","space_cookies_eaten >= 1000","40 coins; badge_cookie_mythic","retro"],["cookie_moonshot","Moonshot","cookie","round_space_cookies >= 5","20 coins; badge_cookie_flight","standard"],["fruit_orchard_raider","Orchard Raider","fruit","round_apples >= 25","20 coins; badge_apple_basket","standard"],["fruit_clean_eating","Clean Eating","fruit",">= 1","10 coins; badge_pure_apple","standard"],["fruit_no_boost","No Boost Needed","fruit",">= 1","15 coins; badge_natural_flyer","standard"],["fruit_bad_decisions","Bad Decisions","fruit",">= 1","5 coins; badge_questionable_fruit","standard"],["survival_30","First Flight","survival","best_survival_seconds >= 30","5 coins; badge_tiny_wings","retro"],["survival_60","Learning to Fly","survival","best_survival_seconds >= 60","10 coins; badge_silver_wings","retro"],["survival_120","Gravity Defier","survival","best_survival_seconds >= 120","20 coins; badge_gravity","retro"],["survival_300","Sky Eternal","survival","best_survival_seconds >= 300","50 coins; badge_eternal_wings","retro"],["survival_terminal_velocity","Terminal Velocity","survival","seconds_after_max_gravity >= 20","25 coins; badge_falling_star","standard"],["survival_close_call","Close Call","survival","close_calls >= 1","5 coins; badge_scraped_paw","retro"],["survival_living_on_edge","Living on the Edge","survival","round_close_calls >= 5","15 coins; badge_razor_edge","standard"],["survival_perfect_control","Perfect Control","survival",">= 1","15 coins; badge_balance","standard"],["survival_untouchable","Untouchable","survival",">= 1","15 coins; badge_empty_sky","standard"],["survival_one_more_tap","One More Tap","survival","longest_near_ground_streak >= 10","10 coins; badge_last_tap","standard"],["coins_balance_500","Coin Collector","coins","highest_coin_balance >= 500","25 coins; badge_coin_collector","retro"],["coins_balance_2500","Golden Hoard","coins","highest_coin_balance >= 2500","50 coins; badge_golden_vault","retro"],["coins_token_hunter","Token Hunter","coins","gameplay_coins_collected >= 1000","25 coins; badge_token_hunter","retro"],["coins_big_spender","Big Spender","coins","coins_spent >= 500","15 coins; badge_shopping_bag","retro"],["coins_shop_regular","Shop Regular","coins","unique_shop_items_purchased >= 10","20 coins; badge_merchant","retro"],["coins_fully_dressed","Fully Dressed","coins",">= 1","10 coins; badge_wardrobe","standard"],["coins_golden_opportunity","Golden Opportunity","coins","round_hero_tokens >= 3","15 coins; badge_golden_hero","standard"],["coins_shiny_distraction","Shiny Distraction","coins",">= 1","5 coins; badge_dropped_coin","standard"],["online_win_1","First Victory","multiplayer","online_matches_won >= 1","10 coins; badge_first_crown","online, retro"],["online_win_10","Last One Floating","multiplayer","online_matches_won >= 10","25 coins; badge_survivor_crown","online, retro"],["online_win_100","Sky Champion","multiplayer","online_matches_won >= 100","100 coins; badge_champion_wings","online, retro"],["online_photo_finish","Photo Finish","multiplayer",">= 1","20 coins; badge_photo_finish","online"],["online_flawless","Flawless Victory","multiplayer",">= 1","15 coins; badge_perfect_crown","online"],["online_poisoned_champion","Poisoned Champion","multiplayer",">= 1","25 coins; badge_toxic_crown","online"],["online_comeback","Comeback Flight","multiplayer",">= 1","15 coins; badge_comeback","online"],["online_crowded","Crowded Skies","multiplayer",">= 1","25 coins; badge_crowded_sky","online"],["online_rivalry","Rivalry","multiplayer",">= 1","10 coins; badge_rival","online"],["online_friendly","Friendly Competition","multiplayer","private_matches_completed >= 10","15 coins; badge_friends","online, retro"],["prog_getting_started","Getting Started","progression","achievements_completed >= 5","10 coins; badge_beginner","retro"],["prog_badge_collector","Badge Collector","progression","badges_unlocked >= 10","20 coins; badge_badge_case","retro"],["prog_achievement_hunter","Achievement Hunter","progression","achievements_completed >= 25","50 coins; badge_achievement_hunter","retro"],["prog_completionist","Completionist","progression",">= 1","0 coins; badge_completionist; hex_completionist","retro"],["prog_dedicated_tapper","Dedicated Tapper","progression","rounds_played >= 100","20 coins; badge_tap_counter","retro"],["prog_tap_veteran","Tap Veteran","progression","rounds_played >= 1000","75 coins; badge_veteran","retro"],["prog_persistent","Persistent","progression","immediate_restarts >= 25","15 coins; badge_never_quit","retro"],["prog_daily_flyer","Daily Flyer","progression","daily_play_streak >= 7","20 coins; badge_weekly_wings","retro"],["secret_worth_it","Was That Worth It?","secret",">= 1","5 coins; badge_regret","hidden"],["secret_floor_inspector","Floor Inspector","secret",">= 1","0 coins; badge_floor","hidden"],["secret_maximum_poison","Maximum Poison","secret","round_poison_fruits >= 7","25 coins; badge_purple_skull","hidden"],["secret_perfectly_balanced","Perfectly Balanced","secret",">= 1","10 coins; badge_balance_fruit","hidden"],["secret_nine_lives","Velvet's Nine Lives","secret",">= 1","25 coins; badge_nine_lives","hidden"],["secret_too_greedy","Too Greedy","secret",">= 1","0 coins; badge_greedy_hero","hidden"]]},{"type":"heading","level":2,"text":"Current Badge Definitions","id":"current-implemented-achievement-catalog-current-badge-definitions"},{"type":"p","text":"DATA-DEFINED The badge catalog contains 60 records with complete one-to-one coverage. Rarity distribution: 11 common, 26 rare, 18 gold, and 5 mythic. Four definitions are animated. Badge presentation is a reward/identity layer and never a gameplay modifier."},{"type":"table","rows":[["Badge ID","Display name","Rarity","Source achievement","Glyph","Tier","Flags"],["badge_cookie_bronze","Bronze Cookie","common","cookie_10","cookie","bronze","standard"],["badge_cookie_silver","Silver Cookie","rare","cookie_50","cookie","silver","standard"],["badge_cookie_gold","Gravity Optional","gold","cookie_250","cookie","gold","standard"],["badge_cookie_mythic","The Whole Jar","mythic","cookie_1000","cookie","mythic","standard"],["badge_cookie_flight","Moonshot","gold","cookie_moonshot","cookie","none","standard"],["badge_poison_bronze","Bronze Poison","rare","fruit_poison_25","poison","bronze","standard"],["badge_poison_silver","Silver Poison","rare","fruit_poison_100","poison","silver","standard"],["badge_poison_gold","Gold Poison","gold","fruit_poison_500","poison","gold","standard"],["badge_poison_mythic","Mythic Poison","mythic","fruit_poison_2500","poison","mythic","animated"],["badge_golden_apple","Golden Apple","gold","fruit_apple_500","apple_gold","none","standard"],["badge_fruit_salad","Fruit Salad","common","fruit_salad","salad","none","standard"],["badge_toxic_slime","Toxic Slime","rare","fruit_toxic_appetite","slime","none","standard"],["badge_poison_shield","Poison Shield","rare","fruit_poison_proof","shield","none","standard"],["badge_apple_calendar","Apple Calendar","rare","fruit_apple_a_day","calendar","none","standard"],["badge_apple_basket","Apple Basket","gold","fruit_orchard_raider","basket","none","standard"],["badge_pure_apple","Pure Apple","rare","fruit_clean_eating","apple","none","standard"],["badge_natural_flyer","Natural Flyer","rare","fruit_no_boost","feather","none","standard"],["badge_questionable_fruit","Questionable Fruit","common","fruit_bad_decisions","poison","none","standard"],["badge_tiny_wings","First Flight","common","survival_30","wings1","bronze","standard"],["badge_silver_wings","Learning to Fly","rare","survival_60","wings2","silver","standard"],["badge_gravity","Gravity Defier","gold","survival_120","gravity","gold","standard"],["badge_eternal_wings","Sky Eternal","mythic","survival_300","wings3","mythic","animated"],["badge_falling_star","Falling Star","gold","survival_terminal_velocity","star_fall","none","standard"],["badge_scraped_paw","Scraped Paw","common","survival_close_call","paw","none","standard"],["badge_razor_edge","Razor Edge","rare","survival_living_on_edge","edge","none","standard"],["badge_balance","Balance","rare","survival_perfect_control","balance","none","standard"],["badge_empty_sky","Empty Sky","rare","survival_untouchable","empty","none","standard"],["badge_last_tap","Last Tap","rare","survival_one_more_tap","tap","none","standard"],["badge_coin_collector","Coin Collector","rare","coins_balance_500","coin","silver","standard"],["badge_golden_vault","Golden Vault","gold","coins_balance_2500","vault","gold","standard"],["badge_token_hunter","Token Hunter","gold","coins_token_hunter","coin_stack","none","standard"],["badge_shopping_bag","Shopping Bag","rare","coins_big_spender","bag","none","standard"],["badge_merchant","Merchant","rare","coins_shop_regular","tag","none","standard"],["badge_wardrobe","Wardrobe","rare","coins_fully_dressed","wardrobe","none","standard"],["badge_golden_hero","Golden Hero","rare","coins_golden_opportunity","star","none","standard"],["badge_dropped_coin","Dropped Coin","common","coins_shiny_distraction","coin_drop","none","standard"],["badge_first_crown","First Victory","gold","online_win_1","crown","none","standard"],["badge_survivor_crown","Last One Floating","rare","online_win_10","crown2","silver","standard"],["badge_champion_wings","Sky Champion","mythic","online_win_100","crown3","gold","animated"],["badge_photo_finish","Photo Finish","gold","online_photo_finish","photo","none","standard"],["badge_perfect_crown","Perfect Crown","gold","online_flawless","crown_clean","none","standard"],["badge_toxic_crown","Toxic Crown","gold","online_poisoned_champion","crown_toxic","none","standard"],["badge_comeback","Comeback","rare","online_comeback","comeback","none","standard"],["badge_crowded_sky","Crowded Sky","rare","online_crowded","crowd","none","standard"],["badge_rival","Rival","rare","online_rivalry","rival","none","standard"],["badge_friends","Friends","common","online_friendly","friends","none","standard"],["badge_beginner","Beginner","common","prog_getting_started","star_small","none","standard"],["badge_badge_case","Badge Case","rare","prog_badge_collector","case","none","standard"],["badge_achievement_hunter","Achievement Hunter","gold","prog_achievement_hunter","trophy","none","standard"],["badge_completionist","Completionist","mythic","prog_completionist","laurel","none","animated"],["badge_tap_counter","Tap Counter","rare","prog_dedicated_tapper","counter","silver","standard"],["badge_veteran","Veteran","gold","prog_tap_veteran","counter_gold","gold","standard"],["badge_never_quit","Never Quit","rare","prog_persistent","retry","none","standard"],["badge_weekly_wings","Weekly Wings","gold","prog_daily_flyer","calendar_wings","none","standard"],["badge_regret","Regret","common","secret_worth_it","regret","none","hidden"],["badge_floor","Floor Inspector","common","secret_floor_inspector","floor","none","hidden"],["badge_purple_skull","Purple Skull","gold","secret_maximum_poison","skull","none","hidden"],["badge_balance_fruit","Balance Fruit","rare","secret_perfectly_balanced","scales","none","hidden"],["badge_nine_lives","Nine Lives","gold","secret_nine_lives","cat","none","hidden"],["badge_greedy_hero","Greedy Hero","common","secret_too_greedy","coin_drop","none","hidden"]]},{"type":"p","text":"The current JSON contains no Infinity-category achievements. Infinity achievement concepts in the design chapters and seed catalog remain planned/design-only until stable IDs, tracking fields, badge definitions, runtime progress, grant evidence, and migration behavior exist."}]},{"id":"current-implemented-challenge-catalog","number":44,"title":"44. Current Implemented Challenge Catalog","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Workspace data/challenges.json. Daily and weekly pools are recorded here for reference and test coverage."},{"type":"table","rows":[["Cadence","Configured value"],["Daily selection count","3"],["Weekly selection count","3"],["Daily completion bonus","5 Hero Coins"],["Weekly completion bonus","Not configured separately"]]},{"type":"table","rows":[["Pool","ID","Name","Player-facing requirement","Metric / target","Reward"],["Daily","d_apples_10","Orchard Run","Collect ten Green Apples.","apples_collected x 10","3 coins"],["Daily","d_survive_60","One Minute","Survive for 60 seconds in a round.","rounds_survived_60 x 1","5 coins"],["Daily","d_rounds_5","Five Flights","Complete five rounds.","rounds_played x 5","3 coins"],["Daily","d_tokens_3","Gold Rush","Collect three Golden Hero Tokens.","hero_tokens_collected x 3","4 coins"],["Daily","d_taps_250","Busy Paws","Tap 250 times.","taps x 250","4 coins"],["Daily","d_no_fruit","Fasting","Finish a round without collecting fruit.","rounds_no_fruit x 1","4 coins"],["Daily","d_poison_3","Bad Diet","Consume three Poison Fruits.","poison_fruits_consumed x 3","3 coins"],["Daily","d_coins_20","Pocket Change","Earn 20 Coins through gameplay.","gameplay_coins_collected x 20","5 coins"],["Daily","d_online_1","Into the Fray","Play one online match.","online_matches_played x 1","5 coins; online"],["Daily","d_tokens_8","Token Hoarder","Collect 8 hero tokens.","hero_tokens_collected x 8","5 coins"],["Daily","d_cookies_5","Star Baker","Eat five Space Cookies.","space_cookies_eaten x 5","4 coins"],["Daily","d_cookies_12","Sweet Tooth","Eat twelve Space Cookies.","space_cookies_eaten x 12","6 coins"],["Weekly","w_survive_1200","Twenty Minutes Up","Survive for a combined 20 minutes.","total_survival_seconds x 1200","25 coins"],["Weekly","w_wins_10","Ten Crowns","Win ten online matches.","online_matches_won x 10","25 coins; online"],["Weekly","w_apples_100","Harvest","Collect 100 Green Apples.","apples_collected x 100","20 coins"],["Weekly","w_poison_25","Acquired Taste","Consume 25 Poison Fruits.","poison_fruits_consumed x 25","15 coins"],["Weekly","w_coins_100","Paid Work","Earn 100 Coins through gameplay.","gameplay_coins_collected x 100","20 coins"],["Weekly","w_dailies_5","Regular","Complete five daily challenges.","daily_completions x 5","20 coins"],["Weekly","w_rounds_50","Fifty Flights","Play 50 rounds.","rounds_played x 50","15 coins"],["Weekly","w_taps_5000","Relentless","Tap 5,000 times.","taps x 5000","25 coins"],["Weekly","w_cookies_40","The Whole Jar","Eat 40 Space Cookies.","space_cookies_eaten x 40","20 coins"]]},{"type":"p","text":"FAIRNESS Challenge rotation must not create pay-to-win pressure, require an unavailable queue, punish players for accessibility settings, or silently replace earned progress. Online-only tasks must be clearly labeled before the player commits time."}]},{"id":"current-implemented-store-and-equipment-catalog","number":45,"title":"45. Current Implemented Store and Equipment Catalog","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Workspace data/store.json plus the equipment-slot rules consolidated in this Bible."},{"type":"table","rows":[["Slot","ID","Name","Price","Color","Description","Bundle grants"],["skin","default","Velvet Hex","0 coins","#8f5fd6","Nine lives, allegedly. Sceptical about gravity.","-"],["skin","hex_toxic","Toxic Hex","100 coins","#7dff4a","Something is leaking. It does not seem worried.","-"],["skin","hex_golden","Golden Hex","100 coins","#ffd45e","Heavier than it looks. Falls exactly as fast.","-"],["skin","hex_arcade","Arcade Hex","100 coins","#31d6ff","Ships with scanlines nobody asked for.","-"],["skin","hex_frozen","Frozen Hex","100 coins","#9fe8ff","Rimed over. Still not cool about it.","-"],["skin","hex_molten","Molten Hex","100 coins","#ff6a1f","The cracks glow. That is probably fine.","-"],["skin","hex_ghost","Ghost Hex","100 coins","#dfe6ff","Barely there. Still hits the floor.","-"],["skin","hex_corrupted","Corrupted Hex","100 coins","#ff2f6a","Some of these pixels are in the wrong place.","-"],["skin","hex_strawberry","Strawberry Slime","100 coins","#e8547f","Seeded. Sweet. Structurally questionable.","-"],["skin","hex_abyssal","Abyssal Hex","100 coins","#2fd8c8","Grew its own light. Down there you have to.","-"],["skin","hex_meadow","Meadow Hex","100 coins","#8fd66a","Flowers in the fur. Nothing has ever gone wrong.","-"],["skin","hex_first_contact","First Contact Hex","100 coins","#8fff6a","Being taken. Has made peace with it.","-"],["skin","hex_cosmic","Cosmic Hex","200 coins","#a88fff","A nebula moves through it, and it never moves the same way twice.","-"],["skin","hex_bundle","The Hex Bundle","1000 coins","#c9a8ff","Every variant, including Cosmic. Worth 1300 coins bought one by one.","hex_toxic, hex_golden, hex_arcade, hex_frozen, hex_molten, hex_ghost, hex_corrupted, hex_strawberry, hex_abyssal, hex_meadow, hex_first_contact, hex_cosmic"],["skin","hex_completionist","Prismatic Hex","earned only","#cfc4e8","Earned, not bought. Not in the bundle, not for sale, not ever.","-"],["trail","none","No Trail","0 coins","#7a819c","Clean flight.","-"],["trail","trail_spark","Sparks","35 coins","#ffd45e","Leaves a lick of gold behind each tap.","-"],["trail","trail_comet","Comet","70 coins","#6fd0ff","A cold streak across the sky.","-"],["trail","trail_bloom","Bloom","110 coins","#ff8fc7","Petals where you have been.","-"],["effect","none","No Effect","0 coins","#7a819c","A silent tap.","-"],["effect","fx_ring","Shockring","30 coins","#8fd8ff","A ring of air on every tap.","-"],["effect","fx_burst","Starburst","55 coins","#ffd45e","Little stars where you flapped.","-"],["effect","fx_ripple","Ripple","80 coins","#a0f0c8","The sky remembers each beat.","-"]]},{"type":"p","text":"The shipped catalog currently exposes one skin slot, one trail slot, and one tap-effect slot. The source comment requires globally unique IDs, yet 'none' appears for both trail and effect, and a server map keyed only by item ID would collide. Treat this as a known implementation defect until the IDs are made unique or every lookup and persistence key is proven composite. Prismatic Hex is explicitly earned-only and must remain absent from direct-purchase and bundle grants."},{"type":"p","text":"IMPLEMENTATION BOUNDARY A current catalog record describes available content, not permission for the content to affect physics or outcomes. Ownership, equipped selection, ledger entries, acquisition source, refunds, and catalog version must persist independently."}]},{"id":"canonical-data-model-reference","number":46,"title":"46. Canonical Data Model Reference","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Cross-source synthesis of accounts, competitive state, Infinity state, economy, content ownership, integrity, and configuration requirements."},{"type":"p","text":"The names below are conceptual contracts, not mandated database table names. Every durable grant uses an idempotency key; every mutable record carries a schema/version field; server-authored competitive and economy state is never trusted from an unverified client payload."},{"type":"table","rows":[["Model","Required fields","Invariant"],["Shared user","user ID; provider links; display name; locale; age/consent state; account creation; sanctions; cross-save revision; settings reference","Identity links can merge, but product-specific progression remains separate."],["Wallet ledger","transaction ID; user; currency; signed amount; reason; source product; source event; idempotency key; timestamp; balance after; reversal link","The ledger is authoritative; cached balances are derived and reconciled."],["Inventory ownership","user; slot/type; item ID; acquired at; source; product origin; paid/earned; permanent flag; content version","Infinity-exclusive acquisition source remains visible and cannot be rewritten as purchased."],["Equipment","user; product; slot; equipped item; updated at; revision","Only owned and product-eligible items may equip; one item per slot unless a later rule says otherwise."],["Competitive profile","rating; RD; volatility; placement count; tier; division; peak/final rank; season; wins/losses; streak; human/bot split","Visible rank is presentation; rating is the matchmaking signal."],["Performance profile","survival median; recent windows; input quality; disconnect pattern; platform/network indicators","Supports match quality and integrity; never exposes sensitive risk scoring to opponents."],["Match","match ID; ruleset/config version; participants; bot flags; seed; start/end; placements; survival; pickups; disconnects; evidence; rating delta","Server or authoritative host validates results and finalizes once."],["Bot definition","personality; tier target; reaction distribution; miss rate; impulse policy; pursuit bias; loadout; disclosure flag","Bots follow the same physics and item rules; no hidden immunity or impossible input."],["Season","season ID; start/end; ruleset; rating compression; reward table; eligibility; archival state","Past peak/final ranks and earned rewards remain auditable."],["Infinity save","world/biome/zone; distance; altitude/depth records; tap totals/remainder; Journal sets; interactions; rare/pity state; pending grants","Local-first progress syncs safely; merge cannot duplicate currency or erase set-valued discoveries."],["Journal entry","entry type/ID; discovered state; progress; first source/location; exact variant; timestamps; hidden-hint state","Supports partial behavior counts without revealing every secret."],["Achievement progress","achievement ID/version; current value; completed; claimed; evidence scope; awarded transaction","Retroactive totals and online evidence are distinct."],["Challenge assignment","rotation ID; challenge ID/version; assigned/expiry; progress; completion; claim; authoritative scope","Expiry never removes already granted rewards."],["Catalog item","item ID; slot; price; currency; availability; grants; restrictions; art/audio refs; content version","Store visibility is independent from ownership and equipment."],["Interaction definition","target; tap thresholds; cooldown; conditions; weighted variants; chain outputs; Journal effect; rare eligibility","Drives Infinity depth without hard-coding each object."],["Rare discovery state","category; eligibility; attempts/taps; pity; last check; last success; pending result; idempotency key","Never expose exact hidden thresholds in the client."],["Integrity case","signals; match/account references; confidence; automated action; reviewer; appeal; resolution; retention class","Enforcement must be explainable, proportionate, and auditable."],["Remote configuration","config ID/version; audience; rollout; start/end; checksum; rollback; author/approval","A match pins one immutable ruleset version from start through result."]]},{"type":"heading","level":2,"text":"Cross-Device Merge Rules","id":"canonical-data-model-reference-cross-device-merge-rules"},{"type":"ul","items":["Set-like discoveries merge by union, preserving earliest known source and timestamp when available.","Monotonic records such as highest altitude use max only when both records belong to the same measurement version and are not flagged invalid.","Wallet state merges by replaying authoritative ledger transactions, never by choosing the larger cached balance.","Tap remainder toward the next 1,000-tap award merges from transaction/evidence history; adding two remainders can duplicate credit and is forbidden.","Exclusive grants reconcile by item ownership ID and grant idempotency key. Pending grants retry until acknowledged, not until duplicated.","Conflicting current locations use a documented policy such as most recent valid checkpoint, while permanent discoveries remain unioned.","Competitive rating accepts only authoritative finalized matches. Offline clients cannot advance rating or backfill ranked results."]}]},{"id":"remote-configuration-and-analytics-event-reference","number":47,"title":"47. Remote Configuration and Analytics Event Reference","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Cross-source implementation and observability requirements. Names are canonical semantic events; transport-specific naming may differ if mapped one-to-one."},{"type":"table","rows":[["Domain","Configuration","Safety rule"],["Competitive physics","gravity curve; tap impulse; velocity caps; collision tolerances; valid-tap timing","Pinned per ruleset/match; signed; rollback tested."],["Pickups and hazards","spawn cadence; positions; weights; durations; stacking; cleanse; despawn","Same authoritative values for humans and bots."],["Matchmaking","rating weight; survival weight; network weight; search bands; expansion timers; bot-fill thresholds","Never change an already formed match."],["Ranked","tier thresholds; divisions; placement count; season length; compression; rewards","Archive the exact version with season results."],["Day/night","120-second phase timing; colors; anchors; cloud/stars/celestial speeds; quality tier","Independent from gravity; deterministic from shared match time."],["Infinity movement","impulse profiles; drag; speed limits; transition thresholds; camera smoothing","Cannot introduce loss or punishment."],["Infinity content","zone sequences; interaction thresholds; rare tables; pity; unlock mapping","Content version stored with discoveries and grants."],["Economy","prices; rewards; challenge selection; caps; offers","Ledger reason/version recorded; paid and earned paths remain distinguishable."],["Cosmetics","particle caps; lifetimes; remote-player density; quality tiers; accessibility overrides","No config may alter competitive outcomes."],["Audio","bus levels; variation; cooldowns; ducking; compression/streaming","Accessibility overrides win over event tuning."]]},{"type":"table","rows":[["Event family","Minimum properties","Purpose / privacy constraint"],["app_session","product; build; device tier; locale; consent; start/end reason","Retention and stability by product."],["onboarding_step","step; entered/completed/skipped; time; failure","Tutorial clarity without coercion."],["tap_validated","product; context; valid/invalid reason; sampled timing bucket","Input quality and false rejection; do not log raw touch traces unnecessarily."],["competitive_match","queue; ruleset; humans/bots; survival; placement; disconnect; result","Match health, fairness, population, and bot prevalence."],["rating_change","season; before/after; RD; expected result; placement flag","Rating correctness and volatility."],["pickup_event","item; spawned/collected/expired; target; outcome","Spawn balance and item comprehension."],["infinity_zone","world; biome; zone; entered/completed/looped; duration","Pacing, depth, and transition health."],["interaction_event","target; stage; condition; chain; Journal result","Which living-world reactions are found and repeated."],["discovery_event","type; rarity; eligible attempts; pity band; source; grant result","Rare-system droughts and grant integrity without exposing secret criteria publicly."],["economy_transaction","currency; amount; reason; source; item; ledger ID","Source/sink balance, fraud, and reconciliation."],["catalog_action","view; preview; purchase; equip; fail reason; product origin","Store clarity, conversion, and mistaken purchase detection."],["achievement_challenge","assigned/progress/completed/claimed; ID/version; evidence scope","Progress correctness and unreachable content."],["accessibility_setting","setting changed; anonymous cohort only","Discover defaults and usability gaps; never infer disability."],["performance_sample","device tier; FPS; memory; load; thermal; battery; network","Quality-tier tuning and regression detection."],["integrity_signal","coarse signal; confidence; action; appeal outcome","Measure false positives with strict access and retention."]]},{"type":"heading","level":2,"text":"Canonical Suggested System Event Names","id":"remote-configuration-and-analytics-event-reference-canonical-suggested-system-event-names"},{"type":"p","text":"These stable semantic names come directly from the detailed Game Bible event appendix. Implementations may add a namespace or version suffix, but dashboards and tests should preserve a documented one-to-one mapping."},{"type":"table","rows":[["Event group","Canonical event names"],["Input and run","tap_registered; player_impulse_applied; ground_contact; run_started; run_ended; close_call; personal_best"],["Match","match_started; match_completed; disconnect; reconnect"],["Pickups","pickup_spawned; pickup_collected; green_apple_collected; poison_fruit_collected; hero_token_collected"],["Progression","achievement_progress; achievement_earned; reward_claimed; badge_equipped; challenge_progress; challenge_completed"],["Ranked and season","rating_updated; tier_changed; season_reward_granted"],["Infinity movement","infinity_tap_milestone; biome_entered; zone_transitioned; boost_started; boost_ended"],["Infinity discovery","environment_reacted; interaction_chain_advanced; animal_behavior_discovered; hero_encountered; secret_discovered; exclusive_unlocked"],["Commerce/entitlement","purchase_validated; ad_free_started; ad_free_expired"],["Integrity","integrity_flag_created"]]}]},{"id":"cross-system-definition-of-done-and-release-gates","number":48,"title":"48. Cross-System Definition of Done and Release Gates","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Consolidated developer acceptance criteria across all supplied bibles, expanded into product-level release evidence."},{"type":"table","rows":[["Gate","Pass condition","Required evidence"],["Competitive input/physics","Repeated taps produce consistent upward resistance; gravity escalation follows pinned config; collisions and ground loss are deterministic; capped inputs do not feel arbitrary; pause/background behavior is defined.","Automated deterministic replays plus frame-rate/device matrix and extended manual feel test."],["Competitive fairness","No owned cosmetic, purchase, accessibility option, device quality tier, or remote effect changes collision, visibility of required signals, item odds, or rating outcome.","Golden-match comparisons across clean and fully equipped accounts."],["Multiplayer authority","Two or more clients agree on match seed, phase, pickups, elimination order, result, and grant; reconnect and duplicate result submission are idempotent.","Two-device tests under latency, loss, suspend/resume, reconnect, and retry."],["Ranked","Glicko values update once; placements complete at configured count; visible tier maps correctly; season compression/rewards archive; division count is resolved before shipping ladder UI.","Reference calculations, migration tests, season rollover rehearsal, abuse cases."],["Bots","Bots use the same physics and pickups; declared personalities produce measurable behavior; bot identity is disclosed; impossible reactions and hidden protection are absent.","Seeded simulation, behavior distributions, human/bot result split, spectator review."],["Day/night","All clients derive the same 120-second presentation from shared match time; phase boundaries are smooth; brightness never encodes gravity; required objects remain readable at darkest phase.","Two-device time-offset capture, color-contrast checks, tier comparison, reduced-motion/flash review."],["Infinity contract","No loss, punishment, urgency, or compulsory monetization; movement is satisfying without rewards; stop/resume preserves progress; one deep biome meets the vertical-slice gate.","Long idle/fidget sessions, interruption matrix, new-player observation, no-network validation."],["Infinity taps/currency","Exactly one Hero Coin is granted per 1,000 valid lifetime taps; remainders persist; reconnect, merge, retry, and reinstall do not duplicate or erase credit.","Boundary tests at 999/1000/1001, multi-device merge, crash between grant and acknowledgement."],["Infinity discovery","Interaction stages, context, cooldown, chains, Journal progress, rare eligibility, pity, and pending grants persist; animals are never harmed; secret criteria do not leak.","Content-driven interaction harness, save migration, deterministic rare simulations, copy/log audit."],["Exclusive rewards","Every designated Infinity-exclusive item is earnable in Infinity, visible with source, and absent from all shops, bundles, passes, ads, and paid grants.","Automated catalog invariant across every offer and server grant path."],["Economy/inventory","Ledger balances reconcile; ownership is permanent unless explicitly reversible; duplicate grants collapse; refunds/reversals are traceable; equip validates slot and ownership.","Transaction property tests, offline/retry cases, migration and rollback rehearsal."],["Achievements/challenges","All enabled records can progress; retroactive and online-only evidence are correct; hidden criteria remain hidden; rotation never assigns impossible content; grants occur once.","Data-driven completion suite covering every catalog row and version migration."],["Cosmetics/effects","Tap effects, trails, particles, skins, badges, frames, and elimination effects remain readable, pooled, capped, accessible, and mechanically inert.","Performance stress scene, remote-player density test, accessibility toggle audit, golden physics comparison."],["Audio","Tap, pickup, danger, result, and menu cues remain distinct; repeated sounds vary without fatigue; streaming/compression works; mute and per-bus controls persist.","Device/headphone/speaker matrix, rapid-tap fatigue session, interruption and Bluetooth changes."],["Accessibility/UI","Text scales/reflows; touch targets, contrast, reduced motion, flash, haptic, audio, remote effects, and color-independent cues work; destructive/paid actions confirm clearly.","Screen-reader/navigation review, scale matrix, one-handed use, color-vision simulation, comfort sessions."],["Performance/mobile","Target device tiers sustain agreed FPS, memory, load time, battery, thermal, and network budgets; quality reductions preserve gameplay information.","Cold/warm launch, 30-minute soak, thermal/battery sampling, low-memory recovery, poor-network profile."],["Security/moderation","Server rejects impossible results and duplicate grants; sanctions and appeals are recorded; display names/reactions are bounded; privacy retention is documented.","Threat-model cases, tampered-client tests, rate limits, false-positive audit, moderation workflow rehearsal."],["Analytics/privacy","Required semantic events arrive once with pinned versions; consent and retention rules are honored; dashboards distinguish products, humans/bots, configs, and acquisition source.","Schema validation, sampled end-to-end trace, opt-out/deletion test, access-control review."]]},{"type":"p","text":"SHIP RULE A milestone is complete only when its acceptance evidence exists. A feature being visible in a build is not the same as being production-ready."}]},{"id":"canonical-open-decision-register","number":49,"title":"49. Canonical Open-Decision Register","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Unresolved choices collected across all supplied sources. Owners and dates belong in the production tracker; the Bible records what must be decided and why."},{"type":"table","rows":[["Decision","Question to resolve","Downstream impact"],["Product packaging","Whether Competitive TAM and Infinity Taps ship as separate store apps, one shell with two entries, or another arrangement while remaining separate player-facing experiences.","Account linking, store policy, acquisition, downloads, reviews, release cadence."],["Shared ownership policy","Which cosmetics earned or purchased in one product may equip in the other, and how unavailable assets display.","Collection clarity, download size, entitlement support."],["Rank divisions","Resolve the conflict between five divisions (V-I) and three divisions (III-I) inside each tier.","Rank UI, thresholds, rewards, migrations, season messaging."],["Rank thresholds","Approve rating-to-tier thresholds and whether visible progress is direct rating, stars, or a protected presentation layer.","Player trust and volatility."],["Season rewards","Exact rewards, eligibility, peak versus final basis, inactivity handling, and distribution timing.","Competitive motivation and support burden."],["Placement/bot rules","When placements may include bots, minimum human count, and how bot-heavy results affect rating.","Queue health versus legitimacy."],["Queue expansion","Final timing/bands by region, mode, skill, and population, including maximum acceptable latency.","Wait time, fairness, network quality."],["Disconnect outcome","Reconnect window, temporary AI takeover if any, rating consequences, and abuse detection.","Mobile reliability and competitive integrity."],["Gravity curve","Final escalation formula, soft/hard caps, round-length target, and interaction with item timing.","Core skill arc and match duration."],["Day/night rollout","Whether the full 120-second system launches with Competitive MVP or follows after core multiplayer stability.","Scope, visual identity, cross-device synchronization."],["Competitive item set","Launch pickups/hazards, targeting, spawn weights, cleanse rules, and stacking matrix.","Readability, comeback potential, bot parity."],["Infinity launch scope","One-biome vertical slice versus broader initial content, and the exact first biome/zone sequence.","Depth, production cost, retention."],["Infinity movement profiles","Final impulse/drag/camera values for land, underwater, sky, space, and other environments.","Feel and accessibility."],["Zone progression","Exact approximately-two-minute pacing, branching/loop policy, checkpoint behavior, and transition presentation.","Fidget continuity and exploration agency."],["Rare system","Check interval, base odds, pity curve, drought reset, category pools, and disclosure policy.","Wonder, fairness, simulation risk."],["Hero acquisition","Which heroes/variants are found, earned, purchased, or hybrid; duplicate handling; two-step encounter conversion details.","Collection ethics and revenue."],["Infinity exclusives","First reward set, unlock thresholds, cross-product equipping, and permanent source labels.","Mode identity and non-purchase promise."],["Currency caps","Daily/weekly reward caps, AFK/automation protection, and treatment of offline Infinity taps.","Inflation, accessibility, fraud."],["Economy prices","Approve price bands, earning velocity, bundles, refunds, regional paid pricing, and supporter offers.","Ethical monetization and progression pace."],["Advertising","Whether ads ship at all; if so, exact opt-in placements and non-punitive reward rules.","Trust and platform compliance."],["Effect depth","Which effects receive accumulation, reactions, or rare events at launch versus simple presentation only.","Content cost, performance, discovery coherence."],["Character roster","First playable/collectible heroes beyond Velvet Hex, variant rarity, lore depth, and product availability.","Brand breadth and production capacity."],["Narrative voice","Final naming, capitalization, humor limits, mystery density, and localization voice guide.","Brand consistency and translation."],["Audio motif","Approve the shared TAM melodic/rhythmic motif, instrumentation per product, and adaptive layer budget.","Cross-product recognition and file size."],["Account model","Guest-to-account conversion, provider set, age/consent handling, deletion, merge conflicts, and recovery.","Cross-save, compliance, support."],["Multiplayer architecture","Final authoritative topology, region strategy, session service, relay/host fallback, and replay evidence.","Cheat resistance, latency, cost."],["Moderation scope","Allowed social features, name/reaction policy, report/appeal flow, and retention.","Safety and operational burden."],["Analytics stack","Event transport, warehouse, consent implementation, retention, dashboards, and ownership.","Decision quality and privacy."],["Device floor","Minimum Android/API/device tier, FPS targets, memory/load/battery/thermal budgets, and asset packs.","Audience reach and quality."],["Accessibility defaults","Default flash, shake, haptics, particle density, remote cosmetics, text scale, and color support.","Comfort and inclusion."],["Live-ops cadence","Season/event cadence, content capacity, reruns, permanent ownership, and rollback expectations.","Sustainable production."],["Legacy concepts","Which reserved modes, items, effects, or product structures are retired permanently versus held for later validation.","Scope control and documentation clarity."]]},{"type":"heading","level":2,"text":"Decision Record Template","id":"canonical-open-decision-register-decision-record-template"},{"type":"table","rows":[["Field","Required content"],["Decision ID / title","Stable reference used by specs, tickets, tests, and release notes."],["Owner / approvers","One accountable owner plus required product, engineering, art, audio, legal, or operations approval."],["Status / date","Proposed, approved, superseded, or retired; effective date and target release."],["Context","Player problem, evidence, constraints, affected products and systems."],["Options","Alternatives considered, including cost, risk, accessibility, fairness, performance, and live-ops impact."],["Decision / rationale","Exact approved behavior and why it best protects the product contracts."],["Configuration / migration","Tunable fields, default values, schema/content version, backward compatibility, rollback."],["Acceptance evidence","Tests, playtests, metrics, review artifacts, and release gate."],["Supersedes / links","Older Bible language, code spec, task, asset brief, analytics dashboard, and support notes."]]}]},{"id":"source-concordance-and-authority-map","number":50,"title":"50. Source Concordance and Authority Map","part":"Part VIII","partName":"Catalogs, data models, release gates, and source concordance","blocks":[{"type":"p","text":"Source basis: Traceability map for the nine supplied source files. Page counts and hashes appear in the front matter."},{"type":"table","rows":[["Source","Principal contribution","Authority treatment"],["TAM Game Design Bible v1.0 (DOCX)","Primary canonical narrative for governance, two-product architecture, all system chapters, roadmap, decisions, terminology, and acceptance framing.","Newest explicit decisions control unless a newer feature-specific authority says otherwise."],["Competitive Dynamic Day-Night and Gravity Presentation Bible","Exact 120-second competitive environment cycle, independent gravity presentation, controller architecture, sync, visual anchors, quality tiers, accessibility, phased delivery, acceptance.","Feature-specific authority for competitive sky/time presentation."],["Original Expanded Bible","Deep tap effects, character particles, price bands, Infinity worlds/interactions/exclusives, rare/pity concepts, ranked/matchmaking/bot details, monetization ideas.","Richest backlog source; proposals remain candidate or tuning unless promoted."],["Game Design Bible (1) / Game Design Bible","Consolidated product and implementation snapshot, developer acceptance, current-vs-planned distinctions.","These two supplied PDFs are byte-identical and count as one unique authority."],["TAM Game Bible (DOCX)","Broad product, content, art, audio, technology, economy, and roadmap synthesis with substantial nuance.","Supporting comprehensive source; newer explicit decisions prevail."],["Game Bible v1.0 (DOCX)","Detailed mechanics, system behavior, implementation snapshot, handoff detail, bot/ranked/Infinity/product notes.","Supporting engineering/design authority."],["Game Design Bible v1.0 (PDF)","Design principles, mechanics, production phases, acceptance framing, and scope controls.","Supporting design/production authority."],["TAM Design Bible v1.0 (PDF)","Condensed high-level vision, product framing, identity, and prioritized direction.","Supporting executive/design summary."]]},{"type":"heading","level":2,"text":"Topic-to-Source Trace","id":"source-concordance-and-authority-map-topic-to-source-trace"},{"type":"table","rows":[["Topic","Primary source basis","Master-Bible location"],["Product architecture and brand","TAM Game Design Bible; TAM Game Bible; condensed design bibles","Chapters 1-6"],["Competitive core, physics, pickups","All consolidated bibles; implementation snapshots","Chapters 7-12"],["Ranked, Glicko, matchmaking, bots","Original Expanded Bible; Game Bible v1.0; consolidated design bibles","Competitive implementation reference"],["Competitive day/night","Dedicated Dynamic Day-Night and Gravity Presentation Bible","Dedicated day/night specification"],["Infinity contract and movement","Original Expanded Bible; TAM Game Design Bible; TAM Game Bible","Chapters 13-16 and Infinity implementation reference"],["Living-world interaction and Journal","Original Expanded Bible; consolidated design bibles","Infinity implementation reference"],["Heroes, variants, collection","TAM Game Design Bible; TAM Game Bible; Original Expanded Bible","Hero/collection chapters and current store appendix"],["Effects and particles","Original Expanded Bible; workspace store catalog; consolidated design bibles","Expanded effect catalog and current store appendix"],["Economy, achievements, challenges","Original Expanded Bible; consolidated bibles; workspace JSON catalogs","Progression chapters and implemented catalog appendices"],["Audio, UI, accessibility","TAM Game Bible; Game Bible v1.0; design bibles","Audio/UI/mobile-quality chapters and release gates"],["Backend, security, analytics","Game Bible v1.0; TAM Game Design Bible; consolidated PDFs","Technology chapters and data/event appendices"],["Roadmap, live ops, risks","All consolidated bibles","Delivery chapters, decision register, release gates"]]},{"type":"p","text":"MAINTENANCE When a new decision changes this Bible, update the relevant chapter, status, open-decision row, acceptance gate, configuration/data contract, source note, and version history together. Do not append a contradictory note and leave the old rule appearing equally valid."}]}]};
